import axios from "axios";

import {
  CREATE_THEME_TEMP_FOLDER,
  FETCH_CONTENTZONES,
  FETCH_CUSTOM_SCSS_STYLES,
  FETCH_DRAGABLE_WIDGETS,
  FETCH_THEME_TO_EDIT,
  FETCH_THEMES,
  SAVE_CHANGES,
  FETCH_ADDITIONAL_AVAILABLE_FONTS,
  UPDATE_EXPERTMODE,
  FETCH_PAGE_NAMESPACES,
  FETCH_CONTENT_MANAGER_LIST
} from "../enums/endpoints";

const requestConfig = {
  headers: {
    "Content-Type": "application/x-www-form-urlencoded; charset=UTF-8"
  }
};
const requestConfigNoError = {
  ...requestConfig,
  handleError: false
};

export default {
  namespaced: true,
  state: {
    shopURL: "",
    startPage: "",
    selectedTheme: false,
    tempTheme: false,
    expertMode: false,
    customerID: 1,
    themeConfig: {},
    iframeLoading: true,
    editorView: "desktop",
    breadcrumb: {
      current: "",
      items: {}
    },
    madeChangesStatus: false,
    saveBtnStatus: 1,
    currentLanguage: 'de',
    sourceThemeId: 0,
    pageNamespace: '',
    pageNamespacesLinks: {},
    pagesList: {}
  },
  mutations: {
    initializeUrlParams(state) {
      const URL_PARAMS = new URLSearchParams(location.search);
      state.currentLanguage = URL_PARAMS.get("language") || 'de';
    },
    saveThemeConfig(state, data) {
      state.themeConfig = data;
    },
    savePagesList(state, data) {
      state.pagesList = data;
    },
    saveCurrentLanguage(state, language) {
      state.currentLanguage = language;
    },
    saveSourceTheme(state, sourceThemeId) {
      state.sourceThemeId = sourceThemeId;
    },
    saveSelectedThemeData(state, previewThemeData) {
      state.selectedTheme = previewThemeData;
      // state.selectedTheme.availableFonts = state.fetchAdditionalAvailableFonts(state, state.themeConfig.id);
    },
    saveSelectedEditorView(state, currentView) {
      state.editorView = currentView;
    },
    saveThemeTempFolder(state, tempFolder) {
      state.tempTheme = tempFolder;
    },
    toggleExpertMode(state, active) {
      state.expertMode = active;
    },
    saveCustomerID(state, id) {
      state.customerID = id;
    },
    saveShopURL(state, url) {
      state.shopURL = url;
    },
    saveStartPageURL(state, url) {
      state.startPage = url;
    },
    toggleIframeLoading(state, showIframe) {
      if (showIframe != undefined) {
        state.iframeLoading = showIframe;
      } else {
        state.iframeLoading = !state.iframeLoading;
      }
    },

    saveThemeOption(state, data) {
      if (data && Object.keys(data).length) {
        let optID = Object.keys(data)[0];
        if (data[optID].type == 'variant') {
          let selectedVariant = optID + '/' + data[optID].value.id;

          let optObj = state.themeConfig;
          if (optObj) {
            for (let [key, item] of Object.entries(optObj)) {
              if (item.for) {
                if (item.for != selectedVariant) {
                  delete state.themeConfig[key];
                }
              }
            }

          }

        }
      }

      Object.keys(data).forEach(key => {
        let name = key;
        if (state.selectedTheme.colorPalette[name] !== data[name].value
            && state.selectedTheme.colorPalette[name]) {
          state.selectedTheme.colorPalette[name] = data[name].value || 'transparent';
        }
      });



      state.themeConfig = {...state.themeConfig, ...data};
    },
    currentBreadcrumb(state, current) {
      //console.log(this.breadcrumbItemsCounter());
      state.breadcrumb.current = current;
      /*state.breadcrumb.current = Object.keys(state.breadcrumb.items)[
      Object.keys(state.breadcrumb.items).length - 1
          ];*/
    },
    generateBreadcrumb(state, breadcrumb) {
      // state.breadcrumb.items.push(breadcrumb);
      state.breadcrumb.items = {...state.breadcrumb.items, ...breadcrumb};
      let currentBreadcrumbItems = Object.keys(state.breadcrumb.items);
      let itemsCount = currentBreadcrumbItems.length;
      let currentId;
      /*for (let i = 0; i<itemsCount; i++) {
        currentId = currentBreadcrumbItems[i];
        console.log(currentBreadcrumbItems[i]);
        console.log('========================');
      }*/
      if (itemsCount <= 2) {
        currentId = currentBreadcrumbItems[0];
      } else {
        currentId = currentBreadcrumbItems[itemsCount - 2];
      }
      if (itemsCount <= 1) {
        currentId = currentBreadcrumbItems[0];
      }
      // console.log("generate here: "+ currentId);
      state.breadcrumb.current = currentId;
      //console.log('breadcrumb items added:');
      //console.log(state.breadcrumb.items);
    },

    updateLanguage(state, data) {
      state.currentLanguage = data;
    },

    reArrangeBreadcrumb(state, data) {
      let actionType = data.action;
      if (actionType == "clear") {
        state.breadcrumb.current = "";
        state.breadcrumb.items = {};
      } else if (actionType == "goBack") {
        state.breadcrumb.items = data.from;
        //console.log(data.from.length);
        // Get the last item id and put on the current breadcrumb var
        /*state.breadcrumb.current = Object.keys(state.breadcrumb.items)[
          Object.keys(state.breadcrumb.items).length - 1
        ];*/

        let currentBreadcrumbItems = Object.keys(state.breadcrumb.items);
        let itemsCount = currentBreadcrumbItems.length;
        let currentId;
        /*for (let i = 0; i<itemsCount; i++) {
          currentId = currentBreadcrumbItems[i];
          console.log(currentBreadcrumbItems[i]);
          console.log('========================');
        }*/
        if (itemsCount <= 2) {
          currentId = currentBreadcrumbItems[0];
        } else {
          currentId = currentBreadcrumbItems[itemsCount - 2];
        }
        if (itemsCount <= 1) {
          currentId = currentBreadcrumbItems[0];
        }
        // console.log("reArrange here: "+ currentId);
        state.breadcrumb.current = currentId;
      }
    },
    updateSelectedThemeColorPalette(state, data) {
      state.selectedTheme.colorPalette[data.selector] = data.value;
    },

    changeMadeChangesStatus(state, status) {
      state.madeChangesStatus = status;
    },

    changeSaveBtnStatus(state, status) {
      state.saveBtnStatus = status;
    },

    saveCustomScss(state, data) {
      state.selectedTheme.config['styles'] = data;
    },
    
    savePageNamespace(state, pageNamespace) {
      state.pageNamespace = pageNamespace;
    },
    savePageNamespaceList(state, list) {
      state.pageNamespacesLinks = list;
    },
    changePreviewThemeName(state, newName) {
      state.selectedTheme.title = newName
    }
  },
  getters: {
    breadcrumbItemsCounter: state => Object.keys(state.breadcrumb.items).length,
    madeChangesStatus: state => state.madeChangesStatus,
    pageNamespace: state => state.pageNamespace,
    themeIsUpdatable: state => state.selectedTheme.updatable || false
  },
  actions: {
    async fetchPagesList() {
      const {data} = await axios.get(FETCH_CONTENT_MANAGER_LIST(), requestConfig);
      return data;
    },
    fetchWidgets({state}) {
      let forTheme = state.selectedTheme.id;
      return axios.get(FETCH_DRAGABLE_WIDGETS(forTheme), requestConfig);
    },
    fetchPageNamespaces({state}) {
      let forTheme = state.selectedTheme.id;
      return axios.get(FETCH_PAGE_NAMESPACES(forTheme), requestConfig);
    },
    fetchContentZones({state}, contentZoneIDs) {
      let forTheme = state.selectedTheme.id;
      return axios.get(FETCH_CONTENTZONES(forTheme, contentZoneIDs), requestConfig);
    },
    fetchAdditionalAvailableFonts(context, selectedTheme) {
      return axios.get(FETCH_ADDITIONAL_AVAILABLE_FONTS(selectedTheme), requestConfig);
    },
    fetchThemeToEdit(context, selectedTheme) {
      if (selectedTheme) {
        return axios.get(FETCH_THEME_TO_EDIT(selectedTheme), requestConfig);
      } else {
        return axios.get(FETCH_THEMES, requestConfig);
      }
    },
    createPreviewTheme(context, themeId) {
      return axios.post(CREATE_THEME_TEMP_FOLDER(themeId), {}, requestConfigNoError);
    },

    fetchThemes() {
      return axios(FETCH_THEMES);
    },

    updateExpertMode({state, commit}) {
      commit("toggleExpertMode", !state.expertMode);
      return axios.patch(
        UPDATE_EXPERTMODE,
        {expertMode: state.expertMode, customer_id: state.customerID},
        requestConfig
      );
    },

    saveEditorChanges: function ({state, commit}, data) {
      commit("saveThemeOption", data);
      commit("changeMadeChangesStatus", true);

      let requiresReload = false;
      Object.keys(data).forEach(key => {
        if (data[key].requiresReload === true || data[key].type === 'variant'){
          requiresReload = true;
        }

      });
      let newData = {...state.themeConfig};

      if (!requiresReload) {
        Object.keys(newData).forEach(key => {
          if (newData[key].requiresReload === true || newData[key].type === 'variant'){
            delete newData[key];
          }
        });
      }

      return axios.patch(
          SAVE_CHANGES(state.selectedTheme.id),
          {options: newData},
          {...requestConfig, handleError: true}
      );
    },

    saveTheme({state, commit}, theme) {
      commit("changeMadeChangesStatus", false);
      
      const options = Object.keys(state.themeConfig).length ? state.themeConfig : null
      const contentManager = Object.keys(state.pagesList).length ? state.pagesList : null
      const payload = {...theme, ...{options}, ...{contentManager}}
      
      if (options === null) {
        delete payload.options
      }
      
      return axios.patch(
        SAVE_CHANGES(state.sourceThemeId),
        payload,
        {requestConfig, ...{handleError: true}}
      ).then(response => {
        commit("saveThemeConfig", {});
        return Promise.resolve(response);
      }, response => Promise.reject(response));
    },

    fetchCustomScss(context, themeId) {
      return axios.get(FETCH_CUSTOM_SCSS_STYLES(themeId), {
        headers: {
          "Content-Type": "application/x-www-form-urlencoded; charset=UTF-8"
        }
      });
    },
    updatePreviewThemeName({commit}, newName) {
      commit('changePreviewThemeName', newName)
    }
  }
};
