<template>
  <div class="option-container option-radio-image">
    <div class="row no-gutters">
      <div class="col-6" v-for="radio in value.options" :key="radio.id">
        <div class="radio-option" :ref="`radio-option-${radio.id}`" :class="{ 'active-option': radio.id === currentValue }" @click="currentValue = radio.id">
          <span class="type" v-if="radio.title">{{ radio.title }}</span>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import axios from 'axios'
  
export default {
  props: {
    id: String,
    value: Object
  },
  computed: {
    currentValue: {
      get() {

        return this.id in this.$store.state.editor.themeConfig
                ? this.$store.state.editor.themeConfig[this.id].value
                : this.value.value;
      },
      set(newValue) {
        this.value.value = newValue;
        this.$emit("input", this.value);
        this.$emit("triggerSave", newValue);

      }
    }
  },
  mounted() {
    this.value.options.forEach(async option => {
      const radioOptionDiv = this.$refs[`radio-option-${option.id}`][0]
      let imageTag = document.createElement('img')
      let imageSrc = option.thumbnail
  
      if (/{THEME_ID}/g.test(option.thumbnail)) {
        imageSrc =  await this.getImagePath(option)
      }
      
      imageTag.src = imageSrc
      radioOptionDiv.appendChild(imageTag)
    })
  },
  methods: {
    async getImagePath(option) {
      let imagePath = option.thumbnail;
      const themeId = this.$store.state.editor.selectedTheme.id;
      
      const url = imagePath.replace('{THEME_ID}', themeId)
          .replace('{STYLE_ID}', option.id)
          .replace('{STYLE_NAME}', option.title)
      
      const response = await axios.get(url, {
        responseType: 'blob',
        timeout: 30000,
      })
      
      const urlCreator = window.URL || window.webkitURL;
      return urlCreator.createObjectURL( response.data );
    },
  }
};
</script>

<style scoped lang="scss">
.option-radio-image {
  margin: -5px;
}
.radio-option {
  position: relative;
  border: 4px solid transparent;
  cursor: pointer;
  &:last-child {
    margin-bottom: 0;
  }
  img {
    width: 100%;
  }
  .type {
    display: none;
    position: absolute;
    top: 0;
    left: 0;
    padding-right: 4px;
    padding-bottom: 4px;
    font-size: 12px;
    background: $primary;
  }
  &.active-option {
    border-color: $primary;
    .type {
      display: block;
    }
  }
}
</style>
