<template>
  <div :class="isOpen ? 'is-opened' : 'is-closed'" class="fieldset">
    <div @click="toggle()" class="head" :class="{'can-not-open': showCopyContentButton() || fieldsetCounter == 1 }">
      <h3 class="title">
        {{ data.title }}
        <b-button
          class="reset-fieldset"
          v-on:click.stop="resetFieldset()"
          size="sm"
          variant="danger"
          :class="{'show-btn': fieldsetCounter == 1 }"
          v-if="!isFromWidget()"
        >reset</b-button>
      </h3>
      <b-button
              class="copy-to-other-language"
              size="sm"
              variant="primary"
              @click="handleCopyContent"
              v-if="showCopyContentButton()"
              title="Copy to other languages">
        <custom-icon icon="copy" />
      </b-button>
      <span class="toggler" v-if="!showCopyContentButton() && fieldsetCounter > 1">
        <custom-icon icon="Expand" />
      </span>
    </div>
    <div class="content" >
      <component
        :id="opt.id"
        :is="opt.type"
        :key="opt.id"
        :label="opt.label"
        :language="language"
        @triggerSave="value => handleTriggerSave(value, opt)"
        v-for="(opt, index) in fieldsetOptions"
        v-model="data.options[index]"
        v-show="isVisible(data.options[index], fieldsetOptions)"
      ></component>
    </div>
  </div>
</template>

<script>
  import CustomIcon from "@/components/CustomIcon";
  import Vue from "vue";
  import Options from "./options/Options";

  export default {
    name: "Fieldset",
    extends: Options,
    props: {
      partialSelector: String,
      usedFor: String,
      fieldsetCounter: Number,
      data: Object,
      locales: Object,
      parentPageNamespace: String
    },
    components: {
      CustomIcon
    },
    computed: {
      language() {
        return this.$store.state.editor.currentLanguage;
      },
      fieldsetOptions() {
        return this.data.options.filter(element => !element.hidden);
      }
    },
    data() {
      return {
        isOpen: true,
        requestCount : 0,
        options: {},
        requiresReload: false
      };
    },
    methods: {
      isVisible(option, fieldsetOptions){
        let result = true;
        if(option.visible !== undefined && fieldsetOptions) {
          fieldsetOptions.forEach((arrayOption) => {
            if(arrayOption.id === option.visible.id) {
              let comparison = option.visible.comparison_type || '==';
              let value =  (arrayOption.value === undefined) ? arrayOption.items : arrayOption.value;
              if(comparison === '=='){
                result =  option.visible.value == value
              }
            }
          })
        }
        return result;
      },

      handleIframe(action) {
        this.$emit('handleIframe', action);
      },
      resetFieldset() {
        for (let i = 0; i<this.data.options.length; i++) {
          if(this.data.options[i].id !== "gx-logo") {
            // Resets the value to default

            if(typeof (this.data.options[i].default) === 'object' || typeof (this.data.options[i].items) === 'object'){
              let newItems = JSON.parse(JSON.stringify(this.data.options[i].default));
//              let oldItems  = JSON.parse(JSON.stringify(this.data.options[i].items));

          //let selected = newItems||oldItems;
              //this.data.options[i].items = new Vue({ data : { selected } });
              this.updateObject(this.data.options[i].items, newItems);
            } else {
              this.data.options[i].value = this.data.options[i].default;
            }

            const value = this.data.options[i].value || this.data.options[i].items || null
            this.pushOptionToSave(value, this.data.options[i])
          }
        }
        // Sends to store
        this.saveToStore();
      },

      updateObject($original, newValue) {
        Object.keys(newValue).forEach(fieldName => {
          if(typeof newValue[fieldName] === 'object' && newValue[fieldName]!== null){
            this.updateObject($original[fieldName], newValue[fieldName]);
          } else {
            if($original && newValue){
              Vue.set($original, fieldName, newValue[fieldName]);
            }
          }
        });
      },

      updateIframePreview(requestCount){
        //only update the iframe if this is the last request realized by the Fieldset
        if(requestCount === this.requestCount) {
          const handleType = this.requiresReload ? 'reload' : 'compile';
          this.$emit('handleIframe', handleType)
          this.$emit('reloadPreviewTheme')

          this.options = {}
          this.requiresReload = false;
        }
      },

      async saveToStore(pageNamespace = '') {
        if (Object.keys(this.options).length) {
          try {
            const currentPageNamespace = this.$store.state.editor.pageNamespace;
            
            window.console.log(`pageNamespace: ${pageNamespace}`)
            window.console.log(`currentPageNamespace: ${currentPageNamespace}`)
            
            // Save the change to store and make the save request
            this.requestCount++
            let count = this.requestCount;
            this.$store.dispatch("editor/saveEditorChanges", this.options).then(() => {
              if (!pageNamespace.length || pageNamespace === currentPageNamespace) {
                this.updateIframePreview(count);
              } else {
                // show the toast and don't re compile neither reloads Iframe
                this.options = {}
                const toastID = `ToastMSG_${count}`;
                const h = this.$createElement;
                const vNodesMsg = h(
                  'p',
                  {
                    class: 'm-0'
                  },
                  [
                    h(
                      'span',
                      this.locales.optionNotForCurrentPageNamespace +' '
                    ),
                    h(
                      'a',
                      {
                        on: {
                          click: () => this.redirectToPageNamespace(pageNamespace, toastID)
                        },
                        class: 'link-style'
                      },
                      this.locales.clickToSeeTheChanges
                    )
                  ]
                )

                this.$bvToast.toast([vNodesMsg],{
                  id: toastID,
                  noCloseButton: true,
                  autoHideDelay: 5000,
                  appendToast: true,
                  toastClass: 'custom-info-toast'
                })
              }
            })
          } catch (e) {
            this.$bvToast.toast(e.message, {
              title: `An error has occurred`,
              autoHideDelay: 5000,
              appendToast: true,
              variant: 'danger'
            })
          }
        }
      },
      redirectToPageNamespace(pageNamespace, toastID) {
        this.$bvToast.hide(toastID);
        this.$emit('redirectToPageNamespace', pageNamespace);
      },
      pushOptionToSave(value, option) {
        if (option.from !== undefined) {
          return;
        }

        let saveObject = {
          type: option.type,
          requiresReload: (option.requiresReload || false)
        };

        if (this.usedFor) {
          saveObject.for = this.usedFor;
        }

        if (option.value !== undefined) {
          saveObject.value = value;
        } else {
          saveObject.items = value;
        }

        if (!this.requiresReload) {
          this.requiresReload = saveObject.requiresReload;
        }

        this.options[option.id] = saveObject;
      },
      toggle() {
        if(!this.showCopyContentButton() && this.fieldsetCounter > 1) {
          this.isOpen = !this.isOpen;
        }
      },
      showCopyContentButton() {
        const {options} = this.data;

        const hasTranslatableFields = options.filter(element => element.translatable === true).length > 0;

        return (hasTranslatableFields && this.isFromWidget());
      },
      isFromWidget() {
        const {options} = this.data;

        return options.filter(element => element.from === 'widget').length > 0;
      },
      handleCopyContent(event) {
        event.stopPropagation();

        const data = {
          params: this.data,
          successCallback: this.copyContent,
          locales: this.locales.widgets.copyContentModal,
          confirmButtonVariant: 'success'
        };

        this.$emit('toggleModal', true, data);
      },
      copyContent(data) {
        const {currentLanguage, selectedTheme: {languages}} = this.$store.state.editor;
        const translatableOptions = data.options.filter(element => element.translatable === true);

        translatableOptions.map(option => {
          languages.forEach(language => {
            if (language !== currentLanguage) {
              const value = this.getTranslatableValue(option, language);
              const title = this.getTranslatableTitle(option, language);

              const valueIsEmpty = /^\s*$/.test(value);
              const titleIsEmpty = /^\s*$/.test(title);

              // Copy the content only if other languages' content is empty
              if (!option.value.hasOwnProperty(language) || valueIsEmpty || titleIsEmpty) {
                if (this.optionIsObject(option, language)) {
                  if (valueIsEmpty) {
                    option.value[language].value = option.value[currentLanguage].value;
                  }
                  if (titleIsEmpty) {
                    option.value[language].title = option.value[currentLanguage].title;
                  }
                } else {
                    let newValue =  JSON.parse(JSON.stringify(option.value));
                    newValue[language] = option.value[currentLanguage];
                    option.value = JSON.parse(JSON.stringify(newValue));
                }
              }
            }
          })
        })
      },
      getTranslatableValue(option, language) {
        if (this.optionIsObject(option, language)) {
          return option.value[language].hasOwnProperty('value') ?
                 option.value[language].value :
                 '';
        }

        return option.value[language];
      },
      getTranslatableTitle(option, language) {
        if (this.optionIsObject(option, language)) {
          return option.value[language].hasOwnProperty('title') ?
                 option.value[language].title :
                 '';
        }

        return option.value[language];
      },
      optionIsObject(option, language) {
        return (typeof option.value[language] === 'object');
      },
      handleTriggerSave(value, option) {
        this.pushOptionToSave(value, option);
        
        const pageNamespace = this.getPageNamespace(option);
        this.saveToStore(pageNamespace)
      },
      getPageNamespace(option) {
        if (option.pageNamespace) {
          return option.pageNamespace
        }
        
        if (this.data.pageNamespace) {
          return this.data.pageNamespace
        }
        
        return this.parentPageNamespace;
      }
    }
  };
</script>

<style lang="scss" scoped>
  .fieldset {
    .head {
      position: relative;
      padding: 16px 30px 14px 15px;
      background: $navy-medium-dark;
      cursor: pointer;
      &.can-not-open {
        cursor: default;
      }

      .copy-to-other-language {
        position: absolute;
        top: 50%;
        right: 15px;
        transform: translateY(-50%);
        padding: 5px;
        line-height: 1;
      }

      .title {
        margin: 0;
        font-size: 14px;
        line-height: 21px;
        font-weight: bold;
        text-transform: uppercase;
      }

      .reset-fieldset {
        margin: -1px 0 0 5px;
        padding: 0 5px;
        font-size: 12px;
        transition: all 0.2s;
        opacity: 0;
        &.show-btn {
          opacity: 1;
        }
      }

      .toggler {
        position: absolute;
        top: 50%;
        right: 15px;
        transform: translateY(-50%);
        transition: transform 0.2s;
        transition-timing-function: ease-out;
      }
    }

    .content {
      padding: 15px;

      .option-container {
        margin-bottom: 5px;

        &.option-toprightbottomleft {
          margin-bottom: 10px;
        }

        &:last-child {
          margin-bottom: 0;
        }
      }

      .label {
        font-size: 13px;
      }
    }

    &.is-opened {
      .toggler {
        transform: translateY(-50%) rotate(180deg);
      }

      &:hover {
        .reset-fieldset {
          opacity: 1;
        }
      }
    }

    &.is-closed {
      border-bottom: 1px solid $gray-900;
      .content {
        display: none;
      }
    }
  }
</style>
