<template>
  <b-modal
    :key="active"
    :noEnforceFocus="true"
    :visible="active"
    @hidden="$emit('closeModal')"
    centered
    no-fade
    ref="contentZoneModal"
    size="lg"
    modal-class="popup-modal"
  >
    <template slot="modal-header">
      <h3 class="modal-title">
      {{ computedData[0].title }}
      </h3>
      <b-button
              @click="$emit('closeModal')"
              class="close"
              size="sm"
              variant="link"
      >
        <custom-icon icon="close"/>
      </b-button>
    </template>

    <perfect-scrollbar class="overflow-content-wrapper">
      <language-switcher />
      <Handler :data="computedData[0]"
               :key="computedData[0].key"
               :locales="locales"
               @toggleModal="toggleModal"
               v-if="active" />
    </perfect-scrollbar>
    <template slot="modal-footer">
    </template>
  </b-modal>
</template>

<script>
  import CustomIcon from "@/components/CustomIcon";
  import Handler from "@/components/editor/panel/Handler";
  import LanguageSwitcher from "@/components/editor/panel/LanguageSwitcher";

  export default {
    props: {
      active: Boolean,
      data: Array,
      locales: Object
    },
    components: {
      CustomIcon,
      LanguageSwitcher,
      Handler
    },
    data() {
      return {
        fakedata: [
          {
            title: "el 0",
            id: "element0",
            fieldsets: []
          },
          {
            title: "el 1",
            id: "element1",
            fieldsets: []
          }
        ]
      };
    },
    computed: {
      computedData: {
        get() {
          if (this.data.length === 0) {
            return this.fakedata;
          } else {
            return this.data;
          }
        },
        set(newValue) {
          if (this.data.length === 0) {
            this.fakedata = newValue;
          } else {
            this.data = newValue;
            this.$emit("input", newValue);
          }
        }
      }
    },
    methods: {
      toggleModal(showModal, data) {
        this.$emit("toggleModal", showModal, data);
      }
    }
  };
</script>

<style lang="scss" scoped>
  .overflow-content-wrapper {
    height: 100%;
    min-height: 100%;
  }
  .modal-title {
    margin-top: 2px;
    font-size: 17px;
    font-weight: bold;
    line-height: 1;
