<template>
  <div class="option-container">
    <draggable
      v-model="sortableOptions"
      @start="dragging = true"
      @stop="dragging = false"
      @change="$emit('change', $event)"
      group="sortableOptions"
      handle=".move-option"
    >
      <div v-for="(option, optIndex) in sortableOptions" :key="optIndex" class="row mb-2">
        <div class="col-2">
          <a class="action move move-option" href="javascript:;">
            <custom-icon :color="iconColor" icon="sort" />
          </a>
        </div>
        <div class="col-7">
          {{ option.label }}
        </div>
        <div class="col-3">
          <b-form-checkbox v-model="option.value.status"
                           switch
                           @input="handleInput"
                           :unchecked-value="unCheckedValue(option)"
                           :value="checkedValue(option)" />
        </div>
      </div>
    </draggable>
  </div>
</template>

<script>
import draggable from "vuedraggable";
import CustomIcon from "@/components/CustomIcon";

export default {
  name: "sortable-options.vue",
  components: {
    draggable,
    CustomIcon
  },
  props: {
    value: Array
  },
  computed: {
    sortableOptions: {
      get() {
        return this.value
      },
      set(newValue) {
        this.$emit('input', newValue)
      }
    }
  },
  data() {
    return {
      dragging: true,
      iconColor: "#959595",
      checked: true,
      unchecked: false
    };
  },
  methods: {
    handleInput() {
      this.$emit('input', this.sortableOptions)
    },
    checkedValue(option) {
      if(option.value.values !== undefined) {
        return option.value.values.checked || true;
      }
      return true;
    },
    unCheckedValue(option) {
      if(option.value.values !== undefined) {
        return option.value.values.unchecked || false;
      }
      return false
    }
  },
  mounted() {
  },
};
</script>
