<template>
    <div class="option-container option-background">
        <div class="row">
            <div class="col-12">
                <label class="label" :title="'id: ' + id">{{ label }}</label>
                <colorpicker :id="id + '-color'" :title="'id: ' + id + '-color'" :label="locales.color" v-model="color"/>
                <background-image :id="id + '-image'" :label="locales.color" v-model="image"/>
                <background-gradient
                        :id="id + '-gradient'"
                        :label="locales.color"
                        v-model="gradient"
                />
            </div>
        </div>
    </div>
</template>

<script>
  import colorpicker from './colorpicker'
  import backgroundImage from './background-image'
  import backgroundGradient from './background-gradient'
  import Vue from "vue";

  export default {
    props: {
      id: String,
      label: String,
      value: Object
    },
    components: {
      colorpicker,
      backgroundImage,
      backgroundGradient
    },
    computed: {
      color: {
        get () {
          const { themeConfig } = this.$store.state.editor

          if (themeConfig[this.id] !== undefined) {
              const items = themeConfig[this.id].items;
              return new Vue({
                  computed: {
                      value: {
                          get() {
                              return items.color;
                          },
                          set(newValue) {items.color = newValue;
                          }
                      }
                  }
              });
          }

            const items2 = this.value.items;
            return new Vue({
                computed: {
                    value: {
                        get() {
                            return items2.color;
                        },
                        set(newValue) {
                            items2.color = newValue;
                        }
                    }
                }
            });

        },
        set (newValue) {
          Vue.set(this.value.items, 'color', newValue.value);
          this.$emit('input', this.value)
          this.$emit('triggerSave', this.value.items)

        }
      },
      image: {
        get () {
          const { themeConfig } = this.$store.state.editor

          if (themeConfig[this.id] !== undefined) {
            return {
              items: themeConfig[this.id].items.image
            }
          }
          return {
            items: this.value.items.image
          }

        },
        set (newValue) {
          this.value.items.image = newValue.items
          this.$emit('input', this.value)
          this.$emit('triggerSave', this.value.items)
        }
      },
      gradient: {
        get () {
          const { themeConfig } = this.$store.state.editor

          if (themeConfig[this.id] !== undefined) {
            return {
              items: themeConfig[this.id].items.gradient
            }
          }
          return {
            items: this.value.items.gradient
          }

        },
        set (newValue) {
          this.value.items.gradient = newValue.items
          this.$emit('input', this.value)
          this.$emit('triggerSave', this.value.items)
        }
      },

    },

    data () {
      return {
        locales: this.$t('editor').options.background,
        backgroundPosition: [
          'left top',
          'left center',
          'left bottom',
          'right top',
          'right center',
          'right bottom',
          'center top',
          'center center',
          'center bottom'
        ],
        backgroundAttachment: ['scroll', 'fixed', 'local', 'initial', 'inherit'],
        backgroundRepeat: [
          'repeat',
          'repeat-x',
          'repeat-y',
          'no-repeat',
          'space',
          'round',
          'initial',
          'inherit'
        ],
        backgroundSize: [
          'auto',
          'length',
          'percentage',
          'cover',
          'contain',
          'initial',
          'inherit'
        ],
        backgroundGradientType: ['linear', 'radial'],
        backgroundGradientAngle: ['0deg', '45deg', '90deg', '135deg', '180deg']
      }
    }
  }
</script>

<style lang="scss" scoped>
    .option-container {
        margin-bottom: 5px;

        .sub-option-container {
            margin-bottom: 5px;
        }
    }
</style>
