import { FETCH_PAGES_LIST, SAVE_PAGES_LIST } from "../enums/actions";

export default {
    computed: {
        shopLanguages() {
            return this.$store.state.editor.selectedTheme.languages;
        }
    },
    methods: {
        randomID: function () {
            return Math.round((new Date()).getTime() / 1000);
        },
        async loadPagesList() {
            try {
                const {data} = await this.$store.dispatch(FETCH_PAGES_LIST);
                await this.savePageList(data);
                return data;
            } catch (error) {
                throw new TypeError("failed to load content manager pages list", error);
            }
        },
        savePageList(data) {
            this.$store.commit(SAVE_PAGES_LIST, data);
        },
        newPageStructure(contentPosition) {
            const randomID = this.randomID();
            const shopUrl  = this.$store.state.editor.shopURL;
            
            let pageStructure = {
                "isNewPage": true,
                "id": 0,
                "contentId": randomID,
                "type": "page",
                "pageType": "content",
                "sliderID": 0,
                "link": "",
                "sortOrder": 0,
                "name": "",
                "title": "",
                "description": "",
                "deletable": true,
                "publicLink": `${shopUrl}/shop_content.php?coID=${randomID}`,
                "content": {}
            };

            this.shopLanguages.forEach((language) => {
                pageStructure.content[language] = JSON.parse(JSON.stringify(this.languageContents()));
                pageStructure.content[language]['contentPosition'] = contentPosition;
            });

            return JSON.parse(JSON.stringify(pageStructure));
        },
        languageContents() {
            return {
                "contentName": "",
                "contentTitle": "Untitled",
                "contentHeading": "",
                "contentStatus": false,
                "contentText": "",
                "downloadFile": "",
                "contentsMetaTitle": "",
                "contentsMetaKeywords": "",
                "contentsMetaDescription": "",
                "gmUrlKeywords": "",
                "urlRewrite": "",
                "gmSitemapEntry": false,
                "gmPriority": "0.0",
                "gmChangeFreq": "weekly",
                "gmRobotsEntry": true,
                "opengraphImage": ""
            };
        }
    }
}
