<template>
  <div class="row">
    <div class="col-12">
      <div id="searchbox">
        <Loading v-if="loading" />
        <vue-autosuggest
          :get-suggestion-value="getSuggestionValue"
          :inputProps="{class:'form-control form-control-sm', placeholder: value.attributes.placeholder}"
          :render-suggestion="handleRenderSuggestion"
          :sectionConfigs="{'default': {limit: (this.maxResults)}}"
          :suggestions="filteredOptions"
          @input="handleInput"
          @selected="handleOnSelect"
          id="autocomplete-list"
          v-model="queryTerm"
        >
        </vue-autosuggest>
      </div>
    </div>
  </div>
</template>

<script>
  import axios from 'axios';
  import {VueAutosuggest} from 'vue-autosuggest';
  import Loading from '@/components/Loading'

  export default {
    name: "SearchBox",
    components: {
      Loading,
      VueAutosuggest
    },
    props: {
      id: String,
      label: String,
      value: Object,
      maxResults: {
        type: Number,
        default: 15
      },
      minLength: Number,
      renderSuggestion: Function,
      clearAfterSelect: {
        type: Boolean,
        default: false
      }
    },
    data() {
      return {
        loading: false,
        filteredOptions: [],
        query: '',
        setTimeoutId: null
      }
    },
    computed: {
      queryTerm: {
        get() {
          return this.query;
        },
        set(newValue) {
          this.query = newValue;
        }
      }
    },
    methods: {
      handleInput(term) {
        clearTimeout(this.setTimeoutId);
        this.setTimeoutId = setTimeout(() => this.search(term), 300);
      },
      search(term) {
        if (!term.length ||
          ((this.minLength !== undefined) && this.minLength < term.length)
        ) {
          return false;
        }

        this.loading = true;

        axios.get(
          `${this.getParsedRequestUrl(term)}`,
          {handleError: true} // handle if some error occur and show the toast message
        ).then(response => {
          this.loading = false;
          if (response.status === 200) {
            this.filteredOptions = [{data: response.data}]
          }
        }).catch(() => this.loading = false)
      },
      handleOnSelect(option) {
        if (!option) {
          return false;
        }

        this.value.value = option.item;

        if (this.clearAfterSelect) {
          this.queryTerm = '';
          document.getElementById('autocomplete-list').firstElementChild.focus();
        } else {
          this.queryTerm = this.handleRenderSuggestion(option);
        }

        this.filteredOptions = [];
        this.triggerSave();
      },
      handleRenderSuggestion(suggestion) {
        if (this.renderSuggestion !== undefined) {
          return this.renderSuggestion(suggestion);
        }

        return `${suggestion.item.id} - ${suggestion.item.name}`;
      },
      getParsedRequestUrl(term) {
        const path = new URLSearchParams(this.value.endpoint);
        path.set('term', term);
        path.set('language', this.$store.state.editor.currentLanguage);

        return unescape(path.toString());
      },
      triggerSave() {
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.value);
      },
      getSuggestionValue(item) {
        return this.handleRenderSuggestion(item)
      }
    },
    created() {
      if (this.value.value && this.value.value.name !== undefined) {
        this.query = `${this.value.value.id} - ${this.value.value.name}`;
      }
    }
  }
</script>

