<template>
  <div class="overlay-header">
    <!--<h2 class="page-title" :class="{ breadcrumbActive: breadcrumbCount()>1 }">
      <template v-if="!breadcrumb">
        <button @click="closeOverlay()" class="btn btn-link btn-sm">
          <custom-icon icon="close" />
        </button>
        <slot name="title">{{ title }}</slot>
      </template>
      <template v-else>
        <button @click="goBack" class="btn btn-link btn-sm">
          <custom-icon icon="arrow-left" />
        </button>
        <span class="prefix"
          ><slot name="title">{{ title }}</slot> /
        </span>
      </template>
      <span class="current-item" v-if="breadcrumb">{{ breadcrumb }}</span>
    </h2>

    <pre>
    {{ $store.state.editor.breadcrumb }}
      </pre
      >
    {{ $store.state.editor.breadcrumb.current }}
    item counter: {{ breadcrumbCount() }}-->
    <nav aria-label="breadcrumb">
      <ol
        class="breadcrumb"
        :class="{ 'more-than-two': breadcrumbCount() > 2 }"
      >
        <li class="breadcrumb-icon" v-if="breadcrumbCount() > 1">
          <button
            @click="breadcrumbGoBack($store.state.editor.breadcrumb.current)"
            class="btn btn-link btn-sm"
          >
            <custom-icon icon="arrow-left" />
          </button>
        </li>
        <li class="breadcrumb-icon" v-else>
          <button @click="closeOverlay()" class="btn btn-link btn-sm">
            <custom-icon icon="close" />
          </button>
        </li>
        <li
          v-for="(title, id, index) in $store.state.editor.breadcrumb.items"
          :key="index"
          class="breadcrumb-item"
        >
          <template
            v-if="
              breadcrumbCount() > 2 &&
                index != 0 &&
                index != breadcrumbCount() - 1
            "
          >
            &#x2026;
          </template>
          <template v-else>
            {{ title }}
          </template>
        </li>
      </ol>
    </nav>
    <b-button
      v-if="currentPageNamespace && currentPageNamespace !== $store.state.editor.pageNamespace"
      @click="redirectToPageNamespace(currentPageNamespace)"
      variant="primary"
      size="sm"
      v-b-tooltip.hover.bottomleft
      :title="locales.redirectIframeToPageNamespace"
      class="go-to-page-namespace"
    >
      <custom-icon icon="external-link" />
    </b-button>
  </div>
</template>

<script>
import { mapGetters } from "vuex";
import CustomIcon from "@/components/CustomIcon";
export default {
  name: "Header",
  props: {
    title: String,
    currentPageNamespace: String,
    locales: Object
  },
  components: {
    CustomIcon
  },
  methods: {
    breadcrumbCount() {
      return this.$store.getters["editor/breadcrumbItemsCounter"];
    },
    breadcrumbGoBack(curr) {
      // Get current breadcrumb tree from store
      let breadcrumbItems = this.$store.state.editor.breadcrumb.items;
      let itemsKeys = Object.keys(breadcrumbItems);
      let itemsCount = itemsKeys.length;

      for (let i = 0; i < itemsCount; i++) {
        if (itemsCount - 1 == i) {
          breadcrumbItems[itemsKeys[i]] = undefined;
        }
      }

      breadcrumbItems = JSON.parse(JSON.stringify(breadcrumbItems));
      // Save to store the current breadcrumb
      this.$store.commit("editor/reArrangeBreadcrumb", {
        action: "goBack",
        from: breadcrumbItems
      });
      this.$emit("resendMeData", curr);
    },
    closeOverlay() {
      this.$store.commit("editor/reArrangeBreadcrumb", { action: "clear" });
      this.$emit("triggerCloseOverlay");
    },
    redirectToPageNamespace(pageNamespace) {
      this.$emit("redirectToPageNamespace", pageNamespace);
    }
  },
  computed: {
    /*breadcrumbCounter() {
      return this.$store.getters.breadcrumbItemsCount
    }*/
    ...mapGetters(["breadcrumbItemsCounter"])
  }
};
</script>

