<template>
    <b-modal :no-close-on-backdrop="true"
             :visible="show"
             @hidden="$emit('cancel')"
             @show="getCurrentThemeFromChooserStore()"
             centered
             id="editThemeNameModal"
             no-fade
             ref="editThemeNameModal">
        <template slot="modal-title">
            <span>{{ $t('editor.editThemeNameModal.title') }}</span>
        </template>
        <template slot="modal-header-close" v-if="!loading">
            <custom-icon icon="close"/>
        </template>
    
        <b-form-group
            id="fieldset-1"
            :label="`${$t('editor.editThemeNameModal.fields.name.label')}:`"
            label-for="edit-name-modal-name"
        >
            <b-input
                id="edit-name-modal-name"
                required
                type="text"
                v-model="currentTheme.title"
                autocomplete="off"
            ></b-input>
            <div class="help-block text-danger" v-if="hasError">
                {{ $t('editor.importModal.required.templateList')}}
            </div>
        </b-form-group>
    
        <b-form-group
            id="fieldset-2"
            :label="`${$t('editor.editThemeNameModal.fields.author.label')}:`"
            label-for="edit-name-modal-author"
        >
            <b-input
                id="edit-name-modal-author"
                required
                type="text"
                v-model="currentTheme.author"
                autocomplete="off"
            ></b-input>
            <div class="help-block text-danger" v-if="hasError">
                {{ $t('editor.importModal.required.templateList')}}
            </div>
        </b-form-group>
        <div slot="modal-footer">
            <div class="row">
                <div class="col-md-6">
                    <b-button
                        :disabled="loading"
                        @click="$emit('cancel')"
                        class="btn-block"
                        size="md"
                        v-html="$t('editor.editThemeNameModal.cancel')"
                        variant="default"
                    >
                    </b-button
                    >
                </div>
                <div class="col-md-6">
                    <b-button
                        :disabled="loading"
                        @click="handleSave"
                        class="btn-block"
                        size="md"
                        v-html="$t('editor.editThemeNameModal.confirm')"
                        variant="success"
                    >
                    </b-button>
                </div>
            </div>
        </div>
    </b-modal>
</template>

<script>
    import CustomIcon from '../CustomIcon'

    export default {
        name: 'EditThemeNameModal',
        components: { CustomIcon },
        props: {
            show: Boolean
        },
        data() {
            return {
                loading: false,
                hasError: false,
                currentTheme: {}
            }
        },
        methods: {
            async handleSave() {
                this.loading = true
    
                try {
                    this.$store
                        .dispatch('editor/saveTheme', {
                            title: this.currentTheme.title, author: this.currentTheme.author
                        })
                        .then(() => {
                            this.setThemeNameAndAuthorInChooserStore()
                            this.setCurrentPreviewThemeNameInStore()
                            this.resetFields();
                            this.$emit('cancel');
                            this.$bvToast.toast(this.$t('editor.editThemeNameModal.messages.success'),{
                                title: this.$t('editor.editThemeNameModal.title'),
                                autoHideDelay: 5000,
                                appendToast: true,
                                variant: 'success'
                            })
                        })
    
                } catch (e) {
                    this.resetFields()
                    this.$emit('cancel')
                }
            },
            resetFields () {
                this.loading = false
            },
            getCurrentThemeFromChooserStore() {
                const { sourceThemeId } = this.$store.state.editor
                const currentTheme = this.$store.state.chooser.themes.filter(theme => theme.id === sourceThemeId);
                
                if (currentTheme.length) {
                    this.currentTheme = {...currentTheme[0]}
                }
                
                return this.currentTheme
            },
            setThemeNameAndAuthorInChooserStore() {
                this.$store.dispatch('chooser/updateThemeNameAndAuthor', this.currentTheme)
            },
            setCurrentPreviewThemeNameInStore() {
                this.$store.dispatch('editor/updatePreviewThemeName', `${this.currentTheme.title} Preview`)
            }
        }
    }
</script>

<style lang="scss" scoped>
    #editThemeNameModal {
        &::v-deep .dropdown-select {
            option {
                background: $white;
                color: $navy-medium-dark;
            }
        }
        
        #template-list.has-error {
            border: 1px solid $danger !important;
        }
    }
</style>