<template>
  <div v-if="pagesList && pagesList.length">
    <category-wrapper
      v-for="(categoryList, index) in pagesList"
      :key="index"
      :value.sync="categoryList"
      :newPageStructure="newPageStructure()"
      @goTo="(link) => goTo(link)"
      @sortOrderChanged="sortOrderChanged()"
      @updatePagesList="(changesWereMade) => updatePagesList(changesWereMade)"
    />
  </div>
</template>

<script>
import ContentManager from "@/mixins/contentManager";
import CategoryWrapper from "@/components/editor/content-manager/CategoryWrapper";

export default {
  components: {
    CategoryWrapper,
  },
  mixins: [ContentManager],
  created() {
    if (!this.$store.state.editor.pagesList.length) {
      this.loadPagesList();
    }
  },
  computed: {
    pagesList: {
      get() {
        return this.$store.state.editor.pagesList;
      },
      set(newValue) {
        this.savePageList(newValue);
      },
    },
  },
  methods: {
    goTo: function (link) {
      this.$emit("goTo", link);
    },
    updatePagesList: function (changesWereMade) {
      this.savePageList(this.pagesList);
      this.$emit("reloadIframeMenus");

      if (changesWereMade) {
        this.$store.commit("editor/changeMadeChangesStatus", true);
      }
    },
    sortOrderChanged: function () {
      this.pagesList.forEach((item) => (item.sortOrderChanged = true));
      this.updatePagesList(true);
    },
  },
};
</script>

<style lang="scss" scoped>
.top-bar {
  padding: 15px;
}
</style>
