<template>
  <nav class="lang-switcher">
    <ul class="nav">
      <li class="nav-item" v-for="(lang, langIndex) in languages" :key="langIndex">
        <a
          class="nav-link"
          v-on:click="currentLanguage = lang"
          :class="{ active: currentLanguage === lang }"
          ><img
            class="flag"
            :src="$store.state.editor.shopURL + '/images/flags/4x3/' + lang + '.svg'"
            :alt="lang + ' language'"
        /></a>
      </li>
    </ul>
  </nav>
</template>

<script>
export default {
  props: {
    value: String
  },
  computed: {
    languages() {
      return this.$store.state.editor.selectedTheme.languages;
    },
    currentLanguage: {
      get() {
        return this.$store.state.editor.currentLanguage;
      },
      set(newLanguage) {
        this.$store.commit("editor/updateLanguage", newLanguage);
      }
    }
  }
};
</script>

<style scoped lang="scss">
.lang-switcher {
  .nav {
    .nav-item {
      .nav-link {
        cursor: pointer;
        &.active {
          background: $navy-medium-dark;
        }
        .flag {
          width: 24px;
        }
      }
    }
  }
}
</style>
