<template>
  <div class="option-container option-imageupload">
    <div class="row">
      <div class="col-5">
        <label class="label">{{ label }}</label>
      </div>
      <div class="col-7">
        <div class="row no-gutters">
          <div class="col">
            <button
              @click="openImageChooser"
              class="btn btn-outline-light btn-sm btn-block text-small btn-option"
            >
              {{getButtonText('select')}}
            </button>
            <button
              @click="clearImage"
              class="btn btn-outline-light btn-sm btn-block text-small btn-option"
            >
              {{getButtonText('delete')}}
            </button>
          </div>
          <div class="col-auto">
            <div class="thumbnail-container">
              <img
                :src="currentValue"
                @click="openImageChooser"
                alt=""
                class=""
              />
            </div>
          </div>
          <input type="hidden" v-model="currentValue" />
        </div>
      </div>
    </div>
    <b-modal
      centered
      class="image-upload-modal"
      ref="image-upload-modal"
      size="xl"
      :title="getImageUploadTitle()"
    >
      <iframe
        :src="fileManagerUrl"
        class="filemanager-iframe"
        frameborder="0"
        id="filemanager-iframe"
      ></iframe>
      <template #modal-footer="{ cancel }">
        <b-button variant="secondary" @click="cancel()">
          {{ cancelButtonLabel() }}
        </b-button>
      </template>
    </b-modal>
  
    <b-modal
        centered
        class="no-image-upload-modal"
        ref="no-image-upload-modal"
        size="xl"
        :title="getImageUploadTitle()"
        :ok-only=true
        :hide-header-close=true
    >
      {{getNoFilemanagerText()}}
    </b-modal>
  </div>
</template>

<script>
  export default {
    props: {
      id: String,
      label: String,
      value: Object,
      language: String
    },
    computed: {
      currentValue: {
        get() {
          let value =
            this.id in this.$store.state.editor.themeConfig
            ? this.$store.state.editor.themeConfig[this.id].value
            : this.value.value;

          if (Boolean(this.language) && this.value.translatable) {
            return value[this.language];
          } else {
            return value;
          }
        },
        set(newValue) {
          if (Boolean(this.language) && this.value.translatable) {
            this.value.value[this.language] = newValue;
            this.value.value = JSON.parse(JSON.stringify(this.value.value));
          } else {
            this.value.value = newValue;
          }

          this.$emit("input", this.value);

          if (this.value.id) {
            this.$emit("triggerSave", this.value.value);
          }
        }
      }
    },
    data() {
      return {
        fileManagerUrl: null,
        folder: null,
        shopBaseUrl: this.$store.state.editor.shopURL
      };
    },
    methods: {
      getNoFilemanagerText() {
        return this.$i18n.messages[this.$i18n.locale].editor.uninstalledFilemanager;
      },
      getImageUploadTitle() {
        return this.$i18n.messages[this.$i18n.locale].editor.uploadImageModalTitle;
      },
      cancelButtonLabel() {
        return this.$i18n.messages[this.$i18n.locale].editor.customScssModal.cancel;
      },
      openImageChooser() {
        const urlParameters = new URLSearchParams(location.search);
        const filemanagerInstalled = urlParameters.get("noImageUpload") !== '1';
        
        if (filemanagerInstalled) {
          this.$refs["image-upload-modal"].show();
        } else {
          this.$refs["no-image-upload-modal"].show();
        }
      },

      clearImage() {
        this.currentValue = "";
        this.triggerEmitIframe();
      },

      triggerEmitIframe() {
        if (this.value.selector) {
          let iframeData = {
            selector: this.value.selector,
            holder: this.value.holder,
            value: this.currentValue
          };
          this.$emit("sendDataToIframe", iframeData);
        }
      },
      getButtonText(type) {
        return this.$t('editor').buttons[type] || '';
      }
    },
    created() {
      const locale =
        this.$i18n.locale === "de"
        ? this.$i18n.locale
        : this.$i18n.locale + "_" + this.$i18n.locale.toUpperCase();

      switch (this.label) {
        case "Logo":
          this.folder = "Logos";
          break;
        case "Picture":
          this.folder = "Backgrounds";
          break;
        default:
          break;
      }

      this.fileManagerUrl = [
        this.shopBaseUrl,
        "/ResponsiveFilemanager/filemanager/dialog.php?field_id=",
        this.id,
        "&crossdomain=1&multiple=0&sub_folder=images&lang=",
        locale
      ].join("");
    },
    mounted() {
      const onMessage = ({data}) => {
        const {sender, url, field_id} = data;

        if (sender !== "responsivefilemanager" || field_id !== this.id) {
          return;
        }
        this.$refs["image-upload-modal"].hide();
        this.currentValue = url.replace(/([^:]\/)\/+/g, "$1");
      };

      window.addEventListener("message", onMessage);
    }
  };
</script>

<style lang="scss" scoped>
  .btn-option {
    padding-top: 3px;
    padding-bottom: 3px;
    font-size: 12px;
    max-width: 90%;
    border-color: $navy-light;

    &:last-child {
      margin-bottom: 0;
    }
  }

  .thumbnail-container {
    @include clearfix();
    position: relative;
    overflow: hidden;
    width: 80px;
    height: 80px;
    background: url("../../../../assets/editor-bg.png") repeat;
    border: 2px solid $navy-light;

    img {
      position: absolute;
      left: 0;
      max-width: none;
      max-height: 100%;
      transition: all 0.7s;
    }

    &:hover {
      img {
        transform: translateX(calc(-100% + 80px));
      }
    }
  }

  #filemanager-iframe {
    width: 100%;
    min-height: 600px;
  }

  .text-small {
    font-size: 10px !important;
  }
</style>
