<template>
  <div class="option-container">
    <draggable
      :list="selectedProducts"
      @start="dragging = true"
      @stop="dragging = false"
      @change="$emit('change', $event)"
      group="selectedProducts"
      handle=".move-product"
    >
      <div
        :key="product.id"
        class="row product-row mt-2 mb-2"
        v-for="(product, index) in selectedProducts"
      >
        <div class="col-2">
          <div class="product-image-container">
            <img :src="product.image" alt="" />
          </div>
        </div>
        <div class="col-7 p-0">
          <custom-icon
            :color="iconColor"
            class="ml-1 mr-2"
            icon="eye"
            title="product invisible"
            v-b-tooltip.hover
            v-if="!product.active"
          ></custom-icon
          >
          {{ product.id + " - " + product.name }}
        </div>

        <div class="col-3 text-right">
          <a class="action move move-product mr-2" href="javascript:;"
          >
            <custom-icon :color="iconColor" icon="sort"
            />
          </a>
          <a @click="removeProduct(index)" class="action" href="javascript:;"
          >
            <custom-icon :color="iconColor" icon="close"
            />
          </a>
        </div>
      </div>
    </draggable>
  </div>
</template>

<script>
  import draggable from "vuedraggable";
  import CustomIcon from "@/components/CustomIcon";

  export default {
    components: {
      draggable,
      CustomIcon
    },
    props: {
      selectedProducts: {
        required: true,
        type: Array
      }
    },
    data() {
      return {
        dragging: true,
        iconColor: "#959595"
      };
    },
    methods: {
      removeProduct(index) {
        const removed = this.selectedProducts.splice(index, 1);
        this.$emit('itemDeleted', removed[0] || [])
      },
      getProductImagePath(imageName) {
        return this.$store.state.editor.shopURL + "/images/product_images/thumbnail_images/" + imageName
      }
    }
  };
</script>

<style lang="scss">
  .product-row {
    .product-image-container {
      background: #FEFEFE;
      padding: 1px;
      border-radius: 3px;
      border: 1px solid darken(#FEFEFE, 10%);
      height: 30px;
      width: 30px;
    }
  }
</style>
