<template>
    <div id="wrapper" v-show="show">
        <div class="container">
            <div class="row">
                <div class="col">
                    <b-button @click="handleCloseAction" id="close" v-if="!hideCloseIcon() === true" variant="link">
                        <custom-icon icon="close"/>
                        {{ locales.close }}
                    </b-button>
                </div>
            </div>
            <div class="row">
                <div class="col">
                    <h1 id="title">{{ locales.heading }}</h1>
                </div>
            </div>
            <div class="row no-gutters">
                <theme-item :active="theme.active"
                            :author="theme.author"
                            :editable="theme.editable"
                            :editing="editing"
                            :id="theme.id"
                            :key="theme.id"
                            :locales="locales.item"
                            :removable="theme.removable"
                            :thumbnail="theme.thumbnail"
                            :title="theme.title"
                            @activate="$emit('activate', theme.id)"
                            @delete="deleteThemeAction(theme.id)"
                            @download="$emit('download', theme.id)"
                            @duplicate="duplicatedTheme => handleDuplicateThemeAction({theme, duplicatedTheme})"
                            @edit="openThemeToEdit(theme.id)"
                            v-for="theme in themeList"
                ></theme-item>
                <theme-placeholder
                    :locales="locales.placeholder"
                    :upload-status="themeUploadStatus"
                    @overwriteTheme="status => $emit('overwriteTheme', status)"
                    @reset="$emit('reset-placeholder')"
                    @upload="formData => $emit('upload', formData)"
                />
            </div>
        </div>
    </div>
</template>

<script>
    import CustomIcon from './CustomIcon'
    
    import ThemeItem from './chooser/Item'
    import ThemePlaceholder from './chooser/Placeholder'
    
    export default {
        components: {
            ThemeItem,
            ThemePlaceholder,
            CustomIcon
        },
        
        props: {
            show: Boolean,
            themeUploadStatus: Number,
            themes: Array,
            locales: Object
        },
        
        data() {
            return {
                needRedirection: false
            }
        },
        
        computed: {
            themeList() {
                return this.themes.filter(function(theme) {
                    return !theme.preview;
                });
            },
            editing() {
                return `${this.$store.state.editor.sourceThemeId}`
            },
        },
        
        created() {
            this.$emit('fetch')
        },
        
        methods: {
            handleCloseAction() {
                if (!this.needRedirection) {
                    this.$emit('hide')
                    return
                }
                
                let activeTheme = this.$store.state.chooser.themes.filter(theme => theme.active || false)
                
                if (!activeTheme.length) {
                    this.$emit('hide')
                    return
                }
                
                activeTheme = activeTheme.shift()
                
                const urlParameters = new URLSearchParams(location.search)
                urlParameters.set('editing', activeTheme.id)
                
                window.location.href = '?' + unescape(urlParameters.toString())
            },
            deleteThemeAction(theme) {
                const editingTheme = this.$store.state.editor.sourceThemeId
                
                if (editingTheme === theme) {
                    this.$store.commit('editor/changeMadeChangesStatus', false)
                    this.needRedirection = true
                }
                
                this.$emit('delete', theme)
            },
            hideCloseIcon() {
                const parameters = new URLSearchParams(location.search)
                const editing = parameters.get('editing');
                
                return (parameters.get('welcome') === '1' || editing === null)
                    || !this.$store.state.editor.selectedTheme
            },
            openThemeToEdit(theme) {
                const urlParameters = new URLSearchParams(location.search)
                urlParameters.set('editing', theme)
                urlParameters.delete('welcome')
                const redirectParameters = '?' + unescape(urlParameters.toString())
                
                window.location.href = redirectParameters
            },
            handleDuplicateThemeAction({theme, duplicatedTheme}) {
                const parentThemeID = {parentThemeID: theme.id}
                
                theme = {...theme, ...duplicatedTheme, ...parentThemeID}
                
                if (duplicatedTheme.id === undefined) {
                    delete theme.id
                }
                
                if (duplicatedTheme.title === undefined) {
                    delete theme.title
                }
                this.$emit('duplicate', theme)
            }
        }
    }
</script>

