import axios from 'axios'
import {FETCH_TOKEN} from "../enums/endpoints";

export default {
  namespaced: true,
  state: {
    token: window.jwtToken || null
  },
  mutations: {
    updateToken(state, newToken) {
      state.token = newToken;
    }
  },
  getters: {},
  actions: {
    produceAuthenticationToken({commit, state}) {
      if (state.token) {
        return new Promise((resolve) => {
          resolve(state.token);
        })
      } else {/*initialize token*/
        return new Promise((resolve, reject) => {
          const instance = axios.create();
          let result = instance.get(FETCH_TOKEN());
          result.then(function ({data}) {
            commit('updateToken', data.token)
            resolve(state.token);
          }).catch(error => {
            reject(error);
          });
        });
      }
    }
  },
};
