<template>
  <div class="option-container option-checkbox">
    <div class="row">
      <div class="col">
        <b-form-checkbox v-model="currentValue" switch :unchecked-value="unchecked" :value="checked" >
          <span class="label">{{ label }}</span>
        </b-form-checkbox>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  props: {
    id: String,
    label: String,
    value: Object
  },

  data() {
    return {
      checked: true,
      unchecked: false
    }
  },

  mounted() {
    this.setCheckedValues();
  },

  computed: {
    currentValue: {
      get() {
        return this.value.value;
      },
      set(newValue) {
        if (this.value.value !== newValue) {
          this.value.value = newValue;
          this.$emit("input", this.value);
          this.$emit("triggerSave", newValue);
        }
      }
    }
  },

  methods: {
    setCheckedValues() {
      if (this.value.values !== undefined) {
        this.checked = this.value.values.checked;
      }

      if (this.value.values !== undefined) {
        this.unchecked = this.value.values.unchecked;
      }
    }
  }
};
</script>

<style scoped lang="scss"></style>
