<template>
  <div class="option-container option-selectbox">
    <div class="row">
      <div class="col-5">
        <label class="label">{{ label }}</label>
      </div>
      <div class="col-7">
        <b-form-select
          ref="dropdownSelect"
          v-model="currentValue"
          :options="value.options"
          class="dropdown-select"
          :id="id"
        >
        </b-form-select>
      </div>
    </div>
  </div>
</template>

<script>
export default {
    props: {
        id: String,
        label: String,
        value: Object
    },
    computed: {
        currentValue: {
            get() {
                return this.id in this.$store.state.editor.themeConfig
                    ? this.$store.state.editor.themeConfig[this.id].value
                    : this.value.value;
            },
            set(newValue) {
                this.value.value = newValue;
                this.$emit('input', this.value);
                this.$emit('triggerSave', newValue);
            }
        }
    }
};
</script>

<style scoped lang="scss">
.dropdown-select {
  option {
    background: $white;
    color: $navy-medium-dark;
  }
}
</style>
