<template>
    <padding :id="id" :label="label" v-model="computedValue" v-on:triggerSave="$emit('triggerSave', $event)"/>
</template>

<script>
    import padding from "./padding";

    export default {
        props: {
            id: String,
            label: String,
            value: Object
        },
        components: {
            padding
        },
        computed:{
            computedValue:{
                get(){
                    return this.value;
                },
                set(newValue){
                    this.$emit('input', newValue);
                }
            }
        }
    };
</script>

