<script>
    import Vue from "vue";
    import { compileToFunctions } from 'vue-template-compiler';
    import store from "@/store";
    import i18n from '@/i18n.js';
    import css from "!!raw-loader!./../assets/vueFrame/style.css";
    import contentZone from './editor/widgets/contentZone';
    import CookiesMixin from "@/mixins/cookies";
    
    export default {
        name: "vueFrame",
        mixins: [CookiesMixin],
        props: {
            contentZoneList: Array,
            locales: Object,
            previewChanges: Boolean
        },
        data() {
            return {
                instances: []
            }
        },
        render: function(h) {
            this.setThemeIdCookie();
            
            return h("iframe", {
                on: {load: this.triggerLoadFile}
            });
        },
        watch: {
            previewChanges() {
                this.togglePreviewChanges();
            }
        },
        methods: {
            togglePreviewChanges() {
                
                const container = this.$el.contentWindow || this.$el.contentDocument;
                const iframeDocument = container.document ? container.document : container;
                
                if (this.previewChanges) {
                    iframeDocument.body.classList.add('style-edit-edit-mode-off');
                    iframeDocument.body.classList.remove('style-edit-edit-mode-on');
                } else {
                    iframeDocument.body.classList.add('style-edit-edit-mode-on');
                    iframeDocument.body.classList.remove('style-edit-edit-mode-off');
                }
            },
            triggerLoadFile() {
                const container = this.$el.contentWindow || this.$el.contentDocument;
                const iframeDocument = container.document ? container.document : container;
                
                container.addEventListener('beforeunload', () => {
                    this.setThemeIdCookie();
                    this.$emit("activeLoading");
                    this.destroyInstances();
                });
                
                try {
                    this.savePageNamespaceToStore(iframeDocument);
                    this.addStyleToiframe(iframeDocument);
                    this.iniPageSelectors(iframeDocument);
                    this.findContentZones(iframeDocument);
                    this.iniContentManagerBlocks();
                    this.togglePreviewChanges();
                } finally {
                    this.$emit("load");
                    
                    this.scheduleThemeIdCookieRemoval();
                }
                
                
            },
            
            addStyleToiframe(document) {
                let head = document.head || document.getElementsByTagName("head")[0],
                    style = document.createElement("style");
                
                head.appendChild(style);
                
                style.type = "text/css";
                if (style.styleSheet) {
                    // This is required for IE8 and below.
                    style.styleSheet.cssText = css;
                } else {
                    style.appendChild(document.createTextNode(css));
                }
            },
            
            initOverlayOpen(selector) {
                this.$emit("openOverlayForCategory", selector);
            },
            
            iniPageSelectors(iframeDocument) {
                let selTheme = this.$store.state.editor.selectedTheme;
                let availableCategories = null;
                if (selTheme && selTheme.config && selTheme.config.areas && selTheme.config.areas.categories) {
                    availableCategories = selTheme.config.areas.categories;
                }
                if (availableCategories) {
                    for (let i = 0; i < availableCategories.length; i++) {
                        let menuId = availableCategories[i].id;
                        let selector = availableCategories[i].selector;
                        let title = availableCategories[i].title;
                        let element = iframeDocument.querySelector(selector);
                        if (element) {
                            element.classList.add('editable-partial');
                            
                            let editWrapperTrigger = iframeDocument.createElement("div");
                            editWrapperTrigger.classList.add("edit-section-trigger");
                            editWrapperTrigger.innerHTML =
                                title + '<a href="javascript:;"><i class="fa fa-pencil"></i></a>';
                            element.appendChild(editWrapperTrigger);
                            
                            editWrapperTrigger.onclick = function() {
                                this.initOverlayOpen(menuId);
                            }.bind(this);
                        }
                    }
                }
            },

            iniContentManagerBlocks() {

              const container = this.$el.contentWindow || this.$el.contentDocument;
              const iframeDocument = container.document ? container.document : container;

              let pageList = this.$store.state.editor.pagesList;
              if (pageList && pageList.length) {
                for (let i = 0; i < pageList.length; i++) {
                  let blockId = pageList[i].id;
                  let selector = `#${blockId}`;
                  let element = iframeDocument.querySelector(selector);
                  if (element) {
                    let menuItems = pageList[i].items;
                    let self = this;

                    if(iframeDocument.getElementById(`${blockId}-menu-template`)) {
                      const menuItemsComponent = {
                        ...compileToFunctions(iframeDocument.getElementById(`${blockId}-menu-template`).innerHTML),
                        props: ['items'],
                        methods: {
                          goTo: function(goToData){
                            self.$emit("redirectIFrame", goToData);
                          }
                        }
                      };

                      const menuComponent = Vue.extend(menuItemsComponent);

                      new menuComponent({
                        propsData: {
                          items: menuItems
                              .filter(item => item.content[this.$store.state.editor.currentLanguage].contentStatus)
                              .map(item => {
                                return {
                                  title: item.content[this.$store.state.editor.currentLanguage].contentTitle,
                                  content: item
                                }
                              })
                        }
                      }).$mount(element)
                    }
                  }
                }
              }
            },
            
            findContentZones(iframeDoc) {
                let contentZones = [];
                let contentZoneBlocks = iframeDoc.querySelectorAll('.gx-content-zone');
                
                for (let i = 0; i < contentZoneBlocks.length; i++) {
                    let contentZoneID = contentZoneBlocks[i].getAttribute('data-gx-content-zone');
                    
                    if (contentZoneID) {
                        contentZones.push(contentZoneID);
                    }
                }
                
                this.$emit("load-content-zones", contentZones);
                
            },
    
            findPageNamespace(iframeDoc) {
                const pageNamespaceElement = iframeDoc.getElementById('page_namespace');
                return pageNamespaceElement ? pageNamespaceElement.value : '';
            },
    
            savePageNamespaceToStore(iframeDoc) {
                const pageNamespace = this.findPageNamespace(iframeDoc);
        
                this.$store.commit("editor/savePageNamespace", pageNamespace);
                this.$emit("onLoadPageNamespace", pageNamespace);
            },
            
            /**
             * Destroy dynamically created instances in order to remove the listeners of it
             */
            destroyInstances() {
                do {
                    const instance = this.instances.shift()
                    if (instance) {
                        instance.$destroy()
                    }
                } while (this.instances.length > 0)
            },
            
            renderChildren() {
                
                this.applications = [];
                const container = this.$el.contentWindow || this.$el.contentDocument;
                const iframeDocument = container.document ? container.document : container;
                
                if (this.contentZoneList.length) {
                    this.contentZoneList.forEach((contentZoneElement) => {
                        const contentZoneContainer = iframeDocument.getElementById(
                            contentZoneElement.id
                        );
                        
                        if (contentZoneContainer) {
                            let self = this;
                            
                            const ComponentClass = Vue.extend(contentZone);
                            const instance = new ComponentClass({
                                i18n,
                                store,
                                propsData: {
                                    locales: this.locales.contentZone,
                                    contentZone: contentZoneElement
                                },
                                mounted() {
                                    this.$on(
                                        'handleOverlay',
                                        (overlayData, opened) => self.$emit("handleOverlay", overlayData, opened)
                                    );
                                    this.$on(
                                        'goTo',
                                        (goToData) => self.$emit("goTo", goToData)
                                    );
                                    this.$on(
                                        'toggleModal',
                                        (opened, data) => self.$emit("toggleModal", opened, data)
                                    );
                                    this.$on(
                                        'handleIframe',
                                        (action) => self.$emit("handleIframe", action)
                                    );
                                    this.$on('closeOverlay', () => self.$emit('closeOverlay'))
                                }
                            });
                            
                            instance.$mount(contentZoneContainer);
                            this.instances.push(instance)
                        }
                    })
                }
            },
            
            
        },
    };
</script>
