<template>
	<div id="style-edit-container">
		<div class="theme-editor-wrapper">
			<div class="theme-editor-panel" :class="{ 'active-overlay' : editor.overlay.visible || editor.contentZoneOverlay.visible }">
				<div class="editor-panel-header">
					<div class="row">
						<div class="col-8">
							<button
								@click="$emit('show-chooser')"
								class="btn btn-link hamburger-menu"
								:title="$store.state.editor.selectedTheme.title"
							>
								<custom-icon icon="hamburger"/>
								{{ $store.state.editor.selectedTheme.title }}
								<!--{{ $store.state.editor.tempTheme }}-->
							</button>
						</div>
						<div class="col-4 text-right">
							<button
								class="btn btn-link home-button"
								@click="redirectIFrame($store.state.editor.shopURL)"
								v-b-tooltip.hover
								:title="$t('editor.buttons.homeTooltip')"
							>
								<custom-icon :class="homeIcon" icon="home"/>
							</button>
							
							<b-dropdown right variant="link">
								<template slot="button-content">
									<custom-icon icon="more"/>
								</template>
								<b-dropdown-item @click="openEditThemeNameModal()" v-if="themeIsUpdatable"
								>{{ $t("editor.menu.editThemeName") }}
								</b-dropdown-item>
								<b-dropdown-divider v-if="themeIsUpdatable"></b-dropdown-divider>
								<b-dropdown-item v-b-modal.customStyleModal
								>{{ $t("editor.menu.editCss") }}
								</b-dropdown-item>
								<b-dropdown-item style="display: none;"
								>{{ $t("editor.menu.download") }}
								</b-dropdown-item>
								<b-dropdown-item @click="openImportSettingsModal()"
								>{{ $t("editor.menu.importSettings") }}
								</b-dropdown-item>
							</b-dropdown>
						</div>
					</div>
					<SaveBeforeLeaveModal :made_changes="editor.made_changes"/>
					<CustomScssModal
						:openModal="editor.custom_style.show"
						@handleIframe="handleIframe"
					/>
					<import-settings-modal
							:show="showImportSettingsModal"
							@cancel="showImportSettingsModal = false"
							@handleIframe="handleIframe"
					/>
					<edit-theme-name-modal
							:show="showEditNameModal"
							:name="$store.state.editor.selectedTheme.title"
							@cancel="showEditNameModal = false"
					/>
				</div>
				<div class="editor-panel-tabs">
					<b-tabs class="editor-tabs" v-model="editor.tabIndex">
						<b-tab :title="$t('editor.tabs.basics')" active>
							<perfect-scrollbar
								class="tabs-content-wrapper"
								v-if="$store.state.editor.selectedTheme.config"
							>
								<Handler
									:data="$store.state.editor.selectedTheme.config.basics"
									@handleIframe="handleIframe"
									@toggleModal="toggleModal"
									@closeOverlay="closeAllOverlays"
								/>
							</perfect-scrollbar>
						</b-tab>
						<b-tab :title="$t('editor.tabs.areas')">
							<perfect-scrollbar
								class="tabs-content-wrapper"
								v-if="$store.state.editor.selectedTheme.config"
							>
								<Handler
									:data="$store.state.editor.selectedTheme.config.areas"
									:locales="locales"
									@handleIframe="handleIframe"
									@handleOverlay="handleOverlay"
									@toggleModal="toggleModal"
								/>
							</perfect-scrollbar>
						</b-tab>
						<b-tab title="Contents">
              <b-tabs class="editor-tabs__second-level" v-model="editor.contents.tabIndex">
                <b-tab :title="$t('editor.tabs.pages')">
                  <perfect-scrollbar
                      class="tabs-content-manager-wrapper"
                      v-if="$store.state.editor.selectedTheme.config"
                  >
                    <content-manager-list
                        @goTo="link => redirectIFrame(link)"
                        @reloadIframeMenus="reloadIframeMenus"/>
                  </perfect-scrollbar>
                </b-tab>
                <b-tab :title="$t('editor.tabs.widgets')" active>
                  <perfect-scrollbar
                      class="tabs-content-manager-wrapper"
                      v-if="$store.state.editor.selectedTheme.config"
                  >
                    <div v-if="editor.preview || !existsContentZones" class="widgets-head-message">
                      <b-alert show variant="warning"
                      >{{ $t("editor.widgets.noContentZones") }}
                      </b-alert>
                      <b-alert show variant="info"
                      >{{locales.widgets.previewModeMessage}}
                      </b-alert>
                    </div>

                    <draggable
                        :clone="cloneDog"
                        :group="{ name: 'widgets', pull: 'clone', put: false }"
                        :list="dragableWidgets"
                        :disabled="!existsContentZones || editor.preview"
                        :sort="false"
                        @change="log"
                        class="available-widgets"
                        :setData="modifyDragItem"
                    >
                      <div
                          v-for="(widget, widgetIndex) in dragableWidgets"
                          :key="widgetIndex"
                          v-bind:class="{
                  'draggable-widget': true,
                  'no-content-zone': !existsContentZones || editor.preview
                }"
                      >
                        <div class="widget-icon">
                          <img
                              :alt="widget.icon.name"
                              :src="$store.state.editor.shopURL + '/' + widget.icon.file"
                          />
                        </div>
                        <h4 class="widget-label">{{ widget.title }}</h4>
                      </div>
                    </draggable>
                  </perfect-scrollbar>
                </b-tab>
              </b-tabs>
						</b-tab>
					</b-tabs>
				</div>
				<div class="editor-panel-footer">
					<b-button @click="save()" class="btn-block" variant="primary" :disabled="saveButtonStatus > 1">
						{{ saveBtnLabel() }}
						<!-- @todo: :disabled="!$store.state.editor.madeChangesStatus" -->
					</b-button>
					<b-button @click="exitEditor" class="btn-block" variant="link"
					>{{ $t("editor.buttons.exit") }}
					</b-button>
					
					<div id="expertmode-preview-bar-container" class="row">
						<div class="col-6">
							<ExpertModeBar
								:expertmode="expertmode"
								:locales="locales"
								@trigger-expertmode="toggleExpertModeOpt()"
							/>
						</div>
						<div class="col-6">
							<PreviewChangesBar
								:preview="editor.preview"
								:locales="locales"
								@trigger-preview-changes="togglePreviewChangesOpt()"
							/>
						</div>
					</div>
					<ResolutionBar
						:size="editor.size"
						:preview="editor.preview"
						@triggerWindowResize="handleEditorResize"
					/>
				</div>
				
				<DynamicOverlay
                        v-if="editor.overlay.visible"
					:active="editor.overlay.visible"
					:data="editor.overlay.data"
					:locales="locales"
					@change="onOverlayChange"
					@closeOverlay="editor.overlay.visible = false"
					@handleIframe="handleIframe"
					@reloadPreviewTheme="reloadPreviewTheme"
					@reSendBlockData="reSendDataToOverlay"
					@redirectToPageNamespace="redirectToPageNamespace"
				/>
				
				<Overlay
                        v-if="editor.contentZoneOverlay.visible"
					:active="editor.contentZoneOverlay.visible"
					:data="editor.contentZoneOverlay.data"
					:locales="locales"
					@closeOverlay="editor.contentZoneOverlay.visible = false"
					@toggleModal="toggleModal"
				/>
				
				<Popup
                        v-if="editor.contentZoneModal.visible"
					:active="editor.contentZoneModal.visible"
					:data="editor.contentZoneModal.data"
					:locales="locales"
					@closeModal="editor.contentZoneModal.visible = false"
					@toggleModal="toggleModal"
				/>
			</div>
			<div class="theme-editor-viewer">
				<div id="editor">
					<div class="editor-wrapper" ref="editor">
						<Loading
							v-if="$store.state.editor.iframeLoading && !showThemeChooser"
						/>
            <form
                ref="postToIframe"
                :action="editor.postToIframe.action"
                :method="editor.postToIframe.method"
                target="style-edit-iframe"
                class="post-to-iframe-form"
            >
              <input type="hidden" name="gambio_se_content_manager" :value="JSON.stringify(editor.postToIframe.value)">
            </form>
						<vueFrame
							:contentZoneList="initContentZones"
							:language="language"
							:locales="locales"
							:previewChanges="editor.preview"
							:src="shopIFrameURL"
							@goTo="goTo"
              @redirectIFrame="link => redirectIFrame(link)"
							@handleIframe="handleIframe"
							@handleOverlay="handleContentZoneOverlay"
							@load-content-zones="requestContentZones"
							@mounted="handleContentZoneCreation"
							@openOverlayForCategory="openOverlayForCategory"
							@toggleModal="toggleModal"
							@closeOverlay="closeAllOverlays"
							@activeLoading="activeLoading"
							@onLoadPageNamespace="handlePageNamespaceEvent"
              name="style-edit-iframe"
							class="shop-iframe"
							frameborder="0"
							id="shop-iframe-editor"
							ref="shopIframe"
							v-on:load="load"
						>
						</vueFrame>
					</div>
				</div>
			</div>
		</div>
	</div>
</template>

<script>
	import draggable from "vuedraggable";
	
	import DynamicOverlay from "@/components/editor/panel/DynamicOverlay";
	import Overlay from "@/components/editor/panel/Overlay";
	import Popup from "@/components/editor/panel/Popup";
	import Handler from "@/components/editor/panel/Handler";
	
	import CustomIcon from "./CustomIcon";
	
	import vueFrame from "./vueFrame";
	import CookiesMixin from "@/mixins/cookies";
	import ContentManagerMixin from "@/mixins/contentManager";

	import SaveBeforeLeaveModal from "./editor/SaveBeforeLeaveModal";
	import CustomScssModal from "./editor/CustomScssModal";
	import ImportSettingsModal from './editor/ImportSettingsModal'
	import ExpertModeBar from "./editor/ExpertModeBar";
	import PreviewChangesBar from "./editor/PreviewChangesBar";
	import ResolutionBar from "./editor/ResolutionBar";
	import EditThemeNameModal from './editor/EditThemeNameModal'
	
	import Loading from "@/components/Loading";

  import ContentManagerList from "@/components/editor/content-manager/Index";

  export default {
		props: {
			expertmode: Boolean,
			availableDragableWidgets: Array,
			availableContentZones: Array,
			locales: Object
		},
		mixins: [CookiesMixin, ContentManagerMixin],
		components: {
			EditThemeNameModal,
			ImportSettingsModal,
			SaveBeforeLeaveModal,
			CustomScssModal,
			ExpertModeBar,
			PreviewChangesBar,
			vueFrame,
			ResolutionBar,
			draggable,
			CustomIcon,
			DynamicOverlay,
			Overlay,
			Popup,
			Handler,
			Loading,
      ContentManagerList
		},
		computed: {
			shopIFrameURL: function() {
				return this.$store.state.editor.startPage ? this.$store.state.editor.startPage : this.$store.state.editor.shopURL;
			},
			dragableWidgets: function() {
				if (
					this.availableDragableWidgets &&
					this.availableDragableWidgets.length != 0
				) {
					return this.availableDragableWidgets;
				} else {
					return [];
				}
			},
			initContentZones: function() {
				return this.availableContentZones;
			},
			codemirror() {
				return this.$refs.codemirror.codemirror;
			},
			themeConfig() {
				return this.$store.state.editor.selectedTheme.config.basics.fieldsets[0];
			},
			existsContentZones() {
				return this.containsContentZones;
			},
			saveButtonStatus() {
				if (this.$store.state.editor.saveBtnStatus === 3) {
					this.resetButtonStatus();
				}
				return this.$store.state.editor.saveBtnStatus;
			},
			themeIsUpdatable() {
				return this.$store.getters['editor/themeIsUpdatable']
			}
		},
		
		data() {
			return {
				language: "de",
				contentZoneCreationCount: 0,
				editor: {
					preview: false,
					tabIndex: 0,
          contents: {
            tabIndex: 1,
          },
					postToIframe: {
						action: "",
						method: "post",
            value: {}
					},
					size: {
						width: "",
						height: ""
					},
					custom_style: {
						show: false
					},
					made_changes: false,
					changes_status: false,
					overlay: {
						visible: false,
						data: {}
					},
					contentZoneOverlay: {
						visible: false,
						data: []
					},
					contentZoneModal: {
						visible: false,
						data: []
					}
				},
				showThemeChooser: false,
				selectedPage: null,
				containsContentZones: false,
				homeIcon: "",
				homeIconAnimation: "animated wobble three",
				showModal: false,
				modalData: null,
				showImportSettingsModal: false,
				showEditNameModal: false
			};
		},
		
		methods: {
			redirectIFrame(url) {
        if( url.publicLink && url.pageType === 'content' ) {
          this.editor.postToIframe.action = url.publicLink;
          this.editor.postToIframe.value = url;

          setTimeout(() => { this.$refs.postToIframe.submit(); })
        } else {
          const iframe = this.$refs.shopIframe.$el;
          iframe.src = url.publicLink || url;
        }
			},
			modifyDragItem(dataTransfer) {
				dataTransfer.setData("text/html", null);
			},
			saveBtnLabel() {
				let label;
				switch (this.saveButtonStatus) {
					case 2:
						label = this.$t("editor.buttons.saving");
						break;
					case 3:
						label = this.$t("editor.buttons.saved");
						this.$store.commit("editor/changeMadeChangesStatus", false);
						break;
					default:
						label = this.$t("editor.buttons.save");
				}
				return label;
			},
			goTo(position) {
				if (position == "widgetTab") {
					this.closeAllOverlays();
					this.editor.tabIndex = 2;
					this.editor.contents.tabIndex = 1;
				}
			},
			cloneDog(widget) {
				let result = JSON.parse(JSON.stringify(widget));
				let idOption = this.findId(result);
				if (idOption) {
					idOption.value =
						widget.id +
						Math.random()
							.toString(36)
							.substr(2, 9);
					result.type = widget.id;
				}
				return result;
			},
			findId(widget) {
				let result = null;
				widget.fieldsets.forEach(fieldset => {
					fieldset.options.forEach(option => {
						if (option.id === "id") {
							result = option;
						}
					});
				});
				return result;
			},
			log: function(evt) {
				window.console.log(evt);
			},
			load: function() {
                this.$emit("loadAvailableWidgets");
				this.$emit("toggle-iframeLoading", false);
			},
			activeLoading: function() {
				this.$emit("toggle-iframeLoading", true);
			},
			updateContentZones() {
				this.$refs.shopIframe.renderChildren();
			},
			requestContentZones: function(contentZones) {
				this.containsContentZones = !!contentZones.length;
				
				if (contentZones.length > 0) {
					this.$emit("load-content-zones", contentZones);
				}
			},
			onOverlayChange(newObj) {
				//console.log("Change overlay.data & overlay.breadcrumb");
				this.editor.overlay.data = newObj;
				this.editor.overlay.visible = true;
			},
			
			closeAllOverlays() {
				if (this.editor.overlay.visible) {
					this.editor.overlay.visible = false;
					this.editor.overlay.data = {};
					this.$store.commit("editor/reArrangeBreadcrumb", {action: "clear"});
				}
				if (this.editor.contentZoneOverlay.visible) {
					this.editor.contentZoneOverlay.visible = false;
					this.editor.contentZoneOverlay.data = [];
				}
			},
			
			handleContentZoneCreation() {
				this.contentZoneCreationCount++;
				if (this.contentZoneCreationCount >= this.initContentZones.length) {
					this.contentZoneCreationCount = 0;
					this.$refs.shopIframe.renderChildren();
				}
			},
      reloadIframeMenus() {
        this.$refs.shopIframe.iniContentManagerBlocks();
			},
			handleOverlay(data, opened = true) {
				this.editor.overlay.visible = opened;
				this.editor.overlay.data = data;
			},
			handleContentZoneOverlay(data, opened = true) {
				let editLocation = data.length ? (data[0].location || null) : null;
				if (editLocation !== "modal") {
					this.editor.contentZoneOverlay.visible = opened;
					this.editor.contentZoneOverlay.data = data;
				} else {
					this.editor.contentZoneModal.visible = opened;
					this.editor.contentZoneModal.data = data;
				}
				
				this.editor.overlay.visible = false;
				this.editor.overlay.data = {};
				this.$store.commit("editor/reArrangeBreadcrumb", {action: "clear"});
			},
			findThemeJsonBlock(list, id) {
				let result;
				let themeSettings = list;
				let countBlock = themeSettings.length;
				
				for (let i = 0; i < countBlock; i++) {
					let currentBlockId = themeSettings[i]["id"];
					if (currentBlockId == id) {
						result = themeSettings[i];
					} else {
						if (themeSettings[i].categories) {
							this.findThemeJsonBlock(themeSettings[i].categories, id);
						}
					}
				}
				
				if (result) {
					// console.log(result);
					this.addDataToOverlay(result);
				}
			},
			reSendDataToOverlay(forId) {
				this.findThemeJsonBlock(
					this.$store.state.editor.selectedTheme.config.areas.categories,
					forId
				);
			},
			addDataToOverlay(data) {
				this.editor.overlay.data = data;
			},
			togglePreviewChangesOpt() {
				this.editor.preview = !this.editor.preview;
				this.closeAllOverlays();
			},
			toggleExpertModeOpt() {
				this.$emit("toggle-expertmode");
				
				if (this.editor.overlay.visible) {
					//let currentOverlayOptions = this.$store.state.editor.breadcrumb.current;
					// console.log(currentOverlayOptions);
					//this.findThemeJsonBlock(this.editor.themeConfig.config.areas.categories, currentOverlayOptions);
					
					if (!this.editor.overlay.data.basic) {
						this.editor.overlay.visible = false;
						this.editor.overlay.data = {};
						this.$store.commit("editor/reArrangeBreadcrumb", {action: "clear"});
					} else {
						let currentPanel = this.$store.state.editor.breadcrumb.current;
						this.$store.commit("editor/reArrangeBreadcrumb", {action: "clear"});
						this.editor.overlay.data = {};
						let selectedPanel = document.querySelectorAll(
							'[data-menu-item="' + currentPanel + '"]'
						);
						if (selectedPanel.length) {
							for (const panel of selectedPanel) {
								panel.click();
							}
						}
					}
				}
			},
			openOverlayForCategory(selector) {
				this.$store.commit("editor/reArrangeBreadcrumb", {action: "clear"});
				this.editor.overlay.data = {};
				let selectedPanel = document.querySelectorAll(
					'[data-menu-item="' + selector + '"]'
				);
				if (selectedPanel.length) {
					for (const panel of selectedPanel) {
						panel.click();
					}
				}
			},
			save() {
				this.initContentZones.forEach(
					function(item) {
						this.$store.commit("editor/saveThemeOption", {
							[item.id]: item
						});
					}.bind(this)
				);
				
				this.$emit("saveEditorChanges",async () => {
          await this.loadPagesList()
          this.reloadIframe();
        });
			},
			handleEditorResize(e, view, zoom) {
        let editor_container = document.getElementsByClassName("theme-editor-viewer");
				let editor_content = document.getElementById("shop-iframe-editor");
				let editorHeight = editor_content.clientHeight;
				let editorWidth = editor_content.clientWidth;
				this.editor.size.height = editorHeight;
				this.editor.size.width = editorWidth;
				if (view) {
					if (view != "desktop") {
						this.editor.preview = true;
            editor_container[0].classList.remove('overflow-hidden');
					}
					if(zoom) {
            editor_container[0].classList.add('overflow-hidden');
          }
					this.$emit("saveEditorViewPort", view);
				}
			},
			exitEditor() {
        this.editor.made_changes = this.editor.changes_status
        this.$emit('exitEditor')
			},
			toggleModal(showModal, data) {
				this.$emit("toggleModal", showModal, data);
			},
			handleIframe(action) {
				if (action === "compile") {
					this.reloadCssFile();
				} else if (action === "reload") {
					this.reloadIframe();
				}
			},
			reloadPreviewTheme() {
				this.$emit('reloadPreviewTheme');
			},
			redirectToPageNamespace(pageNamespace) {
				let linksList = this.$store.state.editor.pageNamespacesLinks;
				let pageNamespaceLink = linksList[pageNamespace];
				this.redirectIFrame(pageNamespaceLink);
			},
			reloadCssFile() {
				
				const iframeElement = this.$refs.shopIframe.$el;
				if (iframeElement) {
					// Get all the link tags related to the src/dynamic_theme_style.css.php file
					const linkElements = iframeElement.contentWindow.document.head.getElementsByTagName(
						"LINK"
					);
					const cssLinkTags = [].slice.call(linkElements).filter(element => {
						return (
							element.rel === "stylesheet" &&
							element.href.indexOf("dynamic_theme_style") >= 0
						);
					});
					
					if (cssLinkTags.length) {
						
						const mainCss = cssLinkTags[0];
						const timestamp = new Date().getTime();
						const search = new URLSearchParams(mainCss.href);
						
						// Searches for the timestamp query param
						if (search.has("timestamp")) {
							search.set("timestamp", timestamp);
						} else {
							search.append("timestamp", timestamp);
						}
						
						// Creates a new link tag and add an event listener to it
						const newCss = iframeElement.contentWindow.document.createElement(
							"link"
						);
						newCss.type = "text/css";
						newCss.rel = "stylesheet";
						newCss.href = unescape(search.toString());
						this.setThemeIdCookie();
						newCss.addEventListener("load", () => {
							this.removeStyleLoading(cssLinkTags);
						});
						newCss.addEventListener("error", () => {
							this.removeStyleLoading(cssLinkTags);
						});
						this.$emit("toggle-iframeLoading", true);
						iframeElement.contentWindow.document.head.append(newCss);
						return true;
					} else {
						this.reloadIframe();
					}
				}
				
				
			},
			removeStyleLoading(cssLinkTags) {
				this.$emit("toggle-iframeLoading", false);
				cssLinkTags.forEach(tag => tag.remove());
				this.scheduleThemeIdCookieRemoval();
			},
			reloadIframe() {
				this.$emit("toggle-iframeLoading", true);
				
				const iframeWindow = this.$refs.shopIframe.$el;
				iframeWindow.src = iframeWindow.contentDocument.location.href;
			},
			openImportSettingsModal() {
				this.showImportSettingsModal = true;
			},
			openEditThemeNameModal() {
				this.showEditNameModal = true;
			},
			resetButtonStatus() {
				setTimeout(() => this.$store.commit('editor/changeSaveBtnStatus', 1), 2000)
			},
			handlePageNamespaceEvent() {
				this.$emit('loadPageNamespacesList');
			}
		},
		created() {
			window.addEventListener("resize", this.handleEditorResize);
		},
		destroyed() {
			window.removeEventListener("resize", this.handleResize);
		},
		mounted() {
			this.containsContentZones = this.availableContentZones.length <= 0;
			this.handleEditorResize();
			const iframeWindow = this.$refs.shopIframe.$el;
			iframeWindow.addEventListener("load", event => {
				let iframeUrl;
				try {
					iframeUrl = new URL(event.target.contentWindow.location.href);
				} catch (e) {
					this.homeIcon = this.homeIconAnimation;
					this.closeAllOverlays();
				}
				
				if (iframeUrl) {
					let shopUrl = new URL(this.$store.state.editor.shopURL);
					if (iframeUrl.hostname === shopUrl.hostname) {
						this.homeIcon = "";
					} else {
						this.homeIcon = this.homeIconAnimation;
						this.closeAllOverlays();
					}
				}
			});
			// this.containsContentZones = document.getElementsByClassName('shop-iframe')[0].contentWindow.document.body.getElementsByClassName('gx-content-zone').length !== 0;
			//this.editor.overlay.data = themeConfig;
		}
	};
