<template>
  <b-modal
      :no-close-on-backdrop="true"
      :visible="show"
      @hidden="cancelEditing"
      centered
      scrollable
      no-fade
      size="lg"
      modal-class="content-manager-modal"
  >
    <template slot="modal-title">
      <span><strong v-text="title"></strong> {{ $t('editor.contentManager.editModal.title') }}</span>
    </template>
    <template slot="modal-header-close" v-if="!loading">
      <custom-icon icon="close" />
    </template>
    <div class="">
      <language-switcher class="ml-3" />

      <b-tabs vertical class="page-settings-tabs">
        <b-tab :title="$t('editor.contentManager.editModal.tabs.content')">
          <b-form-group
              id="input-group-content-name"
              :label="$t('editor.contentManager.editModal.fields.contentName')"
              label-for="input-content-name"
          >
            <b-form-input
                id="input-content-name"
                v-model="name"
            ></b-form-input>
          </b-form-group>

          <b-form-group
              id="input-group-title"
              :label="$t('editor.contentManager.editModal.fields.contentTitle')"
              label-for="input-title"
          >
            <b-form-input
                id="input-title"
                v-model="title"
                required
            ></b-form-input>
          </b-form-group>

          <b-form-group
              id="input-group-heading"
              :label="$t('editor.contentManager.editModal.fields.contentHeading')"
              label-for="input-heading"
          >
            <b-form-input
                id="input-heading"
                v-model="heading"
                required
            ></b-form-input>
          </b-form-group>

          <b-form-group>
            <b-form-checkbox v-model="status" name="check-button" switch>{{ $t('editor.contentManager.editModal.fields.contentStatus') }}</b-form-checkbox>
          </b-form-group>

          <b-form-group
              class="wysiwyg-editor-container"
          >
            <ckeditor
                :config="editorConfig"
                :editor="editor"
                ref="wysiwygeditor"
                v-model="pageContent"></ckeditor>
          </b-form-group>

          <div v-if="id === '3889891'" class="alert alert-warning floating-icon mb-0">
            <custom-icon icon="shipping-fast" color="#856404" />
            {{ $t('editor.contentManager.createMatrixWarning') }}
          </div>
        </b-tab>
        <b-tab :title="$t('editor.contentManager.editModal.tabs.meta')">
          <b-form-group>
            <b-form-checkbox v-model="gmRobotsEntry" name="check-button" switch>{{ $t('editor.contentManager.editModal.fields.gmRobotsEntry') }}</b-form-checkbox>
          </b-form-group>

          <b-form-group
              id="input-group-meta-title"
              :label="$t('editor.contentManager.editModal.fields.metaTitle')"
              label-for="input-meta-title"
          >
            <b-form-input
                id="input-meta-title"
                v-model="metaTitle"
                required
            ></b-form-input>
          </b-form-group>

          <b-form-group
              id="input-group-meta-keywords"
              :label="$t('editor.contentManager.editModal.fields.metaKeywords')"
              label-for="input-meta-keywords"
          >
            <b-form-textarea
                id="input-meta-keywords"
                v-model="metaKeywords"
                required
            ></b-form-textarea>
          </b-form-group>

          <b-form-group
              id="input-group-meta-description"
              :label="$t('editor.contentManager.editModal.fields.metaDescription')"
              label-for="input-meta-description"
          >
            <b-form-textarea
                id="input-meta-description"
                v-model="metaDescription"
                required
            ></b-form-textarea>
          </b-form-group>
        </b-tab>
        <b-tab :title="$t('editor.contentManager.editModal.tabs.customUrl')">
          <b-form-group
              id="input-group-meta-title"
              :label="$t('editor.contentManager.editModal.fields.urlKeywords')"
              label-for="input-url-keywords"
          >
            <b-form-input
                id="input-url-keywords"
                v-model="urlKeywords"
                required
            ></b-form-input>
          </b-form-group>

          <b-form-group
              id="input-group-url-rewrite"
              :label="$t('editor.contentManager.editModal.fields.urlRewrite')"
              label-for="input-url-rewrite"
          >
            <b-input-group prepend="info/" append=".html">
              <b-form-input
                  id="input-url-rewrite"
                  v-model="urlRewrite"></b-form-input>
            </b-input-group>
          </b-form-group>
        </b-tab>
        <b-tab :title="$t('editor.contentManager.editModal.tabs.sitemap')">
          <b-form-group>
            <b-form-checkbox v-model="gmSitemapEntry" switch>{{ $t('editor.contentManager.editModal.fields.gmSitemapEntry') }}</b-form-checkbox>
          </b-form-group>

          <b-form-group
              id="select-group-sitemap-priority"
              :label="$t('editor.contentManager.editModal.fields.gmPriority')"
              label-for="select-sitemap-priority"
          >
            <b-form-select
                id="select-sitemap-priority"
                v-model="gmPriority"
                :options="gmPriorityOptions">
            </b-form-select>
          </b-form-group>

          <b-form-group
              id="select-group-sitemap-frequency"
              :label="$t('editor.contentManager.editModal.fields.gmChangeFreq')"
              label-for="select-sitemap-frequency"
          >
            <b-form-select
                id="select-sitemap-frequency"
                v-model="gmChangeFreq"
                :options="gmChangeFreqOptions"
            ></b-form-select>
          </b-form-group>
        </b-tab>
        <b-tab v-if="customerStatus" :title="$t('editor.contentManager.editModal.tabs.customerStatus')">
          <div class="alert alert-warning floating-icon mb-0">
            <custom-icon icon="users" color="#856404" />
            <strong v-text="$t('editor.contentManager.customerStatus')"></strong> {{ $t('editor.contentManager.customerStatusWarning') }}
          </div>
        </b-tab>
      </b-tabs>
    </div>
    <div slot="modal-footer">
      <div class="row">
        <div class="col-md-5">
          <b-button
              @click="cancelEditing"
              class="btn-block"
              variant="default"
              v-text="$t('editor.contentManager.editModal.cancel')">
          </b-button>
        </div>
        <div class="col-md-7">
          <b-button
              v-if="!isCreatedPage"
              @click="$emit('save')"
              block
              variant="success"
              v-text="$t('editor.contentManager.editModal.confirm')">
          </b-button>
          <b-button
              v-if="isNewPage && isCreatedPage"
              @click="triggerSave"
              block
              variant="success"
              v-text="$t('editor.contentManager.editModal.confirmCreate')">
          </b-button>
        </div>
      </div>
    </div>
  </b-modal>
</template>

<script>
import CustomIcon from "@/components/CustomIcon";
import LanguageSwitcher from "@/components/editor/panel/LanguageSwitcher";
import ClassicEditor from '@ckeditor/ckeditor5-editor-classic/src/classiceditor';

import EssentialsPlugin from '@ckeditor/ckeditor5-essentials/src/essentials';
import BoldPlugin from '@ckeditor/ckeditor5-basic-styles/src/bold';
import ItalicPlugin from '@ckeditor/ckeditor5-basic-styles/src/italic';
import LinkPlugin from '@ckeditor/ckeditor5-link/src/link';
import ParagraphPlugin from '@ckeditor/ckeditor5-paragraph/src/paragraph';
import HeadingPlugin from '@ckeditor/ckeditor5-heading/src/heading';
import AlignmentPlugin from "@ckeditor/ckeditor5-alignment/src/alignment";
import PasteFromOffice from '@ckeditor/ckeditor5-paste-from-office/src/pastefromoffice';
import Table from '@ckeditor/ckeditor5-table/src/table';
import TableToolbar from '@ckeditor/ckeditor5-table/src/tabletoolbar';

import Font from '@ckeditor/ckeditor5-font/src/font';
import RemoveFormat from '@ckeditor/ckeditor5-remove-format/src/removeformat';
import HorizontalLine from '@ckeditor/ckeditor5-horizontal-line/src/horizontalline';
import Indent from '@ckeditor/ckeditor5-indent/src/indent';
import IndentBlock from '@ckeditor/ckeditor5-indent/src/indentblock';
import ListStyle from '@ckeditor/ckeditor5-list/src/liststyle';

export default {
  components: {
    LanguageSwitcher,
    CustomIcon
  },
  props: {
    id: String,
    value: Object,
    customerStatus: Boolean,
    newPage: Boolean,
    isCreated: Boolean,
    show: Boolean
  },
  data() {
    return {
      pageOriginalContent: JSON.parse(JSON.stringify(this.value)),
      loading: false,
      editor: ClassicEditor,
      editorConfig: {
        // The configuration of the editor.
        language: this.$store.state.editor.currentLanguage,
        toolbar: {
          items: [
            'paragraph',
            'heading',
            '|',
            'bold',
            'italic',
            'underline',
            'strikethrough',
            '|',
            'alignment:left',
            'alignment:center',
            'alignment:right',
            '|',
            'bulletedList',
            'numberedList',
            'outdent',
            'indent',
            'blockQuote',
            '|',
            'removeFormat',
            '-',
            'fontSize',
            'fontFamily',
            'fontColor',
            'fontBackgroundColor',
            '|',
            'link',
            '|',
            'insertTable',
            '|',
            'horizontalLine',
            '|',
            'undo',
            'redo',
          ],
          shouldNotGroupWhenFull: true
        },
        plugins: [
          EssentialsPlugin,
          BoldPlugin,
          Font,
          ListStyle,
          RemoveFormat,
          HorizontalLine,
          ItalicPlugin,
          LinkPlugin,
          ParagraphPlugin,
          HeadingPlugin,
          Indent,
          IndentBlock,
          AlignmentPlugin,
          PasteFromOffice,
          Table, TableToolbar
        ],
        table: {
          contentToolbar: [ 'tableColumn', 'tableRow', 'mergeTableCells' ]
        }
      },
      gmPriorityOptions: [
        { value: '0.0', text: '0.0' },
        { value: '0.1', text: '0.1' },
        { value: '0.2', text: '0.2' },
        { value: '0.3', text: '0.3' },
        { value: '0.4', text: '0.4' },
        { value: '0.5', text: '0.5' },
        { value: '0.6', text: '0.6' },
        { value: '0.7', text: '0.7' },
        { value: '0.8', text: '0.8' },
        { value: '0.9', text: '0.9' },
        { value: '1.0', text: '1.0' }
      ],
      gmChangeFreqOptions: [
        { value: 'always', text: 'always' },
        { value: 'hourly', text: 'hourly' },
        { value: 'daily', text: 'daily' },
        { value: 'weekly', text: 'weekly' },
        { value: 'monthly', text: 'monthly' },
        { value: 'yearly', text: 'yearly' },
        { value: 'never', text: 'never' }
      ]
    };
  },
  computed: {
    currentLanguage: function() {
        return this.$store.state.editor.currentLanguage;
    },
    isNewPage: function() {
      return this.newPage;
    },
    isCreatedPage: function() {
      return this.isCreated;
    },
    pageData: {
      get() {
        return this.value
      },
      set(newValue) {
        this.value = newValue;
      }
    },
    name: {
      get() {
        return this.value[this.currentLanguage].contentName
      },
      set(newValue) {
        this.value[this.currentLanguage].contentName = newValue;
      }
    },
    title: {
      get() {
        return this.value[this.currentLanguage].contentTitle
      },
      set(newValue) {
        this.value[this.currentLanguage].contentTitle = newValue;
      }
    },
    heading: {
      get() {
        return this.value[this.currentLanguage].contentHeading
      },
      set(newValue) {
        this.value[this.currentLanguage].contentHeading = newValue;
      }
    },
    status: {
      get() {
        return this.value[this.currentLanguage].contentStatus
      },
      set(newValue) {
        this.value[this.currentLanguage].contentStatus = newValue;
      }
    },
    pageContent: {
      get() {
        return this.value[this.currentLanguage].contentText
      },
      set(newValue) {
        this.value[this.currentLanguage].contentText = newValue;
      }
    },
    metaTitle: {
      get() {
        return this.value[this.currentLanguage].contentsMetaTitle
      },
      set(newValue) {
        this.value[this.currentLanguage].contentsMetaTitle = newValue;
      }
    },
    metaKeywords: {
      get() {
        return this.value[this.currentLanguage].contentsMetaKeywords
      },
      set(newValue) {
        this.value[this.currentLanguage].contentsMetaKeywords = newValue;
      }
    },
    metaDescription: {
      get() {
        return this.value[this.currentLanguage].contentsMetaDescription
      },
      set(newValue) {
        this.value[this.currentLanguage].contentsMetaDescription = newValue;
      }
    },
    urlKeywords: {
      get() {
        return this.value[this.currentLanguage].gmUrlKeywords
      },
      set(newValue) {
        this.value[this.currentLanguage].gmUrlKeywords = newValue;
      }
    },
    urlRewrite: {
      get() {
        return this.value[this.currentLanguage].urlRewrite
      },
      set(newValue) {
        this.value[this.currentLanguage].urlRewrite = newValue;
      }
    },
    gmSitemapEntry: {
      get() {
        return this.value[this.currentLanguage].gmSitemapEntry
      },
      set(newValue) {
        this.value[this.currentLanguage].gmSitemapEntry = newValue;
      }
    },
    gmPriority: {
      get() {
        return this.value[this.currentLanguage].gmPriority
      },
      set(newValue) {
        this.value[this.currentLanguage].gmPriority = newValue;
      }
    },
    gmChangeFreq: {
      get() {
        return this.value[this.currentLanguage].gmChangeFreq
      },
      set(newValue) {
        this.value[this.currentLanguage].gmChangeFreq = newValue;
      }
    },
    gmRobotsEntry: {
      get() {
        return this.value[this.currentLanguage].gmRobotsEntry
      },
      set(newValue) {
        this.value[this.currentLanguage].gmRobotsEntry = newValue;
      }
    }
  },
  methods: {
    triggerSave: function () {
      this.$emit('triggerSave', this.value);
    },
    cancelEditing: function () {
      this.$emit('cancel', this.pageOriginalContent);
    }
  },
  mounted() {
    if(!this.isNewPage) {
      setTimeout(() => this.$refs.wysiwygeditor.$forceUpdate(), 10);
    }
  }
};
</script>

