<template>
  <div>
    <checkbox
      :id="id + '-enabled'"
      v-model="enabled"
      :label="locales.insertGradient"
      :title="'id: ' + id + '-enabled'"
    />
    <template v-if="enabled.value">
      <colorpicker
        :id="id + '-color1'"
        v-model="color1"
        :label="locales.firstColor"
        :title="'id: ' + id + '-color1'"
      />
      <colorpicker
        :id="id + '-color2'"
        v-model="color2"
        :label="locales.secondColor"
        :title="'id: ' + id + '-color2'"
      />
      <selectbox
        :id="id + '-type'"
        v-model="gradientType"
        :label="locales.type"
        :title="'id: ' + id + '-type'"
      />
      <selectbox :id="id + '-angle'" :title="'id: ' + id + '-angle'" v-model="angle" :label="locales.angle" />
    </template>
  </div>
</template>

<script>
import colorpicker from "./colorpicker";
import selectbox from "./selectbox";
import checkbox from "./checkbox";

export default {
  props: {
    id: String,
    label: String,
    value: Object
  },
  components: {
    colorpicker,
    checkbox,
    selectbox
  },
  data() {
    return {
      locales: this.$t("editor").options.backgroundGradient
    };
  },
  computed: {
    enabled: {
      get() {
        return { value: this.value.items.enabled };
      },
      set(newValue) {
        this.value.items.enabled = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    },
    color1: {
      get() {
        return { value: this.value.items.color1 };
      },
      set(newValue) {
        this.value.items.color1 = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    },
    color2: {
      get() {
        return { value: this.value.items.color2 };
      },
      set(newValue) {
        this.value.items.color2 = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    },
    gradientType: {
      get() {
        let gradientType = this.value.items.gradientType;
        if(!gradientType) {
          gradientType = "linear";
        }
        return {
          value: gradientType,
          options: ["linear", "radial"]
        };
      },
      set(newValue) {
        this.value.items.gradientType = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    },
    angle: {
      get() {
        let angle = this.value.items.angle;
        if(!angle) {
          angle = "0deg";
        }
        return {
          value: angle,
          options: ["0deg", "45deg", "90deg", "135deg", "180deg"]
        };
      },
      set(newValue) {
        this.value.items.angle = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    }
  }
};
</script>

