<template>
    <div class="option-container option-toprightbottomleft">
        <div class="row">
            <div class="col-12">
                <label class="label">{{ label }}</label>
                <div class="row no-gutters">
                    <div class="col-8">
                        <div class="row no-gutters">
                            <div class="col-3">
                                <label class="label under-label d-none">{{ topUnit }}</label>
                                <measure-unit :id="id + '-top'" v-model="value.items.top" input-class="first-input"
                                              v-bind:default-unit="currentUnitValue"
                                              v-on:change="triggerSave"></measure-unit>
                                <label :for="id + '-top'" class="label under-label"> Top</label>
                            </div>

                            <div class="col-3">
                                <label class="label under-label d-none">{{ rightUnit }}</label>
                                <measure-unit :id="id + '-right'" v-model="value.items.right" input-class="middle-input"
                                              v-bind:default-unit="currentUnitValue"
                                              v-on:change="triggerSave"></measure-unit>
                                <label :for="id + '-right'" class="label under-label">Right</label>
                            </div>
                            <div class="col-3">
                                <label class="label under-label d-none">{{ bottomUnit }}</label>
                                <measure-unit :id="id + '-bottom'" v-model="value.items.bottom" input-class="middle-input"
                                              v-bind:default-unit="currentUnitValue"
                                              v-on:change="triggerSave"></measure-unit>
                                <label :for="id + '-bottom'" class="label under-label">Bottom</label>
                            </div>
                            <div class="col-3">
                                <label class="label under-label d-none">{{ leftUnit }}</label>
                                <measure-unit :id="id + '-left'" v-model="value.items.left" input-class="last-input"
                                              v-bind:default-unit="currentUnitValue"
                                              v-on:change="triggerSave"></measure-unit>
                                <label :for="id + '-left'" class="label under-label">Left</label>
                            </div>
                        </div>
                    </div>
                    <div class="col-4">
                        <unit-selector v-model="currentUnitValue"/>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>

<script>
    import unitSelector from "./unitSelector";
    import measureUnit from "./measureUnit";

    export default {
        props: {
            id: String,
            label: String,
            value: Object
        },
        components: {
            unitSelector,
            measureUnit
        },
        computed: {
            currentUnitValue: {
                get() {
                    if (this.topUnit == this.bottomUnit && this.topUnit == this.leftUnit && this.topUnit == this.rightUnit) {
                        return this.topUnit;
                    } else {
                        return '';
                    }
                },
                set(newValue) {
                    this.topUnit = newValue;
                    this.bottomUnit = newValue;
                    this.leftUnit = newValue;
                    this.rightUnit = newValue;
                    this.triggerSave();
                }
            },
            topUnit: {
                get() {
                    return this.extractUnit(this.value.items.top);

                },
                set(newUnit) {
                    this.value.items.top = this.updateUnit(this.value.items.top, newUnit)
                }
            },
            bottomUnit: {
                get() {
                    return this.extractUnit(this.value.items.bottom);

                },
                set(newUnit) {
                    this.value.items.bottom = this.updateUnit(this.value.items.bottom, newUnit)

                }
            },
            leftUnit: {
                get() {
                    return this.extractUnit(this.value.items.left);

                },
                set(newUnit) {
                    this.value.items.left = this.updateUnit(this.value.items.left, newUnit)
                }
            },
            rightUnit: {
                get() {
                    return this.extractUnit(this.value.items.right);

                },
                set(newUnit) {
                    this.value.items.right = this.updateUnit(this.value.items.right, newUnit)
                }
            }

        },

        methods: {
            extractUnit(value) {
                let result = value.replace(/^[.-\d\s]+/gm, '').trim();
                return result
            },
            updateUnit(value, newUnit) {
                let numericValue = (isNaN(parseInt(value))) ? 0 : parseInt(value);
                let result = numericValue + newUnit;
                return result
            },
            triggerSave() {
                this.$emit("input", this.value);
                this.$emit("triggerSave", this.value.items);
            },
        }

    };
</script>

