<template>
  <div
    class="menu-item"
    v-if="(data.basic && isVisible) || ($store.state.editor.expertMode && ((data.for !== undefined && isVisible)||(data.for == undefined)))"

  >
    <a @click="openCategory()" class="link" :data-menu-item="data.id">
      {{ title }}
      <custom-icon icon="Expand" />
    </a>
  </div>
</template>

<script>
import CustomIcon from "@/components/CustomIcon";
export default {
  components: {
    CustomIcon
  },
  props: {
    title: String,
    data: Object,
    usedFor: String,
    partialSelector: String,
    parentPageNamespace: String
  },
  data() {
    return {
      isVisible: true
    };
  },
  methods: {
    openCategory() {
      let id = this.data.id;
      let title = this.data.title;

      this.$store.commit("editor/generateBreadcrumb", { [id]: title });
      this.$emit("triggerOpenOverlay");
    },

    findThemeJsonBlock(themeSettings, id) {
      for (let i = 0; i < themeSettings.length; i++) {
        const firstCategory = themeSettings[i].categories !== undefined &&
                themeSettings[i].categories.length &&
                themeSettings[i].categories[0];

        if (firstCategory &&
            firstCategory.fieldsets.length &&
            firstCategory.fieldsets[0].options.length &&
            firstCategory.fieldsets[0].options[0].type === 'variant' &&
            firstCategory.fieldsets[0].options[0].id === id
        ) {
          return firstCategory.fieldsets[0].options[0].value.id;
        }
      }

      return null;
    },

    showCategoryForVariant() {
      if (this.data.for) {
        let [variantID, variantSelected]  = this.data.for.split("/");
        if(variantID in this.$store.state.editor.themeConfig) {
          if(this.$store.state.editor.themeConfig[variantID].value.id != variantSelected) {
            this.isVisible = false;
          }
        } else {
          let currentSelectedVariant = this.findThemeJsonBlock(
                  this.$store.state.editor.selectedTheme.config.areas.categories,
                  variantID
          );
          if (currentSelectedVariant != variantSelected) {
            this.isVisible = false;
          }
        }
      }
    }
  },
  mounted() {
    this.showCategoryForVariant();
  },
  computed: {
    calculatedParentPageNamespace() {
      return this.data.pageNamespace || this.parentPageNamespace || ''
    }
  }
};
</script>

