<template>
  <div id="resolution-bar-container" class="editor-responsive-resolution">
    <ul class="responsive-buttons">
      <li
        class="responsive-option"
        :class="{
          'active-preview': $store.state.editor.editorView == 'desktop'
        }"
      >
        <b-button
          @click="changeView($event, 'desktop')"
          class="responsive-button"
          variant="link"
          title="Desktop"
          size="sm"
        >
          <custom-icon icon="desktop" />
        </b-button>
      </li>
      <li
        class="responsive-option"
        :class="{
          'active-preview': $store.state.editor.editorView == 'tablet-landscape'
        }"
      >
        <b-button
          @click="changeView($event, 'tablet-landscape')"
          class="responsive-button"
          variant="link"
          title="Tablet Landscape"
          size="sm"
        >
          <custom-icon icon="landscape" />
        </b-button>
      </li>
      <li
        class="responsive-option"
        :class="{
          'active-preview': $store.state.editor.editorView == 'tablet-portrait'
        }"
      >
        <b-button
          @click="changeView($event, 'tablet-portrait')"
          class="responsive-button"
          variant="link"
          title="Tablet Portrait"
          size="sm"
        >
          <custom-icon icon="portrait" />
        </b-button>
      </li>
      <li
        class="responsive-option"
        :class="{
          'active-preview': $store.state.editor.editorView == 'smartphone'
        }"
      >
        <b-button
          @click="changeView($event, 'smartphone')"
          class="responsive-button"
          variant="link"
          title="Smartphone"
          size="sm"
        >
          <custom-icon icon="smartphone" />
        </b-button>
      </li>
    </ul>
    <div class="editor-size">
      <span>{{ size.width }}</span>
      <span class="x">x</span>
      <span>{{ size.height }}</span>
      <strong>px</strong>
    </div>
    <div class="editor-zoom">
      <b-form-select v-model="zoom" :options="zoomOptions" :disabled="!isDesktop" @change="changeZoom" size="sm" class="zoom-dropdown"></b-form-select>
    </div>
  </div>
</template>

<script>
import CustomIcon from "../CustomIcon";
export default {
  name: "ResolutionBar",
  components: {
    CustomIcon
  },
  props: {
    size: Object,
    preview: Boolean
  },
  data() {
    return {
      zoom: '100',
      zoomOptions: [
        { value: '25', text: '25%' },
        { value: '33', text: '33%' },
        { value: '50', text: '50%' },
        { value: '67', text: '67%' },
        { value: '75', text: '75%' },
        { value: '80', text: '80%' },
        { value: '90', text: '90%' },
        { value: '100', text: '100%' },
      ],
      zoomClasses: [
        'zoom-to-25',
        'zoom-to-33',
        'zoom-to-50',
        'zoom-to-67',
        'zoom-to-75',
        'zoom-to-80',
        'zoom-to-90',
        'zoom-to-100'
      ]
    }
  },
  computed: {
    isDesktop: function () {
      this.setZoomToDefault();
      return this.$store.state.editor.editorView === 'desktop';
    }
  },
  methods: {
    changeView: function(e, view) {
      let editor = document.getElementById("editor");
      let editorFrame = document.getElementById("shop-iframe-editor");

      // Add preview mode class to editor
      editor.classList.add("preview-mode-on");
      // Add current mode class
      editor.classList.remove(
        "desktop",
        "tablet-portrait",
        "tablet-landscape",
        "smartphone"
      );
      editor.classList.add(view);

      this.removeZoomClasses(editorFrame);
      if(view === 'desktop') this.setZoomToDefault();

      // ReInit Resolution size
      this.$emit("triggerWindowResize", e, view);
    },
    changeZoom: function (percentage) {
      let zoomClass = `zoom-to-${percentage}`;
      let editor = document.getElementById("shop-iframe-editor");

      // Toggle zoom classes
      this.removeZoomClasses(editor);
      editor.classList.add(zoomClass);

      // Recalculate iFrame resolution
      this.$emit("triggerWindowResize", null, this.$store.state.editor.editorView, percentage);
    },
    removeZoomClasses: function (editor) {
      for (let i = 0; i <= this.zoomClasses.length; i++) {
        editor.classList.remove(this.zoomClasses[i]);
      }
    },
    setZoomToDefault: function () {
      this.zoom = '100';
    }
  }
};
</script>

