<template>
  <div>
    <b-dropdown
      @click="active ? $emit('edit') : $emit('activate')"
      size="sm"
      split
      right
      :text="active ? locales.edit : locales.activate"
      variant="primary"
    >
      <b-dropdown-item @click="$emit('edit')" v-if="!active">{{ locales.edit }}</b-dropdown-item>
      <b-dropdown-item @click="$emit('duplicate')">{{
        locales.duplicate
      }}</b-dropdown-item>
      <b-dropdown-item @click="triggerDownload()">{{
        locales.download
      }}</b-dropdown-item>
      <b-dropdown-item v-if="removable" @click="$emit('delete')">{{
        locales.delete
      }}</b-dropdown-item>
    </b-dropdown>

    <download-modal
            :show="showDownloadConfirmation"
            :locales="locales.downloadModal"
            @confirm="emitDownload(true)"
            @cancel="emitDownload(false)"
    />
  </div>
</template>

<script>
import DownloadModal from "./DownloadModal";

export default {
  components: { DownloadModal },
  props: {
    active: Boolean,
    removable: Boolean,
    editing: String,
    themeId: String,
    locales: Object
  },
  data() {
    return {
      showDownloadConfirmation: false
    }
  },
  methods: {
    triggerDownload() {
      if(this.editing === this.themeId && this.$store.state.editor.madeChangesStatus) {
        this.showDownloadConfirmation = true;
      } else {
        this.emitDownload(true);
      }
    },
    emitDownload(status) {
      if(status == true) {
        this.$emit('download');
      }
      this.showDownloadConfirmation = false;
    }
  }
};
</script>
