<template>
  <div>
    <draggable
      :list="col.widgets"
      group="widgets"
      handle=".move-widget"
      v-bind="getDraggableOptions()"
      @start="isDragging = true"
      @end="isDragging = false"
      class="gx-content-zone-col-draggable"
      :setData="modifyDragItem"
      @add="handleAdd"
    >
      <div
        v-for="(widget, widgetIndex) in col.widgets"
        class="widget widget-container"
        :key="widgetIndex"
      >
        <div class="widget-actions">
          <a href="javascript:;" @click="editWidget(widget)" class="action edit"
            ><custom-icon icon="pencil"
          /></a>
          <a
            href="javascript:;"
            @click="duplicateWidget(col, widget, widgetIndex)"
            class="action duplicate"
            ><custom-icon icon="copy"
          /></a>

          <a href="javascript:;" class="action move move-widget"
            ><custom-icon icon="sort"
          /></a>
          <a
            href="javascript:;"
            @click="deleteWidget(col, widgetIndex)"
            class="action delete"
            ><custom-icon icon="cross"
          /></a>
          <span class="content-zone-element-type">{{ widget.title }}</span>
        </div>
        <transition-group type="transition" name="flip-list">
          <contentZoneWidget :widget="widget" :key="widget.id" />
        </transition-group>
      </div>
    </draggable>
    <div class="place-widget-here" @click="gotToWidget">
      <custom-icon icon="add" color="#ccc" custom-class="icon-default" />
      <custom-icon icon="add" color="#00abff" custom-class="icon-on-hover" />
    </div>
  </div>
</template>

<script>
import draggable from "vuedraggable";
import CustomIcon from "@/components/CustomIcon";
import contentZoneWidget from "@/components/editor/widgets/contentZoneWidget";

export default {
  name: "contentZoneCol",
  props: {
    col: Object
  },
  components: {
    CustomIcon,
    draggable,
    contentZoneWidget
  },
  data() {
    return {
      isDragging: false
    };
  },
  methods: {
    modifyDragItem(dataTransfer) {
      dataTransfer.setData("text/html", null);
    },
    gotToWidget() {
      this.$emit("goTo", "widgetTab");
    },
    editWidget(widget) {
      let data = {
        title: widget.title,
        key: widget.id,
        location: widget.displayConfig,
        fieldsets: widget.fieldsets,
        translatable: true,
        showBreadcrumb: false
      };
      this.$emit("handleOverlay", [data]);
    },
    duplicateWidget(column, widget, widgetIndex) {
      let copyWidget = JSON.parse(JSON.stringify(widget));

      copyWidget.fieldsets.forEach(function(fieldset) {
        fieldset.options.forEach(function(option) {
          if (option.id === 'text') {
            if (option.hasOwnProperty('contentGroup')) {
              option.contentGroup = null
            }
            if (option.hasOwnProperty('contentAlias')) {
              option.contentAlias = null
            }
          }

          if (option.id === "id") {
            option.value +=
              "-" +
              Math.random()
                .toString(36)
                .substr(2, 5);
          }
        });
      });
      this.$emit("closeOverlay");
      column.widgets.splice(widgetIndex++, 0, copyWidget);
    },
    deleteWidget(column, widgetIndex) {
      column.widgets.splice(widgetIndex, 1);
      this.handleOverlay({}, false);
    },
    handleOverlay(data, opened = true) {
      this.$emit("handleOverlay", [data], opened);
    },
    getDraggableOptions() {
      return {
        animation: 150
      };
    },
    handleAdd(evt) {
      this.editWidget(this.col.widgets[evt.newIndex]);
    }
  }
};
</script>

<style scoped>
.flip-list-move {
  transition: transform 0.5s;
}
.no-move {
  transition: transform 0s;
}
.ghost {
  opacity: 0.5;
  background: #c8ebfb;
}
</style>
