<template>
  <div class="option-container option-textbox">
    <div class="row">
      <div class="col-5">
        <label class="label">{{ label }}</label>
      </div>
      <div class="col-7">
        <input
          type="text"
          :id="id"
          class="form-control"
          :value="currentValue"
          v-on:change="currentValue = $event.target.value"
        />
      </div>
    </div>
  </div>
</template>

<script>
export default {
  props: {
    id: String,
    label: String,
    language: String,
    value: Object
  },
  computed: {
    currentValue: {
      get(){
        let value = this.id in this.$store.state.editor.themeConfig
                ? this.$store.state.editor.themeConfig[this.id].value
                : this.value.value;

        if(Boolean(this.language) && this.value.translatable){
          return value[this.language];
        } else {
          return value;
        }

      },
      set(newValue) {

        if(Boolean(this.language) && this.value.translatable){
          this.value.value[this.language] = newValue;
          this.value.value = JSON.parse(JSON.stringify(this.value.value)) ;
        } else {

          this.value.value = newValue;
        }

        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.value);
      }
    }
  },
  methods: {
    triggerSave() {
    },
    // Apply the defined attributes
    // on the JSON file to the input
    addInputAttributes() {
      if (!this.value.attributes) {
        return;
      }

      let input = document.getElementById(this.id);
      // Define a list of the attributes that can not be added
      // ex. id, we do not want the user to use a different
      // because it may break our option configuration
      let restrictedAttributes = ["id"];

      // Apply the attributes to the input
      for (let [name, value] of Object.entries(this.value.attributes)) {
        // Check if the attribute is defined as restricted
        if (!restrictedAttributes.includes(name)) {
          input.setAttribute(name, value);
        }
      }
    }
  },
  mounted() {
    this.addInputAttributes();
  }
};
</script>

<style scoped lang="scss"></style>
