<template>
  <div class="option-container option-background">
    <div class="row">
      <div class="col-12">
  
        <checkbox
            v-if="enableCustomization.value !== undefined"
            :id="id + '-enable-customization'"
            v-model="enableCustomization"
            :label="locales.enableCustomization"
        />
        
        <div v-if="enableCustomization.value === undefined || enableCustomization.value === true">
          <label class="label">{{ label }}</label>
          <colorpicker
            :id="id + '-color'"
            v-model="color"
            :label="locales.textColor"
          />
          <selectbox
            :id="id + '-text-align'"
            v-model="textAlign"
            :label="locales.textAlign"
          />
          <fontfamily
            :id="id + '-family'"
            v-model="family"
            :label="locales.fontFamily"
          />
          <numberbox
            :id="id + '-size'"
            v-model="size"
            :label="locales.fontSize"
          />
          <selectbox
            :id="id + '-style'"
            v-model="style"
            :label="locales.fontStyle"
          />
          
          <checkbox
            :id="id + '-text-decoration-underline'"
            v-model="textDecorationUnderline"
            :label="locales.textDecorationUnderline"
          />
          <checkbox
            :id="id + '-text-transform-uppercase'"
            v-model="textTransformUppercase"
            :label="locales.textTransformUppercase"
          />
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import colorpicker from "./colorpicker";
import checkbox from "./checkbox";
import selectbox from "./selectbox";
import fontfamily from "./fontfamily";
import numberbox from "./numberbox";

export default {
  props: {
    id: String,
    label: String,
    value: Object
  },
  computed: {
    enableCustomization: {
      get() {
        return {
          value: this.value.items.enableCustomization
        };
      },
      set(newValue) {
        this.value.items.enableCustomization = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    },
    color: {
      get() {
        return {
          value: this.value.items.color
        };
      },
      set(newValue) {
        this.value.items.color = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    },
    textAlign: {
      get() {
        return {
          value: this.value.items.textAlign,
          options: [
            { value: "left", text: "Left" },
            { value: "center", text: "Center" },
            { value: "right", text: "Right" },
            { value: "justify", text: "Justify" },
            { value: "initial", text: "Initial" },
            { value: "inherit", text: "Inherit" }
          ]
        };
      },
      set(newValue) {
        this.value.items.textAlign = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    },
    family: {
      get() {
        return {
          value: this.value.items.family
        };
      },
      set(newValue) {
        this.value.items.family = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    },
    size: {
      get() {
        return {
          value: this.value.items.size
        };
      },
      set(newValue) {
        this.value.items.size = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    },
    style: {
      get() {
        return {
          value: this.value.items.style,
          options: ["normal", "italic", "oblique", "initial", "inherit"]
        };
      },
      set(newValue) {
        this.value.items.style = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    },
    textDecorationUnderline: {
      get() {
        return {
          value: this.value.items.textDecorationUnderline
        };
      },
      set(newValue) {
        this.value.items.textDecorationUnderline = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    },
    textTransformUppercase: {
      get() {
        return {
          value: this.value.items.textTransformUppercase
        };
      },
      set(newValue) {
        this.value.items.textTransformUppercase = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    }
  },
  components: {
    colorpicker,
    checkbox,
    selectbox,
    fontfamily,
    numberbox
  },
  data() {
    return {
      locales: this.$t("editor").options.font
    };
  }
};
</script>

<style scoped lang="scss">
.option-container {
  margin-bottom: 5px;

  .sub-option-container {
    margin-bottom: 5px;
  }
}
</style>
