<template>
  <textbox :id="id"
           :label="label"
           v-model="computedValue"
  />
</template>

<script>
import textbox from '@/components/editor/panel/options/textbox'
export default {
  props: {
    id: String,
    label: String,
    value: Object
  },
  components: {
    textbox
  },
  computed:{
    computedValue:{
      get(){
        return this.value;
      },
      set(newValue){
        this.$emit('input', newValue);
      }
    }
  }

}
</script>

