<template>
  <div class="option-container option-dropdown-select">
    <div class="row">
      <div class="col-5">
        <label class="label">{{ label }}</label>
      </div>
      <div class="col-7">
        <b-dropdown split class="input-container" split-variant="outline">
          <template slot="button-content">
            <input
              type="text"
              class="form-control"
              v-model="optionValue"
              @change="triggerSave"
            />
          </template>
          <b-dropdown-item
            v-for="optionItem in value.items"
            :key="optionItem"
            :active="optionValue === optionItem"
            @click="setSelectedValue(optionItem)"
            >{{ optionItem }}</b-dropdown-item
          >
        </b-dropdown>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  props: {
    id: String,
    label: String,
    value: Object
  },
  computed:{
    optionValue: {
      get(){
        let result =  this.id in this.$store.state.editor.themeConfig
                ? this.$store.state.editor.themeConfig[this.id].value
                : this.value.value;
        return result;
      },
      set(newValue){
        this.value.value = newValue;
      }
    }
  },

  methods: {
    triggerSave() {
      // Emit the save action
      this.$emit("input", this.value);
      this.$emit("triggerSave", this.value.value);
    },
    setSelectedValue(newValue) {
      this.optionValue = newValue;
      this.triggerSave();
    }
  }
};
</script>

<style scoped lang="scss">
.input-container {
  .form-control {
    position: relative;
    z-index: 1;
    margin: -7px -12px;
    width: calc(100% + 25px);
    border-radius: $border-radius 0 0 $border-radius;
  }
  &::v-deep .dropdown-toggle-split {
    border-left: 0;
  }
}
</style>
