<template>
  <div class="option-container option-variant">
    <div
      class="variant"
      v-for="variant in value.options"
      :class="{ 'active-variant': variant.id === currentValue.id }"
      @click="currentValue = variant"
      :key="variant.id"
    >
      <span class="type">{{ variant.title }}</span>
      <img :src="variant.thumbnail" alt="" />
    </div>
  </div>
</template>

<script>
export default {
  props: {
    id: String,
    value: Object
  },

  computed: {
    currentValue: {
      get(){

          return this.id in this.$store.state.editor.themeConfig
                  ? this.$store.state.editor.themeConfig[this.id].value
                  : this.value.value;
      },
      set(newVariant) {
          this.$emit("triggerSave", newVariant);
          this.value.value = newVariant;

      }
    }
  }

};
</script>

<style scoped lang="scss">
.variant {
  position: relative;
  margin-bottom: 15px;
  border: 4px solid transparent;
  cursor: pointer;
  &:last-child {
    margin-bottom: 0;
  }
  .type {
    display: none;
    position: absolute;
    top: 0;
    left: 0;
    padding-right: 4px;
    padding-bottom: 4px;
    font-size: 12px;
    background: $primary;
  }
  &.active-variant {
    border-color: $primary;
    .type {
      display: block;
    }
  }
}
</style>
