<template>
	<div class="widget-content" v-html="widgetContent.html"></div>
</template>

<script>
	import axios from "axios";
	
	import {FETCH_WIDGET} from "@/enums/endpoints";
	
	const requestConfig = {
		headers: {
			"Content-Type": "application/x-www-form-urlencoded; charset=UTF-8"
		}
	};
	export default {
		name: "contentZoneWidget",
		props: {
			widget: Object
		},
		computed: {
			language() {
				return this.$store.state.editor.currentLanguage;
			}
		},
		data() {
			return {
				widgetContent: {
					html: "",
					styleNode: {}
				},
				timedOutHtmlLoad: 0
			};
		},
		mounted() {
			let style = this.$el.ownerDocument.createElement('style');
			style.type = "text/css";
			style.appendChild(this.$el.ownerDocument.createTextNode(''));
			this.styleNode = style.childNodes[0] // a reference I store in the data hash
			this.$el.ownerDocument.head.appendChild(style);
			this.sendTimedOutInputEvent();
		},
		methods: {
			async loadWidgetHTML() {
				
				const themeID = this.$store.state.editor.selectedTheme.id;
				let newHtml = '';
				let newStyleContent = '';
				
				try {
					const {data} = await axios.post(
						FETCH_WIDGET(themeID, this.widget.type, this.language || ''), this.widget,
						requestConfig
					);
					newHtml = data.html.replace(/<style[\w\W]+?<\/style>/gm, "");
					let newStyleArray = [...data.html.matchAll(/<style\b[^>]*>([\w\W]+?)<\/style>/g)];
					
					newStyleArray.forEach((match) => {
						newStyleContent += match[1];
					})

					newHtml = newHtml.replace(/gambio-style/g, "style");
					
				} catch (error) {
					if(error.response !== undefined
						&& error.response.data !== undefined
						&& error.response.data.message !== undefined){
						newHtml = error.response.data.message;
					} else {
						newHtml = error;
					}
					newStyleContent = '';
				}
				
				
				this.styleNode.textContent = newStyleContent;
				this.widgetContent.html = newHtml;
			},
			sendTimedOutInputEvent() {
				clearTimeout(this.timedOutHtmlLoad);
				this.timedOutHtmlLoad = setTimeout(() => this.loadWidgetHTML(), 1000)
			}
		},
		watch: {
			widget: {
				handler() {
					
					this.sendTimedOutInputEvent();
				},
				deep: true
			},
			language() {
				this.sendTimedOutInputEvent();
			}
		}
	};
</script>

<style scoped></style>
