<template>
  <div>
    <div class="fieldsets-block" v-if="data.fieldsets">
      <Fieldset
        :data="fieldset"
        :locales="locales"
        :usedFor="data.for"
        :fieldsetCounter="data.fieldsets.length"
        :parentPageNamespace="calculatedParentPageNamespace"
        @handleIframe="handleIframe"
        @reloadPreviewTheme="reloadPreviewTheme"
        @toggleModal="toggleModal"
        @closeOverlay="closeOverlay"
        @redirectToPageNamespace="redirectToPageNamespace"
        v-for="(fieldset, fieldsetIndex) in fieldsetsList"
        :key="fieldsetIndex"
      />
    </div>
    <div class="menu-wrapper" v-else-if="data.categories">
      <Category
        :data="category"
        :partialSelector="data.selector"
        :title="category.title"
        :key="category.id"
        :parentPageNamespace="calculatedParentPageNamespace"
        @triggerOpenOverlay="emitOverlayWithData(category)"
        v-for="category in categoriesList"
      />
    </div>
  </div>
</template>

<script>
import Fieldset from "@/components/editor/panel/Fieldset";
import Category from "@/components/editor/panel/Category";

export default {
  name: "Handler",
  props: {
    data: Object,
    locales: Object,
    parentPageNamespace: String
  },
  components: {
    Fieldset,
    Category
  },
  data() {
    return {
      localParentPageNamespace: ''
    }
  },
  methods: {
    handleIframe(action) {
      this.$emit("handleIframe", action);
    },
    reloadPreviewTheme() {
      this.$emit("reloadPreviewTheme");
    },
    emitOverlayWithData(overlayData) {
      /*console.log(overlayData);
        console.log(this.$store.state.editor.expertMode);*/
      overlayData.parentPageNamespace = this.calculatedParentPageNamespace

      if (!this.$store.state.editor.expertMode) {
        overlayData.categories[0].pageNamespace = overlayData.pageNamespace
        overlayData.categories[0].parentPageNamespace = overlayData.parentPageNamespace
        this.$emit("handleOverlay", overlayData.categories[0]);
      } else {
        this.$emit("handleOverlay", overlayData);
      }
    },
    toggleModal(opened, data) {
      this.$emit("toggleModal", opened, data);
    },
    closeOverlay() {
      this.$emit("closeOverlay");
    },
    redirectToPageNamespace(pageNamespace) {
      this.$emit('redirectToPageNamespace', pageNamespace);
    }
  },
  computed: {
    fieldsetsList() {
      return this.data.fieldsets.filter(element => !element.hidden);
    },
    categoriesList() {
      return this.data.categories.filter(element => !element.hidden);
    },
    calculatedParentPageNamespace() {
      return this.data.pageNamespace || this.parentPageNamespace || ''
    }
  }
};
</script>

<style lang="scss" scoped>
.menu-wrapper {
  border-bottom: 1px solid $navy-medium;
}
</style>
