<template>
	<div
		:class="[
      rowClass,
      {
        'row-hidden-on-current-breakpoint':
          (rowHiddenLg && initRowVisibility == 'desktop') ||
          (rowHiddenMd && initRowVisibility == 'tablet-landscape') ||
          (rowHiddenSm && initRowVisibility == 'tablet-portrait') ||
          (rowHiddenXs && initRowVisibility == 'smartphone')
      }
    ]"
		:id="rowID"
		class="row"
	>
		<!--<pre>{{ row }}</pre>-->
		<div
			class="visible-lg row-visibility-status"
			v-if="row.responsive.items.hiddenLg"
		>
			<i class="fa fa-eye"></i> Hidden on <strong>Large</strong> devices
		</div>
		<div
			class="visible-md row-visibility-status"
			v-if="row.responsive.items.hiddenMd"
		>
			<i class="fa fa-eye"></i> Hidden on <strong>Medium</strong> devices
		</div>
		<div
			class="visible-sm row-visibility-status"
			v-if="row.responsive.items.hiddenSm"
		>
			<i class="fa fa-eye"></i> Hidden on <strong>Small</strong> devices
		</div>
		<div
			class="visible-xs row-visibility-status"
			v-if="row.responsive.items.hiddenXs"
		>
			<i class="fa fa-eye"></i> Hidden on <strong>Extra small</strong> devices
		</div>
		<div
			:class="getColClassByLayoutName(row.columnsLayout.value, colIndex)"
			v-bind:style="columnStyle(col)"
			:key="colIndex"
			v-for="(col, colIndex) in row.cols"
		>
			<div
				:class="[
          {
            'row-hidden-on-current-breakpoint':
              (col.responsive.items.hiddenLg &&
                initRowVisibility == 'desktop') ||
              (col.responsive.items.hiddenMd &&
                initRowVisibility == 'tablet-landscape') ||
              (col.responsive.items.hiddenSm &&
                initRowVisibility == 'tablet-portrait') ||
              (col.responsive.items.hiddenXs &&
                initRowVisibility == 'smartphone')
          },
          { 'no-widgets-here': !col.widgets.length }
        ]"
				class="gx-content-zone-col"
			>
				<div
					class="visible-lg row-visibility-status"
					i
					v-if="col.responsive.items.hiddenLg"
				>
					<i class="fa fa-eye"></i> Hidden on <strong>Large</strong> devices
				</div>
				<div
					class="visible-md row-visibility-status"
					v-if="col.responsive.items.hiddenMd"
				>
					<i class="fa fa-eye"></i> Hidden on <strong>Medium</strong> devices
				</div>
				<div
					class="visible-sm row-visibility-status"
					v-if="col.responsive.items.hiddenSm"
				>
					<i class="fa fa-eye"></i> Hidden on <strong>Small</strong> devices
				</div>
				<div
					class="visible-xs row-visibility-status"
					v-if="col.responsive.items.hiddenXs"
				>
					<i class="fa fa-eye"></i> Hidden on
					<strong>Extra small</strong> devices
				</div>
				<div class="col-actions">
					<span class="content-zone-element-type">{{ title() }}</span>
					<a @click="editColumn(col)" class="action edit" href="javascript:;">
						<custom-icon icon="pencil"/>
					</a>
					<a
						@click="handleDeleteColumn(row, colIndex)"
						class="action delete"
						href="javascript:;"
					>
						<custom-icon icon="cross"/>
					</a>
				</div>
				<contentZoneCol
					:col="col"
					@goTo="goTo"
					@closeOverlay="closeOverlay"
					@handleOverlay="(data, opened) => handleOverlay(col, data, opened)"
				/>
			</div>
		</div>
	</div>
</template>

<script>
	import CustomIcon from "@/components/CustomIcon";
	import contentZoneCol from "@/components/editor/widgets/contentZoneCol";
	import contentzoneFactory from "@/mixins/contentzoneFactory";
	
	export default {
		name: "contentZoneRow",
		props: {
			row: Object,
			locales: Object
		},
		components: {
			CustomIcon,
			contentZoneCol
		},
		mixins: [contentzoneFactory],
		data() {
			return {
				editorViewPort: this.$store.state.editor.editorView,
				rowID: this.row.id.value,
				rowClass: this.row.class.value,
				rowHiddenXs: this.row.responsive.items.hiddenXs,
				rowHiddenSm: this.row.responsive.items.hiddenSm,
				rowHiddenMd: this.row.responsive.items.hiddenMd,
				rowHiddenLg: this.row.responsive.items.hiddenLg,
				
				showDeleteModal: false,
				showChangedGridModal: false,
				currentRowToDelete: null,
				columnIndexToDelete: null,
				oldGridValue: null,
				newGridValue: null
			};
		},
		methods: {
			title() {
				return this.$t("editor.contentZone.column.title");
			},
			closeOverlay() {
				this.$emit("closeOverlay");
			},
			goTo(goToData) {
				this.$emit("goTo", goToData);
			},
			columnStyle(col) {
				let result = {
					borderTopWidth: col.border.items.top,
					borderRightWidth: col.border.items.right,
					borderBottomWidth: col.border.items.bottom,
					borderLeftWidth: col.border.items.left,
					borderStyle: col.border.items.style,
					borderColor: col.border.items.color,
					background: ''
				};

				const parameters = new URLSearchParams(location.search);
				let shopUrl = parameters.get("url") || false;
				if(shopUrl.substr(shopUrl.length-1,1) !== '/'){
					shopUrl += '/';
				}
				let imageUrl = col.background.items.image.url;
				if(shopUrl){
					imageUrl = col.background.items.image.url.replace(shopUrl, '');
				}
				
				if (!col.background.items.image.enabled && !col.background.items.gradient.enabled) {
					result.background = col.background.items.color;
				}

				if (col.background.items.image.enabled == true) {
					if (col.background.items.gradient.enabled === false) {
						result.background += col.background.items.color + ' ';
					}
					
					result.background += 'url("'+ imageUrl +'") '+ col.background.items.image.position +' / '+ col.background.items.image.size +' '+ col.background.items.image.repeat +' '+ col.background.items.image.attachment;
				}

				if (col.background.items.gradient.enabled == true) {
					let backgroundStyleGradient = '';
					if (col.background.items.gradient.gradientType == "linear") {
						backgroundStyleGradient = "linear-gradient("+ col.background.items.gradient.angle +", "+ col.background.items.gradient.color1 +", "+ col.background.items.gradient.color2 +")";
					} else {
						backgroundStyleGradient = "radial-gradient("+ col.background.items.gradient.color1 +", "+ col.background.items.gradient.color2 +")";
					}

					if (col.background.items.image.enabled == true) {
						result.background += ', ';
					}
					result.background += backgroundStyleGradient;
				}
				
				return result;
			},
			createDataObject(column) {
				column.type = "contentZoneColumn";
				return {
					title: this.$t("editor.contentZone.column.title"),
					fieldsets: [
						{
							title: this.$t("editor.contentZone.column.fieldsets.responsive"),
							options: [column.responsive]
						},
						{
							title: this.$t("editor.contentZone.column.fieldsets.background"),
							options: [column.background]
						},
						{
							title: this.$t("editor.contentZone.column.fieldsets.border"),
							options: [column.border]
						},
						{
							title: this.$t("editor.contentZone.column.fieldsets.general"),
							options: [column.id, column.class]
						}
					]
				};
			},
			editColumn(column) {
				this.$emit("handleOverlay", [this.createDataObject(column)], true);
			},
			deleteColumn(row, colindex) {
				row.cols.splice(colindex, 1);
				switch (row.cols.length) {
					case 1:
						this.row.columnsLayout.value = "fullwidth";
						break;
					case 2:
						this.row.columnsLayout.value = "fifty-fifty";
						break;
					case 3:
						this.row.columnsLayout.value = "three-thirty-three";
						break;
				}
				
				this.$emit("columnDeleted", row);
			},
			handleDeleteColumn(row, colindex) {
				const widgetsCount = row.cols[colindex].widgets.length;
				
				if (widgetsCount) {
					const data = {
						params: {
							row,
							col: colindex
						},
						successCallback: response => {
							this.deleteColumn(response.row, response.col);
						},
						cancelCallback: this.toggleChangedGridModal,
						locales: this.locales.deleteModal
					};
					this.$emit("toggleModal", true, data);
					return false;
				}
				
				this.deleteColumn(row, colindex);
			},
			onChangedGridModalConfirm() {
				this.changeColumnsLayout(this.newGridValue, null);
				this.resetChangeGridVariables();
			},
			onChangedGridModalCancel() {
				if (this.oldGridValue) {
					this.currentRowToDelete.columnsLayout.value = this.oldGridValue;
				}
			},
			handleOverlay(column, data, opened = true) {
				data.push(this.createDataObject(column));
				this.$emit("handleOverlay", data, opened);
			},
			columnHasWidget(col) {
				return col.widgets.length > 0;
			},
			changeColumnsLayout(val, oldVal) {
				let columnsToAdd;
				let currentColumns = this.row.cols;
				switch (val) {
					case "fifty-fifty":
					case "thirty-three-sixty-six":
					case "sixty-six-thirty-three":
					case "twenty-five-seventy-five":
					case "seventy-five-twenty-five":
						columnsToAdd = 2;
						break;
					case "three-thirty-three":
						columnsToAdd = 3;
						break;
					case "four-twenty-five":
						columnsToAdd = 4;
						break;
					default:
						columnsToAdd = 1;
						break;
				}
				
				// Check if we need to add new or remove old columns
				if (currentColumns.length !== columnsToAdd) {
					// We need to remove if we have more columns than we need
					if (currentColumns.length > columnsToAdd) {
						let cols = currentColumns.length - columnsToAdd;
						
						if (oldVal) {
							// Get in the remaining cols if we have some widget inside of it
							let remainingCols = this.row.cols.slice(cols * -1);
							let firstWidgetFound = remainingCols.find(element =>
								this.columnHasWidget(element)
							);
							
							if (firstWidgetFound !== undefined) {
								this.currentRowToDelete = this.row;
								this.oldGridValue = oldVal;
								this.newGridValue = val;
								
								const data = {
									params: {},
									successCallback: this.onChangedGridModalConfirm,
									cancelCallback: this.onChangedGridModalCancel,
									locales: this.locales.deleteModal
								};
								
								this.$emit("toggleModal", true, data);
								
								return false;
							}
						}
						
						this.row.cols.splice(columnsToAdd, cols);
					} else {
						let cols = columnsToAdd - currentColumns.length;
						for (let i = 1; i <= cols; i++) {
							this.row.cols.push(this.buildColumn());
						}
					}
				}
			},
			getColumnsLayoutByName(layout) {
				switch (layout) {
					case "fifty-fifty":
						return ["col-md-6", "col-md-6"];
					case "thirty-three-sixty-six":
						return ["col-md-4", "col-md-8"];
					case "sixty-six-thirty-three":
						return ["col-md-8", "col-md-4"];
					case "twenty-five-seventy-five":
						return ["col-md-3", "col-md-9"];
					case "seventy-five-twenty-five":
						return ["col-md-9", "col-md-3"];
					case "three-thirty-three":
						return ["col-md-4", "col-md-4", "col-md-4", "col-md-4"];
					case "four-twenty-five":
						return ["col-md-3", "col-md-3", "col-md-3", "col-md-3"];
					case "fullwidth":
					default:
						return ["col-md-12"];
				}
			},
			resetChangeGridVariables() {
				this.oldGridValue = null;
				this.newGridValue = null;
			},
			createColumn() {
				return {widgets: []};
			},
			getColClassByLayoutName(layout, colIndex) {
				const columnsLayout = this.getColumnsLayoutByName(layout);
				const colGridClass = columnsLayout[colIndex] || columnsLayout[0];
				const colCustomClass = [this.row.cols[colIndex].class.value];

				const uniqueClasses = [colGridClass, ...colCustomClass].reduce((previousValue, currentValue) => {
					if (previousValue.indexOf(currentValue) < 0) {
						previousValue.push(currentValue)
					}

					return previousValue;
				}, []);
				return uniqueClasses.join(' ');
			}
		},
		computed: {
			initRowVisibility() {
				return this.$store.state.editor.editorView;
			},
			columnsLayout() {
				return this.row.columnsLayout.value;
			},
			rowResponsive() {
				return this.row.responsive.items;
			},
			watchRowClass() {
				return this.row.class.value;
			},
			watchRowID() {
				return this.row.id.value;
			}
		},
		watch: {
			watchRowID: {
				handler: function(val) {
					this.rowID = val;
				},
				immediate: true
			},
			watchRowClass: {
				handler: function(val) {
					this.rowClass = val;
				},
				immediate: true
			},
			columnsLayout: {
				handler: function(val, oldVal) {
					this.changeColumnsLayout(val, oldVal);
				},
				immediate: true
			},
			rowResponsive: {
				handler: function(val) {
					if (val.hiddenXs == true) {
						this.rowHiddenXs = "hidden-xs";
					} else {
						this.rowHiddenXs = "";
					}
					if (val.hiddenSm == true) {
						this.rowHiddenSm = "hidden-sm";
					} else {
						this.rowHiddenSm = "";
					}
					if (val.hiddenMd == true) {
						this.rowHiddenMd = "hidden-md";
					} else {
						this.rowHiddenMd = "";
					}
					if (val.hiddenLg == true) {
						this.rowHiddenLg = "hidden-lg";
					} else {
						this.rowHiddenLg = "";
					}
				},
				immediate: true,
				deep: true
			}
		}
	};
</script>

<style lang="scss" scoped></style>
