<template>
  <div class="category-wrapper">
    <div class="head">
      <h3 class="title">
        {{ title }}
      </h3>
      <b-button
        @click.stop="newPage"
        variant="success"
        class="add-item-btn"
        v-b-popover.hover.bottomleft="$t('editor.contentManager.actions.newPage')"
      >
        <custom-icon icon="add" class="add-icon" />
      </b-button>
    </div>
    <div class="content">
      <template v-if="!categoryItems.length">
        <div class="no-items" v-text="$t('editor.contentManager.noMenuItemsAvailable')"></div>
      </template>
      <ul class="menu-wrapper">
        <draggable
          v-model="categoryItems"
          @start="dragging = true"
          @stop="dragging = false"
          group="sortablePages"
          handle=".move-page"
        >
          <category-item
            v-for="(item, index) in categoryItems"
            :key="index"
            :page.sync="item"
            @goTo="(link) => goTo(link)"
            @deletePage="deletePage"
            @savePage="(changesWereMade) => savePage(changesWereMade)"
            class="menu-item"
          />
        </draggable>
      </ul>
    </div>
    <edit
      v-if="isCreating"
      :show="isCreating"
      :value="isCreatingPage.content"
      :newPage="isCreatingPage.isNewPage"
      :isCreated="isCreated"
      @cancel="cancelCreate"
      @triggerSave="createPage"
    />
  </div>
</template>

<script>
import CategoryItem from "@/components/editor/content-manager/CategoryItem";
import Edit from "@/components/editor/content-manager/forms/Edit";

import CustomIcon from "@/components/CustomIcon";
import ContentManager from "@/mixins/contentManager";
import draggable from "vuedraggable";

export default {
  components: {
    Edit,
    CategoryItem,
    CustomIcon,
    draggable,
  },
  mixins: [ContentManager],
  props: {
    value: Object,
  },
  data() {
    return {
      isCreating: false,
      isCreated: false,
      isCreatingPage: {},
    };
  },
  computed: {
    title: function () {
      return this.value.title;
    },
    categoryItems: {
      get() {
        return this.value.items;
      },
      set(newValue) {
        this.$emit("sortOrderChanged");
        this.value.items = newValue;
        this.savePage();
      },
    },
  },
  methods: {
    goTo: function (link) {
      this.$emit("goTo", link);
    },
    savePage: function (changesWereMade) {
      this.$emit("updatePagesList", !!changesWereMade);
    },
    createPage: function (page) {
      this.isCreatingPage.content = page;
      this.categoryItems.push(this.isCreatingPage);
      this.$emit("updatePagesList", true);

      this.isCreating = false;
      this.isCreated = false;
      this.isCreatingPage = {};
    },
    cancelCreate: function () {
      this.isCreating = false;
      this.isCreated = false;
      this.isCreatingPage = {};
    },
    deletePage: function (page) {
      const pageIndex = this.categoryItems.indexOf(page);
      this.categoryItems[pageIndex]["isDeleted"] = true;
      this.$emit("updatePagesList", true);
    },
    cancelEdit: function (data) {
      this.isCreating = false;
      this.pageContent = data;
      this.$emit("savePage");
    },
    newPage: function () {
      this.isCreating = true;
      this.isCreated = true;
      this.isCreatingPage = this.newPageStructure(this.value.id);
    },
  },
};
</script>

