<template>
  <div class="gx-content-zone">
    <div class="gx-content-zone-actions">
      <a @click="addSection(contentZone.rows)" class="add-section" href="javascript:;">
        <custom-icon icon="add" />
      </a>
    </div>
    <draggable
      :list="contentZone.rows"
      :setData="modifyDragItem"
      @end="isDragging = false"
      @start="isDragging = true"
      group="rows"
      handle=".move-row"
      v-bind="getDraggableOptions()"
    >
      <transition-group name="flip-list" type="transition">
        <div
          :content-zone-id="contentZone.id"
          :key="rowIndex"
          class="gx-content-zone-row row"
          v-for="(row, rowIndex) in contentZone.rows"
        >
          <div :id="row.id.value" :class="row.class.value" v-bind:style="rowStyle(row)">
            <div :class="[{ container: row.contentAlign.value }, { 'container-fluid': !row.contentAlign.value }]">
              <div class="gx-content-zone-row-actions">
                <span class="content-zone-element-type">{{ $t("editor.contentZone.row.title") }}</span>
                <a @click="editRow(row)" class="action edit" href="javascript:;">
                  <custom-icon icon="pencil" />
                </a>
                <a class="action move move-row" href="javascript:;">
                  <custom-icon icon="sort" />
                </a>
                <a @click="handleDeleteRow(rowIndex)" class="action delete" href="javascript:;">
                  <custom-icon icon="cross" />
                </a>
              </div>
              <contentZoneRow
                :locales="locales"
                :row="row"
                @closeOverlay="closeOverlay"
                @columnDeleted="columnDeleted"
                @goTo="goTo"
                @handleOverlay="(data, opened) => handleOverlay(row, data, opened)"
                @toggleModal="toggleModal"
              />
            </div>
          </div>
        </div>
      </transition-group>
    </draggable>
  </div>
</template>

<script>
import draggable from "vuedraggable";
import CustomIcon from "@/components/CustomIcon";
import contentZoneRow from "@/components/editor/widgets/contentZoneRow";
import contentzoneFactory from "@/mixins/contentzoneFactory";

export default {
  name: "contentZone",
  props: {
    contentZone: Object,
    locales: Object,
  },
  created() {
    this.$emit("mounted");
  },
  mixins: [contentzoneFactory],
  components: {
    draggable,
    CustomIcon,
    contentZoneRow,
  },
  data() {
    return {
      isDragging: false,
      showDeleteModal: false,
      deleteRowIndex: null,
    };
  },
  methods: {
    title() {
      return this.$t("editor.contentZone.row.title");
    },
    closeOverlay() {
      this.$emit("closeOverlay");
    },
    modifyDragItem(dataTransfer) {
      dataTransfer.setData("text/html", null);
    },
    goTo(goToData) {
      this.$emit("goTo", goToData);
    },
    rowStyle(row) {
      let result = {
        borderTopWidth: row.border.items.top,
        borderRightWidth: row.border.items.right,
        borderBottomWidth: row.border.items.bottom,
        borderLeftWidth: row.border.items.left,
        borderStyle: row.border.items.style,
        borderColor: row.border.items.color,
        background: "",
      };

      const parameters = new URLSearchParams(location.search);
      let shopUrl = parameters.get("url") || false;
      if (shopUrl.substr(shopUrl.length - 1, 1) !== "/") {
        shopUrl += "/";
      }
      let imageUrl = row.background.items.image.url;
      if (shopUrl) {
        imageUrl = row.background.items.image.url.replace(shopUrl, "");
      }

      if (!row.background.items.image.enabled && !row.background.items.gradient.enabled) {
        result.background = row.background.items.color;
      }

      if (row.background.items.image.enabled === true) {
        if (row.background.items.gradient.enabled === false) {
          result.background += row.background.items.color + " ";
        }

        result.background +=
          'url("' +
          imageUrl +
          '") ' +
          row.background.items.image.position +
          " / " +
          row.background.items.image.size +
          " " +
          row.background.items.image.repeat +
          " " +
          row.background.items.image.attachment;
      }

      if (row.background.items.gradient.enabled === true) {
        let backgroundStyleGradient = "";
        if (row.background.items.gradient.gradientType === "linear") {
          backgroundStyleGradient =
            "linear-gradient(" +
            row.background.items.gradient.angle +
            ", " +
            row.background.items.gradient.color1 +
            ", " +
            row.background.items.gradient.color2 +
            ")";
        } else {
          backgroundStyleGradient =
            "radial-gradient(" +
            row.background.items.gradient.color1 +
            ", " +
            row.background.items.gradient.color2 +
            ")";
        }

        if (row.background.items.image.enabled === true) {
          result.background += ", ";
        }
        result.background += backgroundStyleGradient;
      }

      return result;
    },
    columnDeleted: function (row) {
      if (row.cols.length == 0) {
        let index = this.contentZone.rows.indexOf(row);
        this.contentZone.rows.splice(index, 1);
      }
      this.$emit("handleOverlay", [], false);
    },
    addSection(list) {
      this.$emit("handleOverlay", [], false);
      list.push(this.buildRow());
    },
    createDataObject(row) {
      row.type = "contentZoneRow";
      return {
        key: Math.random(),
        title: this.$t("editor.contentZone.row.title"),
        fieldsets: [
          {
            title: this.$t("editor.contentZone.row.fieldsets.grid"),
            options: [row.columnsLayout],
          },
          {
            title: this.$t("editor.contentZone.row.fieldsets.alignment"),
            options: [row.contentAlign],
          },
          {
            title: this.$t("editor.contentZone.row.fieldsets.responsive"),
            options: [row.responsive],
          },
          {
            title: this.$t("editor.contentZone.row.fieldsets.background"),
            options: [row.background],
          },
          {
            title: this.$t("editor.contentZone.row.fieldsets.border"),
            options: [row.border],
          },
          {
            title: this.$t("editor.contentZone.row.fieldsets.general"),
            options: [row.id, row.class],
          },
        ],
      };
    },
    setFromProperty(fieldsets) {
      fieldsets.forEach((widget) => {
        if (widget.fieldsets !== undefined) {
          widget.fieldsets.forEach((fieldset) => {
            fieldset.options.forEach((option) => {
              option.from = "widget";
            });
          });
        } else if (widget.categories !== undefined) {
          this.setFromProperty(widget.categories);
        }
      });
      return fieldsets;
    },
    editRow(row) {
      this.$emit("handleOverlay", this.setFromProperty([this.createDataObject(row)]), true);
    },
    handleDeleteRow(rowIndex) {
      let widgetsCount = this.contentZone.rows[rowIndex].cols.reduce(
        (initialValue, col) => (col.widgets.length ? initialValue + 1 : initialValue),
        0
      );

      if (widgetsCount) {
        const data = {
          params: { row: rowIndex },
          successCallback: (response) => {
            this.deleteRow(response.row);
          },
          locales: this.locales.deleteModal,
        };

        this.$emit("toggleModal", true, data);
        return false;
      }

      this.deleteRow(rowIndex);
    },
    deleteRow(rowIndex) {
      this.contentZone.rows.splice(rowIndex, 1);
      this.$emit("handleOverlay", [], false);
    },
    toggleModal(showModal, data) {
      this.$emit("toggleModal", showModal, data);
    },
    handleOverlay(row, data, opened = true) {
      data.push(this.createDataObject(row));
      this.$emit("handleOverlay", this.setFromProperty(data), opened);
    },
    getDraggableOptions() {
      return {
        animation: 300,
      };
    },
  },
};
</script>

<style scoped>
.flip-list-move {
  transition: transform 0.5s;
}

.no-move {
  transition: transform 0s;
}

.ghost {
  opacity: 0.5;
  background: #c8ebfb;
}
</style>
