<template>
  <b-modal
    v-model="made_changes"
    id="confirmStyleChanges"
    ref="modal"
    title="Save changes"
    size="lg"
    no-fade
    @ok="saveChanges"
  >
    <p style="margin: 0;">
      Do you want to save your changes before moving to another page?
    </p>
    <p style="margin: 0;">
      <small>Be aware you will loose all the changes you did!</small>
    </p>
    <div slot="modal-footer" class="container">
      <div class="row">
        <div class="col-6">
          <b-button
            size="md"
            class="btn-block"
            variant="link"
            @click="dontSaveChanges"
            >Continue without saving changes</b-button
          >
        </div>
        <div class="col-6">
          <b-button
            size="md"
            class="btn-block"
            variant="primary"
            @click="saveChanges"
            >Save</b-button
          >
        </div>
      </div>
    </div>
  </b-modal>
</template>

<script>
export default {
  name: "SaveBeforeLeaveModal",
  props: {
    made_changes: Boolean
  },
  methods: {
    dontSaveChanges() {
      this.editor.changes_status = false;
      this.editor.made_changes = false;
      alert("going to front-end page");
    },
    saveChanges() {
      alert("Saving Changes...");
      alert("going to front-end page");
      this.editor.changes_status = false;
      this.editor.made_changes = false;
    }
  }
};
</script>
