<template>
  <div>
    <label>{{ label }}</label>
    <searchbox
      :id="id"
      :label="label"
      v-model="computedValue"
      v-on:triggerSave="$emit('triggerSave', $event)"
    />
  </div>
</template>

<script>
  import searchbox from './searchbox';

  export default {
    name: "CategorySearchBox",
    components: {searchbox},
    props: {
      id: String,
      label: String,
      value: Object
    },
    computed: {
      computedValue: {
        get() {
          return this.value;
        },
        set(newValue) {
          this.$emit('input', newValue);
        }
      }
    }
  };
</script>

