<template>
    <sortable-options v-model="boxItems" :key="seq"/>
</template>

<script>
  import SortableOptions from './sortable-options'

  export default {
    name: 'ordainedlist',
    components: { SortableOptions },
    props: {
      id: String,
      label: String,
      value: Object
    },
    data() {
         return {
             seq: 0
         }
    }   ,
    computed: {
      boxItems: {
        get() {
            return this.value.value;
        },
        set(newValue) {
          this.value.value = this.sortBoxItemOrder(newValue);
          this.triggerInput();
        }
      }
    },
    methods: {
      async triggerInput(){
        this.$emit('input', this.value);
        this.$emit('triggerSave', this.value.value);
        /*
        * The "this.seq++" is to turnaround a problem with VueJs and Draggable when
        * calling the instance.$destroy() inside vueFrame.js
        **/
        this.seq++;
      },
      sortBoxItemOrder(newValue) {
        newValue.map((element, index) => element.value.position = index);
        return newValue;
      }
    }
  }
</script>

