<template>
	<div id="app" v-if="$store.state.authentication.token  && showEditor">
		<theme-editor v-if="$store.state.editor.selectedTheme"
					:availableContentZones="contentZones"
					:availableDragableWidgets="dragableWidgets"
					:expertmode="$store.state.editor.expertMode"
					:locales="this.$t('editor')"
					@load-content-zones="loadContentZones"
					@loadPageNamespacesList="loadPageNamespaces"
					@loadAvailableWidgets="getDragableWidget"
					@saveEditorChanges="triggerSaveChanges"
					@saveEditorViewPort="saveCurrentEditorView"
					@show-chooser="toggleChooser(true)"
					@toggle-expertmode="toggleExpertMode"
					@toggle-iframeLoading="toggleIframeLoading"
					@toggleModal="toggleModal"
					@reloadPreviewTheme="handleReloadPreviewTheme"
          @exitEditor="handleExitEditor"
					ref="editor"
		/>
		<theme-chooser
			:locales="this.$t('chooser')"
			:show="chooserVisible"
			:theme-upload-status="$store.state.chooser.themeUploadStatus"
			:themes="$store.state.chooser.themes"
			@activate="id => activateTheme(id)"
			@delete="id => deleteTheme(id)"
			@download="id => downloadTheme(id)"
			@duplicate="theme => handleThemeChooserDuplicate(theme)"
			@edit="id => loadTheme(id)"
			@hide="toggleChooser(false)"
			@reset-placeholder="resetThemePlaceholder()"
			@upload="formData => uploadTheme(formData)"
			@overwriteTheme="status => requestToOverwriteTheme(status)"
			@toggleModal="toggleModal"
			style="min-height: 100vh;"
		/>
		
		<modal-component
			:locales="getModalLocales()"
			:show="showModal"
			:title="'Modal Title'"
			:confirmButtonVariant="modalConfirmBtnColor()"
			:show-cancel-button="showCancelButton()"
			:hide-close-button="hideCloseButton()"
			@cancel="toggleModal(false)"
			@confirm="onModalConfirm"
		/>
	
	</div>
</template>

<script>
	import ThemeEditor from "./components/Editor";
	import ThemeChooser from "./components/Chooser";
	import ModalComponent from "./components/editor/Modal";
	
	import ThemeChooserMixin from "./mixins/chooser";
	import ThemeEditorMixin from "./mixins/editor";
	import CookiesMixin from "./mixins/cookies";
	import ModalMixin from "./mixins/modal";
	import contentzoneFactory from "./mixins/contentzoneFactory";
	
	export default {
		components: {ThemeEditor, ThemeChooser, ModalComponent},
		mixins: [
			ThemeChooserMixin,
			ThemeEditorMixin,
			CookiesMixin,
			contentzoneFactory,
			ModalMixin
		],
		data() {
			return {
				dragableWidgets: [],
				contentZones: [],
				showEditor: true,
        deletePreviewTheme: true
			}
		},
		computed: {
			chooserVisible() {
				let result = this.$store.state.chooser.show || (this.$store.state.editor.themeConfig === false);
				return result;
			},
			changesMade() {
				return this.$store.state.editor.madeChangesStatus;
			}
		},
		watch: {
			changesMade() {
				this.showDataWarning();
			}
		},
		methods: {
			removeCookie() {
				const iFrames = document.querySelectorAll('iframe');
				for (let i = 0; i < iFrames.length; i++) {
					iFrames[i].parentNode.removeChild(iFrames[i]);
				}
				this.showEditor = false;
				this.removeThemeIdCookie();
				setTimeout(() => this.showEditor = true, 1000);
			},
			
			onBeforeUnload(e) {
				e.preventDefault();
				e.returnValue = ""
			},
			onUnload() {
        if (this.deletePreviewTheme) {
          this.deleteTheme(this.$store.state.editor.selectedTheme.id);
        }
			},
			async getDragableWidget() {
				this.dragableWidgets = await this.loadAvailableWidgets();
			},
			showDataWarning() {
				if (this.$store.state.editor.madeChangesStatus) {
					window.addEventListener('beforeunload', this.onBeforeUnload);
				} else {
					window.removeEventListener('beforeunload', this.onBeforeUnload)
				}
			},
			async loadContentZones(contentZonesID) {
				if (!contentZonesID.length) {
					return null;
				}

				// check if some of the contentZonesID already exists in the this.contentZones (content zones list)
				// we do an reverse loop just to don't lost the contentZonesID's index when run the splice()
				for (let i = (this.contentZones.length - 1); i >= 0; i--) {
					const elementIndex = contentZonesID.indexOf(this.contentZones[i].id);
					if (elementIndex > -1) {
						contentZonesID.splice(elementIndex, 1);
					}
				}
				
				if (contentZonesID.length) {
					let contentZoneResult = await this.requestContentZones(contentZonesID.join(','));
					
					//add all the results to the current contentZoneList
					contentZoneResult.forEach(itemResult => {
						if (!this.idExistsInContentZoneList(itemResult.id)) {
							this.contentZones.push(itemResult);
						}
					});
				}
				
				//create the new contentZones result
				contentZonesID.forEach(id => {
					const alreadyExistsInContentZones = this.idExistsInContentZoneList(id);
					
					if (!alreadyExistsInContentZones) {
						this.contentZones.push(this.buildContentZone(id))
					}
				});
				
				this.$refs.editor.updateContentZones();
			},
			idExistsInContentZoneList(id) {
				return this.contentZones.find(element => element.id === id);
			},
			triggerLanguageSaveToStore(lang) {
				this.triggerSaveCurrentLanguage(lang);
			},
			handleSaveThemeFinished(responseStatus) {
				if (responseStatus === 200) {
					this.contentZones = [];
				}
			},
			handleReloadPreviewTheme() {
				this.reloadPreviewTheme();
			},
			handleThemeChooserDuplicate(theme) {
				this.duplicateTheme({ theme, language: this.$i18n.locale })
			},
      handleExitEditor() {
        this.deletePreviewTheme = false

        const parameters = new URLSearchParams(location.search);
        const shopUrl = parameters.get("url") || false;

        if (shopUrl) {
          window.location.href = shopUrl
        }
      }
		},
		created() {
			const parameters = new URLSearchParams(location.search);
			this.$i18n.locale = parameters.get("language") || this.$i18n.locale;
			
			this.fetchThemes().then(() => {
				if (parameters.get("editing")) {
					this.loadTheme(parameters.get("editing"));
				}
			});
			
			
			window.addEventListener('unload', this.onUnload);
			window.addEventListener('beforeunload', this.removeCookie);
			
			this.triggerLanguageSaveToStore(this.$i18n.locale);
			this.$on('toggleModal', this.toggleModal)
			this.$on('saveThemeFinished', this.handleSaveThemeFinished)
		}
	};
</script>

<style lang="scss">
	#app {
		position: relative;
		-webkit-font-smoothing: antialiased;
		-moz-osx-font-smoothing: grayscale;
	}
</style>
