import axios from "axios";

import { INITIAL } from "../enums/themeUploadStatus";

import {
  FETCH_THEMES,
  ACTIVATE_THEME,
  DELETE_THEME,
  DUPLICATE_THEME,
  UPLOAD_THEME,
  OVERWRITE_THEME,
  DOWNLOAD_THEME
} from "../enums/endpoints";

const requestConfig = {
  headers: {
    "Content-Type": "application/x-www-form-urlencoded; charset=UTF-8"
  }
};

export default {
  namespaced: true,
  state: {
    show: false,
    themeUploadStatus: INITIAL,
    overwriteTheme: {
      exists: false,
      name: '',
      version: '',
      path: ''
    },
    themes: []
  },
  mutations: {
    toggle(state, show) {
      state.show = show;
    },
    setThemes(state, themes) {
      state.themes = themes;
    },
    setThemeUploadStatus(state, status) {
      state.themeUploadStatus = status;
    },
    setOverwriteThemeData(state, theme) {
      const {exists = true} = theme;
      state.overwriteTheme.exists = exists;
      state.overwriteTheme.name = theme.name;
      state.overwriteTheme.path = theme.path;
      state.overwriteTheme.version = theme.version;
    },
    changeOverwriteThemeData(state, status) {
      if(status == true) {
        state.overwriteTheme.exists = false;
        state.overwriteTheme.name = '';
        state.overwriteTheme.path = '';
        state.overwriteTheme.version = '';
      }
    },
    changeThemeNameAndAuthor(state, themeInformation) {
      if (state.themes.length) {
        state.themes.forEach(theme => {
          if (theme.id === themeInformation.id) {
            theme.author = themeInformation.author
            theme.title = themeInformation.title
          }
        })
      }
    }
  },
  actions: {
    fetchThemes() {
      return axios(FETCH_THEMES);
    },
    activateTheme(context, id) {
      return axios.patch(ACTIVATE_THEME(id), { active: true }, requestConfig);
    },
    deleteTheme(context, id) {
      return axios.delete(DELETE_THEME(id));
    },
    duplicateTheme(context, { theme, language }) {
      const { author, id, title } = theme;

      return axios.post(
        DUPLICATE_THEME(theme.parentThemeID),
        { author, id, title, language },
        requestConfig
      );
    },

    downloadTheme(context, id) {
      return axios.get(DOWNLOAD_THEME(id), {responseType: 'blob'});
    },
    uploadTheme(context, formData) {
      return axios.put(UPLOAD_THEME, formData, {handleError: true});
    },
    sendOverwriteTheme(context, status ) {
      let themeData = context.state.overwriteTheme;
      themeData.overwrite = status;

      return axios.post(OVERWRITE_THEME, themeData);
    },
    updateThemeNameAndAuthor({commit}, theme) {
      commit('changeThemeNameAndAuthor', theme)
    }
  }
};
