<template>
    <div>
        <textbox :id="id + '-api-key'"
                 :label="locales.apiKey"
                 v-model="apiKey"
        />
        <template v-if="apiKey.value">
            <GmapMap
                    :center="{ lat: latitude.value || defaultLatLng.lat, lng: longitude.value || defaultLatLng.lng }"
                    :zoom="4"
                    :options="mapOptions"
                    map-type-id="terrain"
                    @click="changeLocation"
                    class="map-wrapper"
            >
                <GmapMarker
                        :position="{ lat: latitude.value || defaultLatLng.lat, lng: longitude.value || defaultLatLng.lng }"
                />
            </GmapMap>

            <textbox :id="id + '-latitude'"
                     :label="locales.latitude"
                     v-model="latitude"
            />
            <textbox :id="id + '-longitude'"
                     :label="locales.longitude"
                     v-model="longitude"
            />
            <slider :id="id + '-zoom'"
                     :label="locales.zoom"
                     v-model="zoom"
            />

        </template>
    </div>
</template>

<script>
    import textbox from "./textbox";
    import slider from "./slider";

    import Vue from "vue";
    import * as VueGoogleMaps from 'vue2-google-maps';

    Vue.use(VueGoogleMaps);

    export default {
        props: {
            id: String,
            label: String,
            value: Object
        },
        components: {
            textbox,
            slider
        },
        data() {
            return {
                locales: this.$t('editor').options.maps,
                defaultLatLng: {
                    lat: 53.0793,
                    lng: 8.8017
                },
                mapOptions: {
                    scrollwheel: false,
                    mapTypeControl: false,
                    navigationControl: false,
                    disableDoubleClickZoom: false,
                    streetViewControl: false
                }
            };
        },
        beforeMount() {
            if(this.apiKey.value) {
                this.loadMapScript(this.apiKey.value);
            }
        },
        computed: {
            apiKey: {
                get() {
                    return { value: this.value.items.apiKey };
                },
                set(newValue) {
                    this.value.items.apiKey = newValue.value;
                    this.loadMapScript(newValue.value);
                    this.$emit("input", this.value);
                    this.$emit("triggerSave", this.value.items);
                }
            },
            latitude: {
                get() {
                    return { value: this.value.items.latitude };
                },
                set(newValue) {
                    this.value.items.latitude = parseFloat(newValue.value);
                    this.$emit("input", this.value);
                    this.$emit("triggerSave", this.value.items);
                }
            },
            longitude: {
                get() {
                    return { value: this.value.items.longitude };
                },
                set(newValue) {
                    this.value.items.longitude = parseFloat(newValue.value);
                    this.$emit("input", this.value);
                    this.$emit("triggerSave", this.value.items);
                }
            },
            zoom: {
                get() {
                    return this.value.items.zoom;
                },
                set(newValue) {
                    this.value.items.zoom.value = newValue.value;
                    this.$emit("input", this.value);
                    this.$emit("triggerSave", this.value.items);
                }
            }
        },
        methods: {
            loadMapScript(APiKey) {
                VueGoogleMaps.loadGmapApi({
                    key: APiKey,
                    libraries: 'places'
                })
            },
            changeLocation(location) {
                if (!location) return;

                // Get new location values
                let newLat = location.latLng.lat(),
                    newLng = location.latLng.lng();

                // Update latitude and longitude fields
                this.latitude = { value: newLat };
                this.longitude = { value: newLng };
            }
        }
    };
</script>

<style scoped>
    .map-wrapper {
        width: 100%;
        height: 230px;
        margin: 10px 0 15px;
    }
</style>
