<template>
  <div class="col-sm-4">
    <div class="item" :class="{ active, 'invalid-theme': !editable }">
      <span class="badge badge-primary" v-if="editing === id">{{ locales.editing }}</span>
      <img :src="thumbnail" :alt="title +' - '+ author" class="thumbnail" v-if="thumbnail != 'PREVIEW_NOT_AVAILABLE'" />
      <div v-if="thumbnail == 'PREVIEW_NOT_AVAILABLE'" class="no-preview">
        <span class="no-preview-label">{{ locales.noPreview }}</span>
      </div>
      <div v-if="!editable" class="invalid-theme-label">
        {{ locales.invalidTheme }}
      </div>
      <div class="meta">
        <h3 class="name">
          {{ title }}
          <span class="author">{{ author }}</span>
        </h3>
        <item-dropdown
          :active="active"
          :removable="removable"
          :editing="editing"
          :themeId="id"
          :locales="locales.dropdown"
          @activate="toggleActivateModal(true)"
          @edit="$emit('edit')"
          @delete="toggleDeleteModal(true)"
          @duplicate="toggleDuplicateModal(true)"
          @download="$emit('download')"
        />
      </div>
    </div>

    <item-activate-modal
      :show="showActivateModal"
      :title="title"
      :locales="locales.activateModal"
      @confirm="onActivateModalConfirm()"
      @cancel="toggleActivateModal(false)"
    />
    <item-delete-modal
      :show="showDeleteModal"
      :title="title"
      :locales="locales.deleteModal"
      @confirm="onDeleteModalConfirm()"
      @cancel="toggleDeleteModal(false)"
    />
    <item-duplicate-modal
      :show="showDuplicateModal"
      :title="title"
      :locales="locales.duplicateModal"
      :parentThemeId="id"
      :parentThemeTitle="title"
      @confirm="formData => onDuplicateModalConfirm(formData)"
      @cancel="toggleDuplicateModal(false)"
    />
  </div>
</template>

<script>
import ItemDropdown from "./item/Dropdown";

import ItemActivateModal from "./item/ActivateModal";
import ItemDeleteModal from "./item/DeleteModal";
import ItemDuplicateModal from "./item/DuplicateModal";

export default {
  components: { ItemDropdown, ItemActivateModal, ItemDeleteModal, ItemDuplicateModal },
  props: {
    id: String,
    title: String,
    author: String,
    thumbnail: String,
    active: Boolean,
    editable: Boolean,
    editing: String,
    removable: Boolean,
    locales: Object
  },
  data() {
    return {
      showActivateModal: false,
      showDeleteModal: false,
      showDuplicateModal: false
    };
  },
  methods: {
    toggleActivateModal(show) {
      this.showActivateModal = show;
    },
    toggleDeleteModal(show) {
      this.showDeleteModal = show;
    },
    toggleDuplicateModal(show) {
      this.showDuplicateModal = show;
    },
    onActivateModalConfirm() {
      this.$emit("activate", this.id);
      this.toggleActivateModal(false);
    },
    onDeleteModalConfirm() {
      this.$emit("delete", this.id);
      this.toggleDeleteModal(false);
    },
    onDuplicateModalConfirm(formData) {
      const duplicateData = {
        author: this.author,
        ...formData
      }
      this.$emit("duplicate", duplicateData);
      this.toggleDuplicateModal(false);
    }
  }
};
</script>

