<template>
  <div class="option-container option-color-picker">
    <div class="row">
      <div class="col-5">
        <label class="label">{{ label }}</label>
      </div>
      <div class="col-7">
        <div class="color-picker-wrapper">
          <b-form-input
            :state="validColorState"
            :value="value.value"
            @input="update"
            class="color-picker-input"
            autocomplete="off"
            placeholder="Choose color"
            style="background-image: none;"
            type="text"/>
          <div
                  ref="colorpicker">
            <span @click="togglePicker" class="color-hint">
              <span
                :style="[ showColorHint ? { backgroundColor: selectedColor } : '' ]"
                class="current-color">
                <custom-icon v-if="!showColorHint" icon="Cancel" class="not-available" width="10px" height="10px" />
              </span>
            </span>
            <div
                v-if="showColorPicker"
                class="color-picker">
                <sketch-picker
                  :presetColors="presetColors"
                   v-model="colorPickerColor" />
                <div class="actions">
                  <b-button @click="chooseColor" variant="primary" class="choose">{{ $t('editor.options.colorpicker.ok') }}</b-button>
                  <b-button @click="togglePicker" class="cancel">{{ $t('editor.options.colorpicker.cancel') }}</b-button>
                </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
  import {Sketch} from "vue-color";
  import CustomIcon from "@/components/CustomIcon";

  export default {
    name: "ColorPicker",
    props: {
      id: String,
      label: String,
      value: Object
    },
    components: {
      "sketch-picker": Sketch,
      CustomIcon
    },
    data() {
      return {
        showColorPicker: false,
        colorPickerSelected: null,
        presetColors: [],
        inputTimeout: null,
        validColorState: null
      };
    },
    mounted() {
      this.updateColorPalette();
      this.value.value = this.id in this.$store.state.editor.themeConfig
              ? this.$store.state.editor.themeConfig[this.id].value
              : this.value.value;
    },
    computed: {
      selectedColor: function(){
        let value = (this.value != null && this.value.value != null) ? this.value.value : this.currentValue;
        if (value && value.slice(0, 1) === "$") {
          return value.slice(1, value.length) in this.$store.state.editor.selectedTheme.colorPalette
                  ? this.$store.state.editor.selectedTheme.colorPalette[value.slice(1, value.length)]
                  : 'transparent'
        }


        return value;
      },

        showColorHint: {
        get() {
          let value = (this.value != null && this.value.value != null) ? this.value.value : this.currentValue;

          if (value && value.slice(0, 1) === "$") {
            let newValue = value.slice(1, value.length);
            return newValue in this.$store.state.editor.selectedTheme.colorPalette
          }

          return ( value === "transparent" || value === "" || this.checkColorName(value) || this.isCssColor(value) ) && !this.isScssFunction(value);
        }

      },
      currentValue: {
        get() {
          let value = this.id in this.$store.state.editor.themeConfig
                  ? this.$store.state.editor.themeConfig[this.id].value
                  : this.value.value;
          return value ? value : 'transparent';
        },
        set(newValue) {
          this.validColorState = this.isValidColor(newValue);
          if(this.isValidColor(newValue)) {
            if (this.value.value !== newValue) {
              this.validColorState = null;
              this.value.value = newValue;
              this.triggerSave();
            }
          }
        }
      },
      colorPickerColor: {
        get() {
          return (this.id in this.$store.state.editor.themeConfig
                  ? this.$store.state.editor.themeConfig[this.id].value
                  : this.value.value) || 'transparent';
        },
        set(newValue) {
          this.colorPickerSelected = this.getCorrectColorFormat(newValue);
        }
      }
    },
    methods: {

      // function to hold all color validation rules
      isValidColor(color) {
        return (
            this.checkColorName(color) ||
            this.isCssColor(color) ||
            this.isScssFunction(color) ||
            color.slice(0, 1) === "$"
        );
      },

      update(value) {
        clearInterval(this.inputTimeout);
        this.inputTimeout = setTimeout(() => {
          this.currentValue = value;
        }, 600);
      },

      /**
       * checks if color code is a valid HEX/rgb/HSL color
       * @param color
       * @returns {boolean}
       */
      isScssFunction(color) {
        const regex = /^(?!rgb|rgba|hsl|hsla)\w+\(.*\)$|^(transparent)$/g;
        return regex.test(color);
      },
      isCssColor(color) {
        let rgbRegEx = /(^rgb\((\d+),\s*(\d+),\s*(\d+)\)$)|(^rgba\((\d+),\s*(\d+),\s*(\d+)(,\s*((0(\.[0-9])?)|(1)|(\.[0-9])))\s*\)$)/;
        let hslRegEx = /(^hsl\((\d+),\s*(\d+%),\s*(\d+%)\)$)|(^hsla\((\d+),\s*(\d+%),\s*(\d+%)(,\s*((0(\.[0-9])?)|(1\.0)|(\.[0-9])))\s*\)$)/;
        let hexRegEx = /^(#([a-fA-F0-9]){3})$|^(#([a-fA-F0-9]){6}$)$/;
        return rgbRegEx.test(color) || hslRegEx.test(color) || hexRegEx.test(color);
      },
      checkColorName(color) {
          let colorOption = new Option().style;
          colorOption.color = color;
          return colorOption.color == color;
      },
      getCorrectColorFormat(color) {
        // Update the current color via the color picker
        let correctColorFormat = null;

        // Check for the correct color format
        if (color.a === 0) {
          // If alpha is equal to 0 make color value transparent
          correctColorFormat = "transparent";
        } else if (color.a === 1) {
          // If alpha is equal to 1 save color value as hex format
          correctColorFormat = color.hex;
        } else {
          // If alpha is from 0 to 1 build the rgba format for this color
          correctColorFormat =
                  "rgba(" +
                  color.rgba.r +
                  ", " +
                  color.rgba.g +
                  ", " +
                  color.rgba.b +
                  ", " +
                  color.rgba.a +
                  ")";
        }

        return correctColorFormat;
      },
      updateColorPalette() {
        this.presetColors.length = 0;
        Object
          .entries(this.$store.state.editor.selectedTheme.colorPalette)
          .forEach(([field, colorName]) => {
            if (colorName && field !== this.id) {
              if (this.presetColors.indexOf(colorName) < 0) {
                this.presetColors.push(colorName);
              }
            }
          });
        return this.presetColors;
      },
      triggerSave() {

        if(this.value.value === '' || this.value.value)
        {
          this.$emit("input", this.value);
          this.$emit("triggerSave", this.value.value);
        }
      },
      togglePicker() {
        this.updateColorPalette();
        // Toggle color picker modal
        this.showColorPicker ? this.hidePicker() : this.showPicker();
      },
      showPicker() {
        // Show color picker modal
        document.addEventListener("click", this.documentClick);
        this.showColorPicker = true;
        if(this.colorPickerSelected == null) {
          this.colorPickerSelected = this.currentValue;
        }
      },
      hidePicker() {
        // Hide color picker modal
        document.removeEventListener("click", this.documentClick);
        this.showColorPicker = false;
      },
      chooseColor() {
        this.currentValue = this.colorPickerSelected;
        this.hidePicker();
      },
      documentClick(e) {
        // Hide color picker modal if you click outside
        let el = this.$refs.colorpicker,
          target = e.target;
        if (el && el !== target && !el.contains(target)) {
          this.hidePicker();
        }
      }
    }
  };
</script>

<style lang="scss" scoped>
  .color-picker-wrapper {
    position: relative;
    .color-picker-input {
      padding-right: 25px;
    }

    .color-hint {
      position: absolute;
      top: 50%;
      right: 5px;
      transform: translateY(-50%);
      width: 15px;
      height: 15px;
      background-image: url("../../../../assets/editor-bg.png");
      background-repeat: repeat;
      background-size: cover;
      border: 1px solid lighten($gray-800, 25%);
      border-radius: 2px;
      cursor: pointer;

      .current-color {
        position: absolute;
        width: 100%;
        height: 100%;
        .not-available {
          position: relative;
          top: -4px;
          left: 2px;
        }
      }
    }

    .color-picker {
      position: absolute;
      top: 100%;
      right: 0;
      z-index: 4;
      .actions {
        position: relative;
        z-index: 1;
        margin-top: -2px;
        padding: 5px;
        background: white;
        border-top: 1px solid #ccc;
        border-radius: 0 0 5px 5px;
        .choose {
          margin-right: 5px;
          width: calc(50% - 5px);
          font-size: 12px;
        }
        .cancel {
          width: 50%;
          font-size: 12px;
        }
      }
    }
  }
</style>
