<template>
  <div class="editor-panel-overlay" :class="active ? 'active-overlay' : ''">
    <template v-if="computedData[0].showBreadcrumb !==false">
      <header id="panel-header" class="overlay-header">
        <nav aria-label="breadcrumb">
          <ol class="breadcrumb">
            <li class="breadcrumb-icon" v-if="breadcrumb.length > 1">
              <button @click="breadcrumbGoBack()" class="btn btn-link btn-sm">
                <custom-icon icon="arrow-left" />
              </button>
            </li>
            <li class="breadcrumb-icon" v-else>
              <button @click="closeOverlay()" class="btn btn-link btn-sm">
                <custom-icon icon="close" />
              </button>
            </li>
            <li :key="index" class="breadcrumb-item" v-for="(item, index) in breadcrumb">
              <template v-if=" breadcrumb.length > 2 && index != 0 && index != breadcrumb.length - 1">
                &#x2026;
              </template>
              <template v-else>
                {{ item.title }}
              </template>
            </li>
          </ol>
        </nav>
      </header>
    </template>
    <template v-else>
      <header id="panel-header" class="overlay-header more-than-two">
        <nav aria-label="breadcrumb">
          <ol class="breadcrumb">
            <li class="breadcrumb-icon">
              <button @click="closeOverlay()" class="btn btn-link btn-sm">
                <custom-icon icon="close" />
              </button>
            </li>
            <li class="breadcrumb-item">
              <template>
                {{ breadcrumb[2].title }}
              </template>
            </li>
          </ol>
        </nav>
      </header>
    </template>
    <main class="overlay-body">
      <language-switcher id="language-switcher-container" v-if="computedData[0].translatable" />
      <perfect-scrollbar id="overlay-scrollbar-container" class="overflow-content-wrapper">
        <Handler :data="computedData[0]" :key="computedData[0].key" :locales="locales" @toggleModal="toggleModal" />
      </perfect-scrollbar>
    </main>
  </div>
</template>

<script>
  import CustomIcon from "@/components/CustomIcon";
  import Handler from "@/components/editor/panel/Handler";
  import LanguageSwitcher from "@/components/editor/panel/LanguageSwitcher";

  export default {
    props: {
      active: Boolean,
      data: Array,
      locales: Object
    },
    components: {
      CustomIcon,
      LanguageSwitcher,
      Handler
    },
    data() {
      return {
        fakedata: [
          {
            title: 'el 0',
            id: "element0",
            fieldsets: []
          },
          {
            title: 'el 1',
            id: "element1",
            fieldsets: []
          },

        ]
      }
    },
    computed: {
      computedData: {
        get() {
          // return this.fakedata;
          if (this.data.length === 0) {
            return this.fakedata;
          } else {
            return this.data;
          }

        },
        set(newValue) {

          // this.fakedata = newValue;

          if (this.data.length === 0) {
            this.fakedata = newValue;
          } else {
            //this.data = newValue;
            this.$emit('input', newValue);
          }
        }
      },

      breadcrumb() {
        return this.computedData.slice().reverse();
      }
    },
    methods: {
      breadcrumbGoBack() {
        this.computedData = this.computedData.splice(0, 1);
      },
      closeOverlay() {
        this.$emit("closeOverlay");
      },
      toggleModal(showModal, data) {
        this.$emit("toggleModal", showModal, data);
      },
    },
    mounted() {
      let sbContainer = document.getElementById('overlay-scrollbar-container');
      let panelHeader = document.getElementById('panel-header') || 0;
      if (panelHeader) {
        panelHeader = panelHeader.clientHeight;
      }
      let languageSwitcher = document.getElementById('language-switcher-container') || 0;
      if (languageSwitcher) {
        languageSwitcher = languageSwitcher.clientHeight;
      }
      let resolutionBar = document.getElementById('resolution-bar-container') || 0;
      if (resolutionBar) {
        resolutionBar = resolutionBar.clientHeight;
      }
      let expertmodePreviewBar = document.getElementById('expertmode-preview-bar-container') || 0;
      if (expertmodePreviewBar) {
        expertmodePreviewBar = expertmodePreviewBar.clientHeight;
      }

      let totalDif = parseInt(languageSwitcher + panelHeader + expertmodePreviewBar + resolutionBar) - 11;
      sbContainer.style.height = 'calc(100vh - '+ totalDif +'px)';
    }
  };
</script>

