export default {
	methods: {
		setThemeIdCookie() {
			this.clearCookRemovalTimeout()
			const selectedThemeId = this.$store.state.editor.selectedTheme.id;
			// set cookies
			let expire = new Date();
			expire.setSeconds(expire.getSeconds() + 10);
			document.cookie = this.getCookieString(selectedThemeId, expire);
		},
		clearCookRemovalTimeout() {
			
			if (window.cookieRemovalTimeout != undefined) {
				clearTimeout(window.cookieRemovalTimeout);
			}
		},
		scheduleThemeIdCookieRemoval() {
			this.clearCookRemovalTimeout();
			window.cookieRemovalTimeout = setTimeout(() => this.removeThemeIdCookie(), 2000);
		},
		removeThemeIdCookie() {
			let expire = new Date();
			expire.setSeconds(expire.getSeconds() - 1000);
			const cookieString = this.getCookieString(0, expire);
			document.cookie = cookieString;
		},
		
		getCookieString(value, expire) {
			return `STYLE_EDIT_PREVIEW_THEME=${value};expires=${expire}; path=/`;
		}
	}
};