import {SET_THEME_UPLOAD_STATUS, SET_THEMES, TOGGLE_CHOOSER, SET_OVERWRITE_THEME_DATA, CHANGE_OVERWRITE_THEME_DATA} from "../enums/mutations";

import {
	ACTIVATE_THEME,
	DELETE_THEME,
	DOWNLOAD_THEME,
	DUPLICATE_THEME,
	FETCH_THEMES,
	UPLOAD_THEME,
	SEND_OVERWRITE_THEME
} from "../enums/actions";

import {FAILED, INITIAL, SAVING, SUCCESS} from "../enums/themeUploadStatus";

export default {
	created() {
		const parameters = new URLSearchParams(location.search);
		
		if (parameters.get("welcome") === "1" || !parameters.get("editing")) {
			this.toggleChooser(true);
		}
	},
	methods: {
		toggleChooser(show) {
			if (this.$store.state.editor.selectedTheme) {
				this.$store.commit(TOGGLE_CHOOSER, show);
			} else {
				this.$store.commit(TOGGLE_CHOOSER, true);
			}
			
		},
		async fetchThemes() {
			const {data} = await this.$store.dispatch(FETCH_THEMES);
			this.$store.commit(SET_THEMES, data);
		},
		async activateTheme(themeId) {
			await this.$store.dispatch(ACTIVATE_THEME, themeId);
			await this.fetchThemes();
		},
		async deleteTheme(themeId) {
			
			await this.$store.dispatch(DELETE_THEME, themeId);
			await this.fetchThemes();
		},
		
		async duplicateTheme(data) {
			await this.$store.dispatch(DUPLICATE_THEME, data);
			await this.fetchThemes();
		},
		
		async downloadTheme(themeId) {
			const {data} = await this.$store.dispatch(DOWNLOAD_THEME, themeId);

			const url = window.URL.createObjectURL(new Blob([data]));
			const link = document.createElement('a');
			link.href = url;
			link.setAttribute('download', themeId+'.zip');
			document.body.appendChild(link);
			link.click();

			setTimeout(() => {
				link.parentNode.removeChild(link);
			}, 300);
		},
		
		async uploadTheme(formData) {
			this.$store.commit(SET_THEME_UPLOAD_STATUS, SAVING);

			try {
				const {data} = await this.$store.dispatch(UPLOAD_THEME, formData);
				let themeData = {
					name: data.name,
					path: data.path,
					version: data.version,
					exists: data.exists
				};
				this.$store.commit(SET_OVERWRITE_THEME_DATA, themeData);
				if(!data.exists) {
					await this.requestToOverwriteTheme(true);
					this.fetchThemes();
				}
			} catch (error) {
				this.$store.commit(SET_THEME_UPLOAD_STATUS, FAILED);
				setTimeout(()=> {
					this.$store.commit(SET_THEME_UPLOAD_STATUS, INITIAL);
				}, 500);
			}
		},

		async requestToOverwriteTheme(status) {
			const {data} = await this.$store.dispatch(SEND_OVERWRITE_THEME, status);
			this.$store.commit(CHANGE_OVERWRITE_THEME_DATA, data);
			if(data == true) {
				this.$store.commit(SET_THEME_UPLOAD_STATUS, SUCCESS);
			}
			setTimeout(()=> {
				this.$store.commit(SET_THEME_UPLOAD_STATUS, INITIAL);
			}, 500);
		},
		
		resetThemePlaceholder() {
			this.$store.commit(SET_THEME_UPLOAD_STATUS, INITIAL);
		}
	}
};
