<template>
  <div class="widget-text">
    <div class="form-group">
      <label class="label">{{value.label || '' }}</label>
      <content-manager-list :placeholder="(value.attributes || false) ? value.attributes.placeholder : ''"
                            :query="contentName"
                            @input="onInputChange"
                            @onSelectItem="onSelectItem"
                            widgetType="text"/>
    </div>
    <div class="form-group">
      <ckeditor
        :config="editorConfig"
        :disabled="!value.useEditorContent"
        :editor="editor"
        :key="language"
        ref="wysiwygeditor"
        v-model="contentValue"></ckeditor>
    </div>
  </div>
</template>

<script>
  import ContentManagerList from './content-manager-list';
  import ClassicEditor from '@ckeditor/ckeditor5-editor-classic/src/classiceditor';

  import EssentialsPlugin from '@ckeditor/ckeditor5-essentials/src/essentials';
  import BoldPlugin from '@ckeditor/ckeditor5-basic-styles/src/bold';
  import ItalicPlugin from '@ckeditor/ckeditor5-basic-styles/src/italic';
  import LinkPlugin from '@ckeditor/ckeditor5-link/src/link';
  import ParagraphPlugin from '@ckeditor/ckeditor5-paragraph/src/paragraph';
  import HeadingPlugin from '@ckeditor/ckeditor5-heading/src/heading';
  import AlignmentPlugin from '@ckeditor/ckeditor5-alignment/src/alignment';
  import Font from "@ckeditor/ckeditor5-font/src/font";
  import ListStyle from "@ckeditor/ckeditor5-list/src/liststyle";
  import RemoveFormat from "@ckeditor/ckeditor5-remove-format/src/removeformat";
  import HorizontalLine from "@ckeditor/ckeditor5-horizontal-line/src/horizontalline";
  import Indent from "@ckeditor/ckeditor5-indent/src/indent";
  import IndentBlock from "@ckeditor/ckeditor5-indent/src/indentblock";
  import PasteFromOffice from "@ckeditor/ckeditor5-paste-from-office/src/pastefromoffice";
  import Table from "@ckeditor/ckeditor5-table/src/table";
  import TableToolbar from "@ckeditor/ckeditor5-table/src/tabletoolbar";

  export default {
    props: {
      id: String,
      label: String,
      language: String,
      value: Object
    },
    components: {
      ContentManagerList
    },
    computed: {
      contentGroup: {
        get() {
          return this.newValue.contentGroup
        },
        set(newValue) {
          this.newValue.contentGroup = newValue;
          this.sendTimedOutInputEvent();
        }
      },
      contentAlias: {
        get() {
          return this.newValue.contentAlias
        },
        set(newValue) {
          this.newValue.contentAlias = newValue;
          this.sendTimedOutInputEvent();
        }
      },
      contentValue: {
        get() {
          return this.currentValue.value
        },
        set(newValue) {
          this.currentValue.value = newValue;
          this.sendTimedOutInputEvent();
        }

      },
      contentTitle: {
        get() {
          return this.currentValue.title
        },
        set(newTitle) {
          this.currentValue.title = newTitle;
          this.sendTimedOutInputEvent();
        }
      },
      currentValue: {
        get() {
          let value =
            this.id in this.$store.state.editor.themeConfig
            ? this.$store.state.editor.themeConfig[this.id].value
            : this.newValue.value;

          if (Boolean(this.language) && this.newValue.translatable) {
            if(!value[this.language]) {
              value[this.language] = {title: "", value:""};
            }
            return value[this.language];
          } else {
            return value;
          }
        },
        set(newValue) {
          if (Boolean(this.language) && this.newValue.translatable) {
            this.newValue.value[this.language] = newValue;

          } else {
            this.newValue.value = newValue;
          }
          this.sendTimedOutInputEvent();
        }
      },

      useEditorContent: {
        get() {
          if (this.contentGroup) {
            return this.newValue.useEditorContent;

          } else {
            return false;
          }

        },
        set(newValue) {
          if (this.contentGroup) {
            this.newValue.useEditorContent = newValue;
            this.sendTimedOutInputEvent();
          } else {
            this.newValue.useEditorContent = false;
            this.sendTimedOutInputEvent();
            this.keyz++;
          }
        }
      },
      contentName() {
        if (this.newValue.value.hasOwnProperty(this.language)) {
          return this.newValue.value[this.language].title;
        }
        return '';
      }
    },
    mounted() {
      setTimeout(() => this.$refs.wysiwygeditor.$forceUpdate(), 10);

      // -------------------------------
      // List all available toolbar list
      // -------------------------------
      // ClassicEditor
      //   .create(document.querySelector('#wysiwyg'), {...this.editorConfig, language: 'de'})
      //   .then(editor => {
      //     console.log(Array.from(editor.ui.componentFactory.names()));
      //   })
      //   .catch(error => {
      //     console.error(error);
      //   });
    },
    data() {
      return {
        keyz: 1,
        timedOutInputEvent: null,
        editor: ClassicEditor,
        editorData: "<p>Content of the editor.</p>",
        editorConfig: {
          // The configuration of the editor.
          language: this.$store.state.editor.currentLanguage,
          toolbar: {
            items: [
              'paragraph',
              'heading',
              '|',
              'bold',
              'italic',
              'underline',
              'strikethrough',
              '|',
              'alignment:left',
              'alignment:center',
              'alignment:right',
              '|',
              'bulletedList',
              'numberedList',
              'outdent',
              'indent',
              'blockQuote',
              '|',
              'removeFormat',
              '-',
              'fontSize',
              'fontFamily',
              'fontColor',
              'fontBackgroundColor',
              '|',
              'link',
              '|',
              'insertTable',
              '|',
              'horizontalLine',
              '|',
              'undo',
              'redo',
            ],
            shouldNotGroupWhenFull: true
          },
          plugins: [
            EssentialsPlugin,
            BoldPlugin,
            Font,
            ListStyle,
            RemoveFormat,
            HorizontalLine,
            ItalicPlugin,
            LinkPlugin,
            ParagraphPlugin,
            HeadingPlugin,
            Indent,
            IndentBlock,
            AlignmentPlugin,
            PasteFromOffice,
            Table, TableToolbar
          ],
          table: {
            contentToolbar: [ 'tableColumn', 'tableRow', 'mergeTableCells' ]
          }
        },
        newValue: {}
      };
    },
    methods: {
      sendTimedOutInputEvent() {
        clearTimeout(this.timedOutInputEvent);
        this.timedOutInputEvent = setTimeout(() => this.$emit("input", this.newValue), 300)
      },
      onSelectItem({contentGroup, contentAlias, value}) {
        this.newValue.contentGroup = contentGroup;
        this.newValue.contentAlias = contentAlias;

        if (contentGroup) {
          this.newValue.value = value;
        }
      },
      onInputChange(term) {
        this.newValue.value[this.language].title = term;
        this.sendTimedOutInputEvent();
      }
    },
    created() {
      this.newValue = JSON.parse(JSON.stringify(this.value));
    }
  };
</script>

