<template>
  <div>
    <checkbox
      :id="id + '-enabled'"
      v-model="enabled"
      :label="locales.insertImage"
      :title="'id: ' + id + '-enabled'"
    />

    <template v-if="enabled.value">
      <imageupload :id="id + '-url'" :title="'id: ' + id + '-url'" v-model="image" :label="locales.image" />
      <selectbox
        :id="id + '-position'"
        :title="'id: ' + id + '-position'"
        v-model="position"
        :label="locales.position"
      />
      <selectbox
        :id="id + '-attachment'"
        :title="'id: ' + id + '-attachment'"
        v-model="attachment"
        :label="locales.attachment"
      />
      <selectbox :id="id + '-repeat'" :title="'id: ' + id + '-repeat'" v-model="repeat" :label="locales.repeat" />
      <selectbox :id="id + '-size'" :title="'id: ' + id + '-size'" v-model="size" :label="locales.size" />
    </template>
  </div>
</template>

<script>
import imageupload from "./imageupload";
import selectbox from "./selectbox";
import checkbox from "./checkbox";

export default {
  props: {
    id: String,
    label: String,
    value: Object
  },
  components: {
    imageupload,
    checkbox,
    selectbox
  },
  data() {
    return {
      locales: this.$t('editor').options.backgroundImage
    };
  },
  computed: {
    enabled: {
      get() {
        return { value: this.value.items.enabled };
      },
      set(newValue) {
        this.value.items.enabled = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    },
    image: {
      get() {
        return {
          value: this.value.items.url,
          holder: "img"
        };
      },
      set(newValue) {
        this.value.items.url = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    },
    position: {
      get() {
        let position = this.value.items.position;
        if(!position) {
          position = 'center center';
        }
        return {
          value: position,
          options: [
            "left top",
            "left center",
            "left bottom",
            "right top",
            "right center",
            "right bottom",
            "center top",
            "center center",
            "center bottom"
          ]
        };
      },
      set(newValue) {
        this.value.items.position = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    },
    repeat: {
      get() {
        let repeat = this.value.items.repeat;
        if(!repeat) {
          repeat = 'no-repeat';
        }
        return {
          value: repeat,
          options: [
            "repeat",
            "repeat-x",
            "repeat-y",
            "no-repeat",
            "space",
            "round",
            "initial",
            "inherit"
          ]
        };
      },
      set(newValue) {
        this.value.items.repeat = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    },
    size: {
      get() {
        let size = this.value.items.size;
        if(!size) {
          size = 'auto';
        }
        return {
          value: size,
          options: [
            "auto",
            "length",
            "percentage",
            "cover",
            "contain",
            "initial",
            "inherit"
          ]
        };
      },
      set(newValue) {
        this.value.items.size = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    },
    attachment: {
      get() {
        let attachment = this.value.items.attachment;
        if(!attachment) {
          attachment = 'scroll';
        }
        return {
          value: attachment,
          options: ["scroll", "fixed", "local", "initial", "inherit"]
        };
      },
      set(newValue) {
        this.value.items.attachment = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    }
  }
};
</script>

