<template>
  <b-modal :visible="show" size="lg" centered no-fade @hidden="$emit('cancel')">
    <template slot="modal-title">
      <span v-html="modalTitle"></span>
    </template>
    <p class="no-margin">{{ locales.firstLine }}</p>
    <p class="no-margin">
      <small v-html="themeData"></small>
    </p>
    <div slot="modal-footer" class="container">
      <div class="row">
        <div class="col-6">
          <b-button
            size="md"
            class="btn-block"
            variant="link"
            @click="$emit('cancel')"
            >{{ locales.cancel }}</b-button
          >
        </div>
        <div class="col-6">
          <b-button
            size="md"
            class="btn-block"
            variant="warning"
            @click="$emit('confirm')"
            >{{ locales.confirm }}</b-button
          >
        </div>
      </div>
    </div>
  </b-modal>
</template>

<script>
export default {
  props: {
    show: Boolean,
    locales: Object
  },
  computed: {
    modalTitle() {
      return this.locales.title.replace(
        "{title}",
        this.$store.state.chooser.overwriteTheme.name
      );
    },
    themeData() {
      return this.locales.secondLine
        .replace("{title}", this.$store.state.chooser.overwriteTheme.name)
        .replace("{version}", this.$store.state.chooser.overwriteTheme.version);
    }
  }
};
</script>

<style>
.no-margin {
  margin: 0;
}
</style>
