<template>
  <div class="widget-code">
    <div class="form-group">
      <label>{{value.label || '' }}</label>
      <content-manager-list :placeholder="(value.attributes || false) ? value.attributes.placeholder : ''"
                            :query="newValue.value[language].title"
                            @input="onInputChange"
                            @onSelectItem="onSelectItem"
                            widgetType="code" />
    </div>
    <div class="form-group">
      <codemirror
        :disabled="!value.useEditorContent"
        :key="language"
        :options="cmOptions"
        @input="sendTimedOutInputEvent"
        ref="codemirror"
        v-model="newValue.value[language].value"
      ></codemirror>
    </div>
  </div>
</template>

<script>
  import ContentManagerList from './content-manager-list';

  import "codemirror/mode/htmlmixed/htmlmixed";
  import "codemirror/lib/codemirror.css";
  import "codemirror/theme/duotone-light.css";

  export default {
    props: {
      id: String,
      label: String,
      language: String,
      value: Object
    },
    components: {
      ContentManagerList
    },
    computed: {
      searchTerm: {
        get() {
          return this.newValue.value[this.language].title;
        },
        set(newValue) {
          this.newValue.value[this.language].title = newValue;
        }
      }
    },
    created() {
      const languages =  this.$store.state.editor.selectedTheme.languages;

      languages.forEach(element => {
        if (!this.value.value[element]) {
          this.value.value[element] = {title: "", value:""};
        }
      });

      this.newValue = JSON.parse(JSON.stringify(this.value));
    },
    mounted() {
      setTimeout(() => this.$refs.codemirror.codemirror.refresh(), 10);
    },
    data() {
      return {
        keyz: 1,
        timedOutInputEvent: 0,
        custom_sass_code: "",
        cmOptions: {
          // codemirror options
          tabSize: 4,
          mode: "text/html",
          matchBrackets: true,
          lineNumbers: true,
          line: true,
          highlightDifferences: true,
          style: [
            ["type", /^text\/(x-)?scss$/, "text/x-scss"],
            [null, null, "css"]
          ],
          custom: [[null, null, "customMode"]],
          // more codemirror options, 更多 codemirror 的高级配置...,
          newValue: {}
        }
      };
    },
    methods: {
      sendTimedOutInputEvent() {
        clearTimeout(this.timedOutInputEvent);
        this.timedOutInputEvent = setTimeout(() => this.$emit("input", this.newValue), 300)
      },
      onSelectItem({contentGroup, contentAlias, value}) {
        this.newValue.contentGroup = contentGroup;
        this.newValue.contentAlias = contentAlias;

        if (contentGroup) {
          this.newValue.value = value;
        }

        this.$emit("input", this.newValue);
      },
      onInputChange(term) {
        this.newValue.value[this.language].title = term;
        this.sendTimedOutInputEvent();
      }
    }
  };
</script>

<style lang="scss" scoped>
  div.widget-code .form-group label {
    color: $white;
  }

  .widget-text {
    color: $black;
  }

  .center-checkbox {
    margin-top: 13px;
  }
</style>
