export default {
  data() {
    return {
      modalData: null,
      showModal: false
    }
  },
  methods: {
    onModalConfirm() {
      if (this.modalData) {
        this.modalData.successCallback(this.modalData.params);
      }

      this.modalData = null;
      this.showModal = false;
    },
    toggleModal(showModal, data = null) {
      if (!showModal && this.modalData) {
        if (this.modalData.cancelCallback !== undefined) {
          this.modalData.cancelCallback();
        }
      }

      this.modalData = data;
      this.showModal = showModal;
    },
    getModalLocales() {
      if (this.modalData && this.modalData.locales) {
        return this.modalData.locales;
      }

      return null;
    },
    modalConfirmBtnColor() {
      if (this.modalData && this.modalData.confirmButtonVariant) {
        return this.modalData.confirmButtonVariant;
      }

      return '';
    },
    showCancelButton() {
      if (this.modalData && this.modalData.showCancelButton !== undefined) {
        return this.modalData.showCancelButton;
      }

      return true;
    },
    hideCloseButton() {
      if (this.modalData && this.modalData.hideCloseButton !== undefined) {
        return this.modalData.hideCloseButton;
      }
    }
  }
}