<template>
  <b-modal :visible="show"
           :hide-header-close="closeButtonVisible"
           @hidden="$emit('cancel')"
           centered
           no-fade
           ref="editorModal"
           size="lg">
    <template slot="modal-title">
      <span v-html="modalTitle"></span>
    </template>
    <template slot="modal-header-close">
      <custom-icon icon="close" />
    </template>
    <p class="no-margin" v-html="modalFirstLine"></p>
    <p class="no-margin">
      <small v-html="modalSecondLine"></small>
    </p>
    <div slot="modal-footer">
      <div class="row">
        <div class="col-md-6" v-if="cancelButtonShown">
          <b-button
            @click="$emit('cancel')"
            class="btn-block"
            size="md"
            v-html="cancelButtonText"
            :variant="cancelButtonColorModal"
          >
          </b-button
          >
        </div>
        <div :class="getButtonCss()">
          <b-button
            @click="$emit('confirm')"
            class="btn-block"
            size="md"
            v-html="confirmButtonText"
            :variant="confirmBtnColorModal"
          >
          </b-button
          >
        </div>
      </div>
    </div>
  </b-modal>
</template>

<script>
  import CustomIcon from "../CustomIcon";
  export default {
    components: {
      CustomIcon
    },
    props: {
      title: String,
      show: Boolean,
      locales: Object,
      confirmButtonVariant: String,
      cancelButtonColor: String,
      showCancelButton: Boolean,
      hideCloseButton: Boolean
    },
    computed: {
      modalTitle() {
        if (this.locales) {
          return this.locales.title.replace("{title}", this.title);
        }
        return this.title;
      },
      modalFirstLine() {
        if (this.locales) {
          return this.locales.firstLine;
        }

        return '';
      },
      modalSecondLine() {
        if (this.locales) {
          return this.locales.secondLine;
        }

        return '';
      },
      cancelButtonText() {
        if (this.locales) {
          return this.locales.cancel;
        }

        return '';
      },
      confirmButtonText() {
        if (this.locales) {
          return this.locales.confirm;
        }

        return '';
      },
      confirmBtnColorModal() {
        return this.confirmButtonVariant || 'danger';
      },
      cancelButtonColorModal() {
        return this.cancelButtonColor || 'link';
      },
      cancelButtonShown() {
        return this.showCancelButton;
      },
      closeButtonVisible() {
        return this.hideCloseButton;
      }
    },
    methods: {
      getButtonCss() {
         return this.cancelButtonShown ? 'col-md-6' : 'col-md-12';
      }
    }
  };
</script>

<style>
  .no-margin {
    margin: 0;
  }
</style>
