<template>
  <div class="col-sm-4">
    <div class="add-new-theme">
      <div class="new-theme-placeholder" :class="placeholderClass">
        <form
          enctype="multipart/form-data"
          novalidate
          v-if="!isSaving"
        >
          <input
            type="file"
            id="upload-theme"
            name="file"
            :disabled="isSaving"
            @change="onFileChange($event)"
            accept="application/zip"
            class="theme-upload-input"
          />
        </form>
        <a v-bind:href="appStoreUrl" target="_blank" class="plus-icon">
          <custom-icon icon="add" />
        </a>
        <a v-bind:href="appStoreUrl" target="_blank" class="themes-store-link">
          {{ locales.appStore }}
          <br />
          {{ locales.or }}
          <label for="upload-theme">{{ locales.upload }}</label>
        </a>
      </div>
    </div>
    <item-overwrite-modal
      v-if="showOverwriteModal"
      :show="showOverwriteModal"
      :locales="locales.overwriteModal"
      @confirm="overwriteTheme(true)"
      @cancel="overwriteTheme(false)" />
  </div>
</template>

<script>
import ItemOverwriteModal from "./item/OverwriteModal";

import CustomIcon from "../CustomIcon";

import {
  INITIAL,
  SAVING,
  SUCCESS,
  FAILED
} from "../../enums/themeUploadStatus";

export default {
  components: { ItemOverwriteModal, CustomIcon },
  props: {
    uploadStatus: Number,
    locales: Object
  },
  data() {
    return {
    }
  },
  computed: {
    showOverwriteModal() {
      return this.$store.state.chooser.overwriteTheme.exists;
    },
    placeholderClass() {
      return {
        "upload-uploading": this.isSaving,
        "upload-failed": this.isFailed,
        "upload-success": this.isSuccess
      };
    },
    appStoreUrl() {

      const parameters = new URLSearchParams(location.search);
      let shopUrl = parameters.get("url") || false;

      if (shopUrl === false) {
        return '//gambio.de';
      }

      if (shopUrl.substr(-1) !== '/') {
        shopUrl += '/';
      }

      return shopUrl + 'admin/admin.php?do=GambioStore';
    },
    isInitial() {
      return this.uploadStatus === INITIAL;
    },
    isSaving() {
      return this.uploadStatus === SAVING;
    },
    isSuccess() {
      return this.uploadStatus === SUCCESS;
    },
    isFailed() {
      return this.uploadStatus === FAILED;
    }
  },
  methods: {
    onFileChange({ target }) {
      const { name, files } = target;

      if (!files.length) {
        return;
      }

      const formData = new FormData();
      const [file] = files;

      formData.append(name, file, file.name);

      this.$emit("upload", formData);
    },
    overwriteTheme(status) {
      this.$emit('overwriteTheme', status);
    }
  }
};
</script>

