<template>
  <div>
    <selectbox
      :id="value.items.listType.id"
      v-model="listType"
      :label="value.items.listType.label"/>
    <div v-if="showCategorySearchBox()">
      <category-search-box v-model="value.items.category" @triggerSave="triggerSave" :label="value.items.category.label" />
    </div>
    <div v-if="showProductSearchBox()">
      <product-search-box
          v-model="value.items.products"
          @triggerSave="triggerSaveProducts"
          :label="value.items.products.label"
          :clear-after-select="true"
      />
      <product-listing :selectedProducts="selectedProducts" @change="onChangeProductList" @itemDeleted="itemDeleted" />
    </div>
  </div>
</template>

<script>
  import axios from 'axios';
  import CategorySearchBox from './categorysearchbox'
  import ProductSearchBox from './productsearchbox'
  import ProductListing from './product-listing'
  import Selectbox from './selectbox'
  import {FETCH_PRODUCTS_BY_ID} from '@/enums/endpoints';

  export default {
    name: "productlist",
    components: {Selectbox, ProductListing, ProductSearchBox, CategorySearchBox},
    props: {
      id: String,
      label: String,
      value: Object
    },
    data() {
      return {
        selectedProducts: []
      }
    },
    computed: {
      listType: {
        get() {
          return this.value.items.listType;
        },
        set(newValue) {
          this.value.items.listType.value = newValue.value;

          this.triggerSave();
        }
      }
    },
    methods: {
      showCategorySearchBox() {
        return this.listType.value === 'category';
      },
      showProductSearchBox() {
        return this.listType.value === 'own-list';
      },
      triggerSaveProducts(event) {
        if (!this.getProductByIdInSelectedProductsList(event.id)) {
          this.selectedProducts.push(event);
        }

        this.value.items.products.value = this.getSelectedProductsIds();
        this.triggerSave();
      },
      getProductByIdInSelectedProductsList(id) {
        return this.selectedProducts.filter(element => element.id === id)[0] || null;
      },
      itemDeleted(item) {
        delete this.getProductByIdInSelectedProductsList(item.id);

        this.value.items.products.value = this.getSelectedProductsIds();
        this.triggerSave();
      },
      getSelectedProductsIds() {
        if (this.selectedProducts.length) {
          return this.selectedProducts.reduce((initialValue, newValue) => {
            initialValue.push(newValue.id)
            return initialValue;
          }, [])
        }

        return [];
      },
      triggerSave() {
        this.$emit('input', this.value);
        this.$emit('triggerSave', this.value.items);
      },
      fillSelectedProductsList() {
        const { id } = this.$store.state.editor.selectedTheme;
        const url = new URLSearchParams(FETCH_PRODUCTS_BY_ID(id));
        url.set('ids', this.value.items.products.value)

        axios.get(unescape(url), {handleError: true})
          .then(response => {
            if (response.status === 200) {
              this.selectedProducts = response.data;
            }
          })
      },
      updateProductsListOrder() {
        this.value.items.products.value = this.getSelectedProductsIds();
        this.triggerSave();
      },
      onChangeProductList() {
        this.updateProductsListOrder();
      }
    },
    mounted() {
      if (this.value.items.products.value.length &&
        !this.selectedProducts.length
      ) {
        this.fillSelectedProductsList();
      }
    }
  }
</script>

