<template>
    <input :id="id" :ref="id" class="form-control" :class="inputClass" v-on:keydown="keyHandler"
           :value="currentValue" v-on:change="update" autocomplete="off"/>
</template>

<script>
    export default {
        props: {
            id: String,
            value: String,
            inputClass: String,
            defaultUnit: String,
        },
        data() {
            return {
                option: {
                    value: this.value,
                    unit: this.extractUnit(this.value)
                }
            };
        },
        methods: {
            extractUnit(value) {
              if (!value) {
                return this.defaultUnit
              }
              return value.replace(/^[.-\d\s]+/gm, '').trim();
            },
            update($event) {
                let newUnit = this.extractUnit($event.target.value);
                if((/\S/.test(newUnit))) {
                    this.option.unit = newUnit;
                }
                this.currentValue = $event.target.value;
                this.$forceUpdate();

                this.$emit('input', this.option.value);
                this.$emit('change', this.option.value);
            },
            keyHandler(event) {
                if (event.key == ",") {
                    if(event.currentTarget.value.replace(/[^.]/g, '').length == 0){
                        event.currentTarget.value +='.';
                        this.currentValue = event.currentTarget.value;
                    }
                    event.preventDefault();
                }

                if ((event.key == "." || event.key == ",") && event.currentTarget.value.replace(/[^.]/g, '').length > 0) {
                    event.preventDefault();
                }
            }
        },
        computed: {
            currentValue: {
                get() {
                    let currentUnit = this.extractUnit(this.option.value);
                    if (currentUnit == this.defaultUnit) {
                      if (!this.option.value) {
                        return '';
                      }
                      return this.option.value.replace(currentUnit, '');
                    } else {
                        let result = (isNaN(parseFloat(this.option.value))) ? '0px' : this.option.value;
                        return result
                    }
                },
                set(newValue) {
                    //define the current value unit
                    let unit = this.currentUnit;
                    let newUnit = this.extractUnit(newValue);
                    if (newUnit.length == 0) {
                        newUnit = unit;
                    }
                    let numericValue = newValue.replace(',', '.').replace(newUnit, '');

                    if (numericValue.replace(/[^.]/g, '').length < 2) {
                        this.option.value = (isNaN(parseFloat((numericValue)))) ? newValue : numericValue + newUnit;

                    } else {
                        this.$forceUpdate();
                    }
                }
            },
            currentUnit: {
                get() {
                    return this.option.unit;
                },
                set() {

                }
            }
        },
        watch: {
            "value": {
                handler: function (value) {
                    this.option.value = value;
                    this.option.unit = this.extractUnit(this.value);
                },
                immediate: true
            }
        }


    }
</script>