<template>
  <b-modal
    @ok="handleSassCompile"
    @show="reInitCodemirror"
    centered
    id="customStyleModal"
    ref="modal"
    size="lg"
    :title="$t('editor.customStylesheetsTitle')"
  >
    <template slot="modal-header-close">
      <custom-icon icon="close" />
    </template>
    <form @submit.stop.prevent="handleSassCompile">
      <codemirror
        :options="cmOptions"
        ref="codemirror"
        v-model="custom_sass_code"
      ></codemirror>
    </form>
    <div class="container" slot="modal-footer">
      <div class="row">
        <div class="col-4"></div>
        <div class="col-8">
          <div class="row">
            <div class="col-6">
              <b-button
                @click="$refs['modal'].hide()"
                class="btn-block"
                size="md"
                variant="link"
              >
                {{ $t('editor.customScssModal.cancel') }}
              </b-button
              >
            </div>
            <div class="col-6">
              <b-button
                @click="handleSassCompile"
                class="btn-block"
                size="md"
                variant="primary"
              >
                {{ $t('editor.customScssModal.confirm') }}
              </b-button
              >
            </div>
          </div>
        </div>
      </div>
    </div>
  </b-modal>
</template>

<script>
  import ThemeEditorMixin from "../../mixins/editor";
  import CustomIcon from "../CustomIcon";

  import "codemirror/mode/css/css";
  import "codemirror/mode/sass/sass";
  import "codemirror/lib/codemirror.css";
  import "codemirror/theme/duotone-light.css";


  export default {
    name: "CustomScssModal",
    mixins: [ThemeEditorMixin],
    components: {
      CustomIcon
    },
    props: {
      openModal: Boolean
    },
    data() {
      return {
        custom_sass_code: '',
        cmOptions: {
          // codemirror options
          tabSize: 4,
          mode: "sass",
          matchBrackets: true,
          theme: "duotone-light",
          lineNumbers: true,
          line: true
          // more codemirror options, 更多 codemirror 的高级配置...
        }
      };
    },
    computed: {
      codemirror() {
        return this.$refs.codemirror.codemirror;
      }
    },
    methods: {
      reInitCodemirror() {
        this.custom_sass_code = '';

        this.$nextTick(async () => {
          let { styles } = this.$store.state.editor.selectedTheme.config || null;

          if (!styles) {
            styles = await this.getContent();
          }

          if (styles.options !== undefined) {
            styles.options.map(element => this.custom_sass_code += `${element.value.trim()}\n`);
          }

          setTimeout(() => this.codemirror.refresh(), 10);
        });
      },
      handleSassCompile() {
        // this.compiledCustomStyle = 'test';
        this.$nextTick(async () => {
          await this.$store.dispatch("editor/saveEditorChanges", {
            ['custom-scss-css-style']: {
              type: 'code-editor',
              group: 'custom',
              value: this.custom_sass_code
            }
          });
          // Wrapped in $nextTick to ensure DOM is rendered before closing
          this.$refs.modal.hide();
          this.$emit('handleIframe', 'compile')
          // this.reloadIframe();
        });
      },
      async getContent() {
        const themeId = this.$store.state.editor.selectedTheme.id;

        return await this.loadCustomScss(themeId);
      }
    }
  };
</script>
