<template>
  <div class="option-container option-background">
    <div class="row">
      <div class="col-12">
        <label class="label">{{ label }}</label>
        <checkbox
          :id="id + '-hidden-xs'"
          v-model="hiddenXs"
          :label="locales.hiddenXs"
        />
        <checkbox
          :id="id + '-hidden-sm'"
          v-model="hiddenSm"
          :label="locales.hiddenSm"
        />
        <checkbox
          :id="id + '-hidden-md'"
          v-model="hiddenMd"
          :label="locales.hiddenMd"
        />
        <checkbox
          :id="id + '-hidden-lg'"
          v-model="hiddenLg"
          :label="locales.hiddenLg"
        />
      </div>
    </div>
  </div>
</template>

<script>
import checkbox from "./checkbox";

export default {
  props: {
    id: String,
    label: String,
    value: Object
  },
  components: {
    checkbox
  },
  data() {
    return {
      locales: this.$t("editor").options.responsive
    };
  },
  computed: {
    hiddenXs: {
      get() {
        return { value: this.value.items.hiddenXs };
      },
      set(newValue) {
        this.value.items.hiddenXs = newValue.value;
        this.$emit("triggerSave", this.value.items);
      }
    },
    hiddenSm: {
      get() {
        return { value: this.value.items.hiddenSm };
      },
      set(newValue) {
        this.value.items.hiddenSm = newValue.value;
        this.$emit("triggerSave", this.value.items);
      }
    },
    hiddenMd: {
      get() {
        return { value: this.value.items.hiddenMd };
      },
      set(newValue) {
        this.value.items.hiddenMd = newValue.value;
        this.$emit("triggerSave", this.value.items);
      }
    },
    hiddenLg: {
      get() {
        return { value: this.value.items.hiddenLg };
      },
      set(newValue) {
        this.value.items.hiddenLg = newValue.value;
        this.$emit("triggerSave", this.value.items);
      }
    }
  }
};
</script>

<style scoped lang="scss">
.option-container {
  margin-bottom: 5px;
  .sub-option-container {
    margin-bottom: 5px;
  }
}
</style>
