<template>
  <b-modal
      :no-close-on-backdrop="true"
      :visible="show"
      @hidden="$emit('cancel')"
      centered
      no-fade
      size="lg"
  >
    <template slot="modal-title">
      <span v-text="$t('editor.contentManager.deleteModal.title')"></span>
    </template>
    <template slot="modal-header-close" v-if="!loading">
      <custom-icon icon="close" />
    </template>
    <div class="">
      <p>
        {{ $t('editor.contentManager.deleteModal.firstPart') }} <strong>{{ pageTitle }}</strong> {{ $t('editor.contentManager.deleteModal.secondPart') }}
      </p>
    </div>
    <div slot="modal-footer">
      <div class="row">
        <div class="col-md-5">
          <b-button
              @click="$emit('cancel')"
              class="btn-block"
              variant="default"
              v-text="$t('editor.contentManager.deleteModal.cancel')">
          </b-button>
        </div>
        <div class="col-md-7">
          <b-button
              @click="$emit('confirm')"
              variant="danger"
              v-text="$t('editor.contentManager.deleteModal.confirm')">
          </b-button>
        </div>
      </div>
    </div>
  </b-modal>
</template>

<script>
import CustomIcon from "@/components/CustomIcon";
export default {
  components: {
    CustomIcon
  },
  props: {
    show: Boolean,
    page: Object
  },
  data() {
    return {
      loading: false
    };
  },
  computed: {
    currentLanguage: function() {
      return this.$store.state.editor.currentLanguage;
    },
    pageTitle: function() {
      return this.page.content[this.currentLanguage].contentTitle
    }
  }
};
</script>

