<template>
  <div class="option-container option-border">
    <margin :id="id + '-margin'" v-model="margin" :label="locales.width" />
    <!-- Removed "-width" from 2nd parameter of triggerSave method because it was conflicting with backend -->
    <selectbox :id="id + '-style'" v-model="style" :label="locales.type" />
    <colorpicker :id="id + '-color'" v-model="color" :label="locales.color" />
  </div>
</template>

<script>
import margin from "./margin";
import selectbox from "./selectbox";
import colorpicker from "./colorpicker";

export default {
  props: {
    id: String,
    label: String,
    chooseOptions: Object,
    value: Object
  },
  computed: {
    margin: {
      get() {
        let result = {
          items: {
            top: this.value.items.top,
            right: this.value.items.right,
            bottom: this.value.items.bottom,
            left: this.value.items.left
          }
        };
        return result;
      },
      set(newValue) {
        this.value.items.top = newValue.items.top;
        this.value.items.right = newValue.items.right;
        this.value.items.bottom = newValue.items.bottom;
        this.value.items.left = newValue.items.left;

        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    },
    style: {
      get() {
        return {
          value: this.value.items.style,
          options: [
            "none",
            "hidden",
            "dotted",
            "dashed",
            "solid",
            "double",
            "groove",
            "ridge",
            "inset",
            "outset",
            "initial",
            "inherit"
          ]
        };
      },
      set(newValue) {
        this.value.items.style = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    },
    color: {
      get() {
        return {
          value: this.value.items.color
        };
      },
      set(newValue) {
        this.value.items.color = newValue.value;
        this.$emit("input", this.value);
        this.$emit("triggerSave", this.value.items);
      }
    }
  },
  components: {
    margin,
    colorpicker,
    selectbox
  },

  data() {
    return {
      locales: this.$t("editor").options.border,
      borderStyle: [
        "none",
        "hidden",
        "dotted",
        "dashed",
        "solid",
        "double",
        "groove",
        "ridge",
        "inset",
        "outset",
        "initial",
        "inherit"
      ]
    };
  }
};
</script>

<style scoped lang="scss">
.option-container {
  margin-bottom: 5px;

  .sub-option-container {
    margin-bottom: 5px;
  }
}
</style>
