<template>
    <div class="option-container option-slider">
        <div class="row">
            <div class="col-12">
                <label class="label">{{ label }}</label>
                <div class="row">
                    <div class="col-8">
                        <input
                                :id="id"
                                v-model="currentValue"
                                type="range"
                                class="custom-range"
                                @change="$emit('triggerSave', value.value);"
                        />
                    </div>
                    <div class="col-4">
                        <input
                                type="number"
                                :id="id + '-input'"
                                class="form-control"
                                v-model="currentValue"
                                @change="$emit('triggerSave', value.value);"
                        />
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>

<script>
    export default {
        props: {
            id: String,
            label: String,
            value: Object
        },
        methods: {
            // Apply the defined attributes
            // on the JSON file to the slider and input
            addInputAttributes() {
                if (!this.value.attributes) {
                    return;
                }
                let inputID = this.id;
                let rangeInput = document.getElementById(inputID);
                let textInput = document.getElementById(inputID + "-input");

                // Define a list of the attributes that can not be added
                // ex. id, we do not want the user to use a different
                // because it may break our option configuration
                let restrictedAttributes = ["id"];

                // Apply the attributes to the input
                for (let [name, value] of Object.entries(this.value.attributes)) {
                    // Check if the attribute is defined as restricted
                    if (!restrictedAttributes.includes(name)) {
                        rangeInput.setAttribute(name, value);
                        textInput.setAttribute(name, value);
                    }
                }
            }
        },
        mounted() {
            this.addInputAttributes();
            this.value.value = this.id in this.$store.state.editor.themeConfig
                ? this.$store.state.editor.themeConfig[this.id].value
                : this.value.value;
        },
        computed: {
            currentValue:  {
                get() {
                    return this.value.value;
                },
                set(newValue) {
                    this.value.value = parseInt('0' + newValue, 10);

                }
            }
        }
    };
</script>

<style scoped lang="scss">
    .label {
        margin: 0;
    }

    .custom-range {
        margin-top: 5px;
    }
</style>
