<template>
    <div class="option-container option-dropdown-select-fontfamily">
        <dropdownselect
                :id="id"
                :label="label"
                v-model="computedOption"
                @triggerSave="$emit('triggerSave', $event)"
        />
    </div>
</template>

<script>
    import dropdownselect from "./dropdownselect";
    export default {
        props: {
            id: String,
            label: String,
            value: Object
        },
        components: {
            dropdownselect
        },
        computed: {
            computedOption:{
                get() {
                    if (this.value.items === undefined) {
                        this.setValueItems(this.$store.state.editor.selectedTheme.availableFonts || [
                            "Roboto",
                            "Open Sans",
                            "Lato",
                            "Slabo",
                            "Oswald",
                            "Source Sans Pro",
                            "Montserrat",
                            "Raleway"
                        ]);
                        
                        if (this.$store.state.editor.additionalFonts !== undefined &&
                            this.$store.state.editor.additionalFonts.length >= 1) {
    
                            this.setValueItems(this.value.items.concat(this.$store.state.editor.additionalFonts));
                        }
                    }
                    
                    return this.value;
                },
                set(newValue) {
                    this.value.value = newValue.value;
                    this.$emit("input", this.value);
                }
            }
        },
        methods: {
            setValueItems(items) {
                this.value.items = items;
            }
        }
    };
</script>

<style scoped lang="scss">
    .input-container {
        .form-control {
            margin: -5px -9px;
            width: calc(100% + 18px);
            border-radius: $border-radius 0 0 $border-radius;
        }
    }
</style>
