<template>
  <div>
    <div class="link" @click="goTo(page)">
      <b-button variant="transparent" size="small" class="move-page py-0">
        <custom-icon icon="sort" />
      </b-button>
      <span class="title">
        {{ pageTitle(page.content) }}
      </span>
    </div>
    <b-dropdown class="link-options" right variant="link" no-caret toggle-class="py-0">
      <template slot="button-content">
        <custom-icon icon="more" />
      </template>
      <b-dropdown-item @click="goTo(page)">{{ $t("editor.contentManager.actions.edit") }}</b-dropdown-item>
      <b-dropdown-item :disabled="page.isNewPage" @click="copyPageLink(page.publicLink)">{{
        $t("editor.contentManager.actions.copyLink")
      }}</b-dropdown-item>
      <b-dropdown-divider></b-dropdown-divider>
      <b-dropdown-item @click="editPage(page.content)">{{
        $t("editor.contentManager.actions.settings")
      }}</b-dropdown-item>
      <b-dropdown-item v-if="page.deletable" @click="confirmDeletePage(page)" variant="danger">{{
        $t("editor.contentManager.actions.delete")
      }}</b-dropdown-item>
    </b-dropdown>
    <input type="hidden" ref="pageLinkInput" value="" />
    <edit
      v-if="isEditing"
      :show="isEditing"
      :id="page.id"
      :value="page.content"
      :customerStatus="page.customerStatusCheck"
      :newPage="page.isNewPage"
      @cancel="cancelEdit"
      @save="savePage"
    />
    <delete v-if="isDeleting" :show="isDeleting" :page="page" @cancel="cancelDelete" @confirm="deletePage" />
  </div>
</template>

<script>
import ContentManager from "@/mixins/contentManager";
import Edit from "@/components/editor/content-manager/forms/Edit";
import Delete from "@/components/editor/content-manager/forms/Delete";

import CustomIcon from "@/components/CustomIcon";

export default {
  components: {
    Edit,
    Delete,
    CustomIcon,
  },
  mixins: [ContentManager],
  props: ["page"],
  data() {
    return {
      isEditing: false,
      isDeleting: false,
    };
  },
  computed: {
    pageType() {
      return this.page.pageType;
    },
    pageContent: {
      get() {
        return this.page.content;
      },
      set(newValue) {
        this.page.content = newValue;
      },
    },
  },
  methods: {
    goTo: function (page) {
      this.$emit("goTo", page);
    },
    cancelEdit: function (data) {
      this.isEditing = false;
      this.pageContent = data;
      this.$emit("savePage");
    },
    editPage: function () {
      if (this.pageType === "content") {
        this.isEditing = true;
      } else {
        const editContentAminUrl = `${this.$store.state.editor.shopURL}/admin/admin.php?do=ContentManagerPages/edit&id=${this.page.id}`;
        window.open(editContentAminUrl, "_blank").focus();
      }
    },
    savePage() {
      this.isEditing = false;
      this.$emit("savePage", true);
      this.page.hasChanged = true;
      this.goTo(this.page);
    },
    confirmDeletePage: function () {
      this.isDeleting = true;
    },
    cancelDelete: function () {
      this.isDeleting = false;
    },
    deletePage: function () {
      this.isDeleting = false;
      this.$emit("deletePage", this.page);
    },
    copyPageLink: function (url) {
      let linkInput = this.$refs.pageLinkInput;
      linkInput.setAttribute("value", url);
      linkInput.setAttribute("type", "text");
      linkInput.select();

      try {
        let successful = document.execCommand("copy");
        let msg = successful
          ? this.$t("editor.contentManager.actions.linkCopied")
          : this.$t("editor.contentManager.actions.linkNotCopied");

        this.$bvToast.toast(msg, {
          noCloseButton: true,
          autoHideDelay: 5000,
          appendToast: true,
          toastClass: "custom-info-toast",
        });
      } catch (e) {
        this.$bvToast.toast(this.$t("editor.contentManager.actions.linkCopyFailed"), {
          title: `An error has occurred`,
          autoHideDelay: 5000,
          appendToast: true,
          variant: "danger",
        });
      }

      linkInput.setAttribute("type", "hidden");
      linkInput.setAttribute("value", "");
      window.getSelection().removeAllRanges();
    },
    pageTitle: function (item) {
      const parameters = new URLSearchParams(location.search);
      const currentLanguage = parameters.get("language") || this.$store.state.editor.currentLanguage;
      return item[currentLanguage].contentTitle || item[currentLanguage].contentName;
    },
  },
};
</script>

<style lang="scss" scoped>
.link {
  display: flex;
  align-items: start;
  flex-grow: 1;
  .move-page {
    cursor: move;
  }
  .title {
    position: relative;
    bottom: -2px;
    cursor: pointer;
  }
  .is-visible {
    margin-left: 5px;
  }
}
</style>
