<template>
    <b-modal :no-close-on-backdrop="true"
             :visible="show"
             @hidden="$emit('cancel')"
             centered
             id="importSettingsModal"
             no-fade
             ref="importSettingsModal"
             size="lg">
        <template slot="modal-title">
            <span>{{ $t('editor.importModal.title') }}</span>
        </template>
        <template slot="modal-header-close" v-if="!loading">
            <custom-icon icon="close"/>
        </template>
        <div class="form-group row">
            <label class="col-form-label col-md-2">{{ $t('editor.importModal.label') }}:</label>
            <div class="col-md-10">
                <b-form-select
                    :class="{'has-error': hasError}"
                    class="dropdown-select"
                    id="template-list"
                    ref="dropdownSelect"
                    v-model="selectedOption"
                >
                    <optgroup :key="optIndex" :label="option.name" v-for="(option, optIndex) in options">
                        <template v-if="option.items.length">
                            <option :key="itemIndex" :value="item" v-for="(item, itemIndex) in option.items">
                                {{ getOptionItemInnerText(item) }}
                            </option>
                        </template>
                        <option :key="'none'" disabled v-if="!option.items.length">--</option>
                    </optgroup>
                </b-form-select>
                <div class="help-block text-danger" v-if="hasError">
                    {{ $t('editor.importModal.required.templateList')}}
                </div>
            </div>
        </div>
        <div slot="modal-footer">
            <div class="row">
                <div class="col-md-6">
                    <b-button
                        :disabled="loading"
                        @click="$emit('cancel')"
                        class="btn-block"
                        size="md"
                        v-html="$t('editor.importModal.cancel')"
                        variant="default"
                    >
                    </b-button
                    >
                </div>
                <div class="col-md-6">
                    <b-button
                        :disabled="loading"
                        @click="handleImportSettings"
                        class="btn-block"
                        size="md"
                        v-html="$t('editor.importModal.confirm')"
                        variant="success"
                    >
                    </b-button
                    >
                </div>
            </div>
        </div>
    </b-modal>
</template>

<script>
    import axios from 'axios'
    import CustomIcon from '../CustomIcon'
    import ThemeEditorMixin from "@/mixins/editor";
    import {
        FETCH_STYLE_EDIT_3_TEMPLATES_LIST,
        FETCH_STYLE_EDIT_3_TEMPLATE_SETTINGS,
        FETCH_STYLE_EDIT_4_THEME_SETTINGS
    } from '@/enums/endpoints'

    const STYLE_EDIT_3 = 'StyleEdit3';
    const STYLE_EDIT_4 = 'StyleEdit4';

    export default {
        name: 'CustomBodyModal',
        components: { CustomIcon },
        mixins: [ThemeEditorMixin],
        props: {
            show: Boolean
        },
        data () {
            return {
                options: {
                    'template': {
                        name: this.$t('editor.importModal.options.template'),
                        items: []
                    },
                    'theme': {
                        name: this.$t('editor.importModal.options.theme'),
                        items: []
                    }
                },
                selectedOption: null,
                loading: false,
                hasError: false
            }
        },
        watch: {
            show () {
                // Get the list only if the user opens the modal
                // instead of calling the method on "mounted"
                if (this.show) {
                    this.getTemplatesList()
                    this.getThemesList()
                }
                
                // Resets the selected value
                if (!this.show) {
                    this.resetFields()
                }
            },
            selectedOption () {
                this.hasError = false
            }
        },
        methods: {
            getTemplatesList () {
                const { id } = this.$store.state.editor.selectedTheme
                axios.get(FETCH_STYLE_EDIT_3_TEMPLATES_LIST(id), { handleError: true })
                    .then(response => {
                        let options = response.data
                        
                        if (response.status === 200 && options.length) {
                            options.map(element => {
                                this.options[element.type.toLowerCase()].items.push({
                                    id: element.path,
                                    value: element.path,
                                    name: element.name,
                                    style: element.style || '',
                                    status: element.isActive || false,
                                    type: element.type.toLowerCase(),
                                    version: this.getVersion(element.path)
                                })
                            })
                        }
                    })
            },
            getThemesList () {
                const availableThemes = this.$store.state.chooser.themes
                const sourceThemeId = this.$store.state.editor.sourceThemeId;
                let elementIsActive = false;
                
                availableThemes.forEach(element => {
                    elementIsActive = element.id == sourceThemeId;
                    if (!elementIsActive && !element.preview) {
                        this.options['theme'].items.push({
                            id: element.id,
                            value: element.id,
                            name: element.title,
                            style: element.style || '',
                            status: elementIsActive,
                            type: 'theme',
                            version: STYLE_EDIT_4
                        })
                    }
                })
            },
            async handleImportSettings () {
                this.hasError = false
                
                if (!this.selectedOption) {
                    this.hasError = true
                    return
                }
                
                this.loading = true
                try {
                    const settings = await this.getTemplateThemeSettings(this.selectedOption)
                    
                    const saveObject = this.parseThemeSettings(settings.data)
                    
                    this.$store
                        .dispatch('editor/saveEditorChanges', saveObject)
                        .then(() => {
                            this.loading = false;
                            this.resetFields();
                            this.$emit('cancel');
                            this.$emit('handleIframe', 'reload');
                            this.reloadPreviewTheme();
                        })
                } catch (err) {
                    this.loading = false
                    this.resetFields()
                    this.$emit('cancel')
                }
            },
            getTemplateThemeSettings (option) {
                const id = option.id

                if (option.version === STYLE_EDIT_3 || option.type === 'template') {
                    return axios.post(FETCH_STYLE_EDIT_3_TEMPLATE_SETTINGS(id), {
                        path: option.value
                    }, { handleError: true })
                }
                
                return axios.get(FETCH_STYLE_EDIT_4_THEME_SETTINGS(id), { handleError: true })
            },
            parseThemeSettings (settings) {
                let parsedSettings = {}
                
                if (settings.length) {
                    settings.reduce((currentValue, newValue) => {
                        currentValue[newValue.name] = { ...newValue }
                        delete currentValue[newValue.name].name
                        return currentValue
                    }, parsedSettings)
                }
                
                return parsedSettings
            },
            resetFields () {
                this.hasError = false
                this.selectedOption = null
                Object.keys(this.options).forEach(element => this.options[element].items = [])
            },
            getOptionItemInnerText (item) {
                const nameAndStyle = item.style ? `${item.name}: ${item.style}` : item.name
                
                return `${nameAndStyle} (${item.status ? this.$t('common.active') : this.$t('common.inactive')}) - ${item.version}`
            },
            getVersion(path) {
              const regex = /(styles\/styleedit|StyleEdit3)/;
              return regex.test(path) ? STYLE_EDIT_3 : STYLE_EDIT_4;
            }
        }
    }
</script>

<style lang="scss" scoped>
    #importSettingsModal {
        &::v-deep .dropdown-select {
            option {
                background: $white;
                color: $navy-medium-dark;
            }
        }
        
        #template-list.has-error {
            border: 1px solid $danger !important;
        }
    }
</style>