<template>
  <div class="option-container option-background">
    <div class="row">
      <div class="col-12">
        <vue-autosuggest
          :disabled="disabled"
          :get-suggestion-value="getSuggestionValue"
          :input-props="{class:'form-control form-control-sm', placeholder: this.placeholder}"
          :suggestions="filteredOptions"
          @selected="handleOnSelect"
          @input="handleOnInputChange"
          id="content-manager-list"
          v-model="queryTerm"
        >
          <div slot-scope="{suggestion}">
            <span class="my-suggestion-item">
              {{suggestion.item.contentGroupId ? `${suggestion.item.contentGroupId} -` : ''}} {{suggestion.item.titles[getSelectedLanguage]}}
            </span>
          </div>
        </vue-autosuggest>
      </div>
    </div>
  </div>
</template>

<script>
  import {VueAutosuggest} from 'vue-autosuggest';
  import axios from 'axios';
  import {FETCH_ALL_CONTENT_MANAGER} from '@/enums/endpoints';

  export default {
    name: "ContentManagerList",
    components: {VueAutosuggest},
    props: {
      widgetType: String,
      query: String,
      placeholder: String
    },
    data() {
      return {
        list: [],
        term: '',
        minLength: 2
      }
    },
    methods: {
      getSuggestionValue(suggestion) {
        if (suggestion.item.contentGroupId) {
          return suggestion.item.titles[this.getSelectedLanguage];
        }
        return this.query
      },
      getCreateNewItemData() {
        // TODO: create translations for "create new" texts
        const {languages} = this.$store.state.editor.selectedTheme;
        let texts = {},
          titles = {};


        languages.forEach(language => {
          const lang = language.toUpperCase();
          texts[lang] = '';
          titles[lang] = this.$t('editor.options.contentManagerList.new', language);
        })
        return {
          contentGroupId: 0,
          texts,
          titles
        };
      },
      parseSelectedItem(item) {
        const contentGroup = item.contentGroupId === 0 ? null : item.contentGroupId;
        const contentAlias = item.contentAlias || null;
        const parsedItem = {contentGroup,contentAlias, value: {}};

        for (let lang in item.texts) {
          parsedItem.value[lang.toLowerCase()] = {
            value: item.texts[lang],
            ...parsedItem.value[lang.toLowerCase()]
          };
        }

        for (let lang in item.titles) {
          parsedItem.value[lang.toLowerCase()] = {
            title: contentGroup ? item.titles[lang] : '',
            ...parsedItem.value[lang.toLowerCase()]
          };
        }

        return parsedItem;
      },
      handleOnSelect(selectedItem) {
        if (!selectedItem) {
          return;
        }

        const {item} = selectedItem;
        const newItem = {...item};

        this.$emit('onSelectItem', this.parseSelectedItem(newItem));
      },
      handleOnInputChange(term) {
        this.$emit('input', term);
      }
    },
    watch: {
      query() {
        this.term = this.query;
      }
    },
    computed: {
      filteredOptions() {
        // Filter the list by term or contentGroup (ID)
        let filteredList = this.list.filter(option => {
          return (
            option.titles[this.getSelectedLanguage].toLowerCase().indexOf(this.term.toLowerCase()) > -1 ||
            option.contentGroupId.toString().indexOf(this.term) > -1
          );
        });

        // Add the "new item" if we have some filtered list to show
        if (filteredList.length) {
          const hasNewItem = filteredList.filter(option => option.contentGroupId === 0).length > 0;

          if (!hasNewItem) {
            filteredList = [this.getCreateNewItemData(), ...filteredList];
          }
        }

        return [
          {data: filteredList}
        ];
      },
      disabled() {
        return !this.list.length;
      },
      getSelectedLanguage() {
        return this.$store.state.editor.currentLanguage.toUpperCase();
      },
      queryTerm: {
        get() {
          return this.term;
        },
        set(newValue) {
          this.term = newValue;
        }
      }
    },
    async mounted() {
      this.list = await axios.get(
        FETCH_ALL_CONTENT_MANAGER(this.widgetType)
      ).then(response => response.data.infoElements || [])
    },
    created() {
      this.term = this.query;
    }
  }
</script>

