<template>
    <b-modal :visible="show" @hidden="handleCloseModal()" no-close-on-backdrop centered no-fade size="lg">
        <template slot="modal-title">
            <span v-html="modalTitle"></span>
        </template>
        <div>
            <b-form>
                <div class="row">
                    <div class="col-6">
                        <b-form-group
                            id="fieldset-2"
                            :label="`${locales.fields.title.label}:`"
                            label-for="duplicate-modal-title"
                        >
                            <b-input
                                id="duplicate-modal-title"
                                :placeholder="locales.fields.title.placeholder"
                                required
                                type="text"
                                v-model="title"
                                autocomplete="off"
                                maxlength="230"
                                :state="isValidTitle"
                                @blur="preFillThemeId(title)"
                            ></b-input>
                            <b-form-invalid-feedback :state="isValidTitle">
                              {{locales.themeTitleIsRequired}}
                            </b-form-invalid-feedback>
                        </b-form-group>
                    </div>
                    <div class="col-6">
                        <b-form-group
                            id="fieldset-1"
                            :label="`${locales.fields.themeId.label}:`"
                            label-for="duplicate-modal-id"
                        >
                            <b-input-group>
                                <b-form-input
                                    id="duplicate-modal-id"
                                    :placeholder="locales.fields.themeId.placeholder"
                                    required
                                    type="text"
                                    v-model="id"
                                    autocomplete="off"
                                    maxlength="230"
                                    ref="duplicate-modal-id"
                                    :state="isValidId"
                                ></b-form-input>
                                <b-form-invalid-feedback :state="isValidId">
                                    {{locales.themeIdAlreadyExists}}
                                </b-form-invalid-feedback>
                            </b-input-group>
                        </b-form-group>
                    </div>
                </div>
                <b-form-group
                    id="fieldset-3"
                    :label="`${locales.fields.author.label}:`"
                    label-for="duplicate-modal-author"
                >
                    <b-input-group>
                        <b-input
                            id="duplicate-modal-author"
                            :placeholder="locales.fields.author.placeholder"
                            required
                            type="text"
                            v-model="author"
                            autocomplete="off"
                        ></b-input>
                    </b-input-group>
                </b-form-group>
            </b-form>
        </div>
        <div class="container" slot="modal-footer">
            <div class="row">
                <div class="col-6">
                    <b-button
                        @click="$emit('cancel')"
                        class="btn-block"
                        size="md"
                        variant="link"
                    >{{ locales.cancel }}
                    </b-button
                    >
                </div>
                <div class="col-6">
                    <b-button
                        @click="handleSubmit"
                        class="btn-block"
                        size="md"
                        variant="warning"
                    >{{ locales.confirm }}
                    </b-button
                    >
                </div>
            </div>
        </div>
    </b-modal>
</template>

<script>
    export default {
        props: {
            show: Boolean,
            locales: Object,
            parentThemeId: String,
            parentThemeTitle: String
        },
        data() {
            return {
                id: '',
                title: '',
                author: '',
                isValidTitle: null,
                isValidId: null
            }
        },
        computed: {
            modalTitle() {
                return this.locales.title.replace("{title}", this.parentThemeTitle);
            },
            formData() {
                let formData = {}

                if (this.id) {
                    formData.id = this.id
                }

                if (this.title) {
                    formData.title = this.title
                }

                if (this.author) {
                    formData.author = this.author
                }

                return formData
            },
            computedParentThemeId() {
                return this.parentThemeId ? this.parentThemeId.toLowerCase() : ''
            }
        },
        methods: {
            handleCloseModal() {
                this.id = ''
                this.author = ''
                this.title = ''
                this.isValidId = null

                this.$emit('cancel')
            },
            handleSubmit() {
                const form = this.formData

                if(form.title === undefined || form.title.length === 0) {
                  this.isValidTitle = false
                  return false
                } else {
                  this.isValidTitle = null
                }

                if(form.id === undefined || form.id.length === 0) {
                  form.id = form.title.toLowerCase()
                      .replace(/'/g, '')
                      .replace(/\s/g, '_')
                }

                if (this.isValidThemeId(form.id)) {
                    this.$emit('confirm', form)
                } else {
                    this.isValidId = false
                }
                return false
            },
            preFillThemeId(title) {
                if (title && !this.id) {
                    this.id = title ?
                              title.toLowerCase()
                                  .replace(/'/g, '')
                                  .replace(/\s/g, '_') :
                              ''
                }
            },
            isValidThemeId(id) {
                const themes = this.$store.state.chooser.themes || [];

                return themes.filter(value => value.id === id).length === 0
            }
        }
    };
</script>

<style scoped lang="scss">
    .no-margin {
        margin: 0;
    }
    .input-group-text {
        background-color: #33383b;
    }
</style>
