import {FETCH_CONTENT_ZONES, FETCH_CUSTOM_SCSS, FETCH_THEME_TO_EDIT, FETCH_WIDGETS, FETCH_PAGE_NAMESPACES, FETCH_FONTS} from "../enums/actions";
import {BASE_PATH, START_PAGE_PATH} from "../enums/endpoints";


export default {
	created() {
		const parameters = new URLSearchParams(location.search);
		
		if (parameters.get("expertMode") === "1") {
			this.setExpertMode(true);
		}
		if (parameters.get("customer_id")) {
			this.saveCurrentCustomerID(parameters.get("customer_id"));
		}
		// Save current shop base path to store
		this.saveCurrentShopURL(BASE_PATH);

		// Save start page url to store
		this.saveStartPageURL(START_PAGE_PATH);
	},
	methods: {
		triggerSaveCurrentLanguage(lang) {
			this.$store.commit("editor/saveCurrentLanguage", lang);
		},
		saveCurrentEditorView(view) {
			this.$store.commit("editor/saveSelectedEditorView", view);
		},
		setExpertMode(active) {
			this.$store.commit("editor/toggleExpertMode", active);
		},
		saveCurrentShopURL(url) {
			this.$store.commit("editor/saveShopURL", url);
		},
		saveStartPageURL(url) {
			this.$store.commit("editor/saveStartPageURL", url);
		},
		saveCurrentCustomerID(id) {
			this.$store.commit("editor/saveCustomerID", id);
		},
		toggleIframeLoading(isIframeLoading) {
			this.$store.commit("editor/toggleIframeLoading", isIframeLoading);
		},
		
		saveTempFolderData(data) {
			this.$store.commit("editor/saveThemeTempFolder", data);
		},
		
		async toggleExpertMode() {
			await this.$store.dispatch("editor/updateExpertMode");
		},
		
		triggerSaveChanges(callback) {
			this.$store.commit('editor/changeMadeChangesStatus', true);
			this.$store.commit('editor/changeSaveBtnStatus', 2);
			this.$store.dispatch("editor/saveTheme").then(
				response => {
					// trigger in order to clear the contentZones variables
					this.$emit('saveThemeFinished', response.status)
					this.$store.commit('editor/changeSaveBtnStatus', 3);
					this.deleteTheme(this.$store.state.editor.selectedTheme.id).then(
						() => this.$store.dispatch("editor/createPreviewTheme", this.$store.state.editor.sourceThemeId)
							.then(
								() => {
									if (callback !== undefined) {
										callback();
									}
								}
							)
					)
				}, this.$store.commit('editor/changeSaveBtnStatus', 1)
			);
		},
		
		alertInvalidThemeIdAndShowChooser() {
			const data = {
				params: {},
				successCallback: () => this.toggleChooser(true),
				showCancelButton: false,
				locales: this.$t('chooser').invalidThemeModal
			};
			this.$emit('toggleModal', true, data);
		},
		
		selectPreviewThemeFor(themeId) {
			
			this.$store.dispatch(FETCH_THEME_TO_EDIT, themeId + '_preview').then(({data}) => {
				try {
					this.$store.commit("editor/saveSelectedThemeData", data, themeId);
					this.$store.commit("editor/saveThemeConfig", {});
					this.$store.commit("editor/saveSourceTheme", themeId);
				} finally {
					this.toggleChooser(false);
				}
				
			});
		},

		reloadPreviewTheme() {
			const themeId = this.$store.state.editor.selectedTheme.id;
			this.$store.dispatch(FETCH_THEME_TO_EDIT,  themeId).then(({data}) => {
				try {
					this.$store.commit("editor/saveSelectedThemeData", data, themeId);
				} finally {
					this.toggleChooser(false);
				}
			});
		},

		decideWhatTodoWithExistentPreviewFor(themeId) {
			const data = {
				params: {themeId},
				successCallback: ({themeId}) => {
					this.deleteTheme(themeId + '_preview')
						.then(() => {
							this.loadTheme(themeId)
						})
				},
				cancelCallback: () => {
					this.selectPreviewThemeFor(themeId)
				},
				confirmButtonVariant: 'danger',
				hideCloseButton: true,
				locales: this.$t('chooser').previewModal
			};
			this.$emit('toggleModal', true, data);
		},
		
		existPreviewFor(themeId) {
			const previewTheme = themeId + '_preview';
			for (let i = 0; i < this.$store.state.chooser.themes.length; i++) {
				if (this.$store.state.chooser.themes[i].id === previewTheme) {
					return true;
				}
			}
			return false;
		},
		
		createPreviewTheme(selectedThemeId){
			this.$store.dispatch("editor/createPreviewTheme", selectedThemeId).then(({data}) => {
					if (data.id) {
						this.selectPreviewThemeFor(selectedThemeId);
					}
				}, ({response}) => {
					if (response) {
						if (404 == response.status) {
							this.alertInvalidThemeIdAndShowChooser(selectedThemeId);
						}
						if (500 == response.status && 100 == response.data.code) {
							this.decideWhatTodoWithExistentPreviewFor(selectedThemeId);
						}
						if (403 === response.status) {
							this.show403Modal(response)
						}
					}
				}
			).catch(error => {
				if (error.response) {
					if (error.response.status == 404) {
						this.$bvToast.toast(`HTTP ${error.response.status} - ${error.response.data.message
						|| error.response.statusText}`, {
							title: `An error has occurred`,
							autoHideDelay: 5000,
							appendToast: true,
							variant: 'danger'
						});
					}
				}
			});
			
		},
		
		async loadTheme(selectedThemeId) {
			if(this.existPreviewFor(selectedThemeId)){
				this.deleteTheme(selectedThemeId + '_preview').then(() => {this.loadTheme(selectedThemeId)})
				//this.decideWhatTodoWithExistentPreviewFor(selectedThemeId);
			} else {
				this.createPreviewTheme(selectedThemeId);
			}
			
			try {
				const {data} = await this.$store.dispatch(FETCH_FONTS, selectedThemeId);
				if (data.length) {
					
					this.$store.state.editor.additionalFonts = data
				}
				
			} catch (error) {
				throw new TypeError("failed to load widgets", error);
			}
		},
		async loadAvailableWidgets() {
			try {
				const {data} = await this.$store.dispatch(FETCH_WIDGETS);
				return data;
			} catch (error) {
				throw new TypeError("failed to load widgets", error);
			}
		},
		async loadPageNamespaces() {
			try {
				const {data} = await this.$store.dispatch(FETCH_PAGE_NAMESPACES);
				this.$store.commit("editor/savePageNamespaceList", data);
				return data;
			} catch (error) {
				throw new TypeError("Failed to page namespaces!", error);
			}
		},
		async requestContentZones(contentZones) {
			try {
				const {data} = await this.$store.dispatch(FETCH_CONTENT_ZONES, contentZones);
				return data;
			} catch (error) {
				throw new TypeError("failed to load content zones", error);
			}
		},
		async loadCustomScss(selectedTheme) {
			try {
				const {data} = await this.$store.dispatch(FETCH_CUSTOM_SCSS, selectedTheme);
				
				return data;
			} catch (error) {
				throw new TypeError("failed to fetch custom scss", error);
			}
		},
		show403Modal(error) {
			const data = {
				params: {error},
				successCallback: () => {
					const {protocol, hostname} = window.location;
					location.href = `${protocol}//${hostname}`;
				},
				showCancelButton: false,
				locales: this.$t('editor').forbiddenModal
			};
			this.$emit('toggleModal', true, data);
		}
	}
};
