<template>
    <div class="option-container option-textbox">
        <div class="row">
            <div class="col-5">
                <label class="label">{{ label }}</label>
            </div>
            <div class="col-7">
                <div class="row no-gutters">
                    <div class="col-6">
                        <measure-unit :id="id + '-top'" v-model="value.value" v-bind:default-unit="currentUnitValue"
                                      v-on:change="triggerSave" class="form-control"/>
                    </div>
                    <div class="col-6">
                        <unit-selector v-model="currentUnitValue"/>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>

<script>
    import unitSelector from "./unitSelector";
    import measureUnit from "./measureUnit";

    export default {
        props: {
            id: String,
            label: String,
            value: Object
        },
        components: {
            unitSelector,
            measureUnit
        },
        computed: {
            currentUnitValue: {
                get() {
                    let currentUnit = this.extractUnit(this.value.value );
                    if(this.fixedUnits.indexOf(currentUnit) > -1){
                        return currentUnit;
                    } else {
                        return '';
                    }

                },
                set(newUnit) {
                    this.value.value = this.updateUnit(this.value.value, newUnit)
                    this.triggerSave();
                }
            },
            currentValue:{
                get(){
                    return this.id in this.$store.state.editor.themeConfig
                        ? this.$store.state.editor.themeConfig[this.id].value
                        : this.value.value;
                },
                set(newValue){
                    this.value.value = newValue;

                }
            }
        },
        methods: {
            updateUnit(value, newUnit){
                let numericValue = (isNaN(parseInt(value))) ? 0 : parseInt(value);
                let result = numericValue + newUnit;
                return result
            },
            extractUnit(value){
                if (!value) {
                  return 'px';
                }
                return value.replace( /^[.\-\d\s]+/gm , '').trim();
            },
            triggerSave() {
                // Emit the save action
                this.$emit("input", this.value);
                this.$emit("triggerSave", this.value.value);
            },

            // Apply the defined attributes
            // on the JSON file to the input
            addInputAttributes() {
                if (!this.attributes) {
                    return;
                }

                let input = document.getElementById(this.id);
                // Define a list of the attributes that can not be added
                // ex. id, we do not want the user to use a different
                // because it may break our option configuration
                let restrictedAttributes = ["id"];

                // Apply the attributes to the input
                for (let [name, value] of Object.entries(this.attributes)) {
                    // Check if the attribute is defined as restricted
                    if (!restrictedAttributes.includes(name)) {
                        input.setAttribute(name, value);
                    }
                }
            },
        },
        mounted() {
            this.addInputAttributes();
        },
        data() {
            return {
                fixedUnits: ["px", "em", "%"],
                unit: this.extractUnit(this.value.value )
            };
        }
    };
</script>

<style scoped lang="scss"></style>
