<template>
  <b-modal :visible="show" size="lg" centered no-fade @ok="$emit('confirm')" @hidden="$emit('cancel')">
    <template slot="modal-title">
      <span v-html="modalTitle"></span>
    </template>
    <p class="no-margin">{{ locales.firstLine }}</p>
    <p class="no-margin">
      <small>{{ locales.secondLine }}</small>
    </p>
    <div slot="modal-footer" class="container">
      <div class="row">
        <div class="col-6">
          <b-button
            size="md"
            class="btn-block"
            variant="link"
            @click="$emit('cancel')"
            >{{ locales.cancel }}</b-button
          >
        </div>
        <div class="col-6">
          <b-button
            size="md"
            class="btn-block"
            variant="primary"
            @click="$emit('confirm')"
            >{{ locales.confirm }}</b-button
          >
        </div>
      </div>
    </div>
  </b-modal>
</template>

<script>
export default {
  props: {
    title: String,
    show: Boolean,
    locales: Object
  },
  computed: {
    modalTitle() {
      return this.locales.title.replace("{title}", this.title);
    }
  }
};
</script>

<style>
.no-margin {
  margin: 0;
}
</style>
