<template>
  <div id="dynamic-overlay-container" :key="data.key" class="editor-panel-overlay" :class="active ? 'active-overlay' : ''">
    <Header
      :title="data.title"
      :currentPageNamespace="calculatedParentPageNamespace"
      :locales="locales.overlayPanel.header"
      id="panel-header"
      @resendMeData="reInitMyData"
      @triggerCloseOverlay="$emit('closeOverlay')"
      @redirectToPageNamespace="redirectToPageNamespace"
    >
      <template slot="title">{{ data.title }}</template>
    </Header>
    <div class="overlay-body">
      <perfect-scrollbar id="scrollbar-container" class="overflow-content-wrapper">
        <Handler :data="data" :key="data.key" :parentPageNamespace="calculatedParentPageNamespace"
                 :locales="locales"
                 @handleOverlay="triggerChangeOverlay"
                 @handleIframe="handleIframe"
                 @reloadPreviewTheme="reloadPreviewTheme"
                 @redirectToPageNamespace="redirectToPageNamespace"
        />
      </perfect-scrollbar>
    </div>
  </div>
</template>

<script>
import Header from "./Header";
import Handler from "@/components/editor/panel/Handler";

export default {
  name: "DynamicOverlay",
  props: {
    active: Boolean,
    data: Object,
    locales: Object
  },
  components: {
    Header,
    Handler
  },
  methods: {
    handleIframe(action) {
      this.$emit('handleIframe', action);
    },
    reInitMyData(id) {
      this.$emit("reSendBlockData", id);
    },
    triggerChangeOverlay(passedData) {
      this.$emit("change", passedData);
    },
    reloadPreviewTheme() {
      this.$emit("reloadPreviewTheme");
    },
    redirectToPageNamespace(pageNamespace) {
      this.$emit('redirectToPageNamespace', pageNamespace);
    }
  },
  mounted() {
    let sbContainer = document.getElementById('scrollbar-container');
    let panelHeader = document.getElementById('panel-header') || 0;
    if (panelHeader) {
      panelHeader = panelHeader.clientHeight;
    }
    let languageSwitcher = document.getElementById('language-switcher-container') || 0;
    if (languageSwitcher) {
      languageSwitcher = languageSwitcher.clientHeight;
    }
    let resolutionBar = document.getElementById('resolution-bar-container') || 0;
    if (resolutionBar) {
      resolutionBar = resolutionBar.clientHeight;
    }
    let expertmodePreviewBar = document.getElementById('expertmode-preview-bar-container') || 0;
    if (expertmodePreviewBar) {
      expertmodePreviewBar = expertmodePreviewBar.clientHeight;
    }

    let totalDif = parseInt(languageSwitcher + panelHeader + expertmodePreviewBar + resolutionBar) - 11;
    sbContainer.style.height = 'calc(100vh - '+ totalDif +'px)';
  },
  computed: {
    calculatedParentPageNamespace() {
      return this.data.pageNamespace || this.data.parentPageNamespace || ''
    }
  }
};
</script>

<style scoped lang="scss">
.editor-panel-overlay {
  position: absolute;
  top: 0;
  left: -100%;
  bottom: 67px;
  z-index: 15;
  width: 100%;
  display: flex;
  flex-direction: column;
  transition: 0.2s;
  transition-timing-function: ease-out;
  overflow: hidden;
  &.active-overlay {
    left: 0;
  }
  .overlay-body {
    height: 100%;
    background: $gray-900;
    .overflow-content-wrapper {
      height: 100%;
    }
  }
}
</style>
